INSERT INTO `Albums` (`id`, `title`, `description`, `coverImagePath`, `releaseDate`, `createdAt`, `updatedAt`) VALUES
(3, 'Хроники забытых миров', '«Хроники забытых миров» — это музыкальное путешествие длиной в 12 треков через\r\nлегенды, которые мир забыл. От пробуждения древних стражей до триумфального\r\nрассвета новой эры — альбом проводит слушателя через эпические битвы, мифические\r\nвозрождения, трагические падения и лирические истории о любви и потере.', '/public/uploads/album_covers/68f4f7da160db.png', '2025-09-25', '2025-10-19 17:38:18', '2025-10-19 17:38:18'),
(4, 'Эхо миров', '', '/public/uploads/album_covers/68f521f7f26c8.webp', '2024-12-19', '2025-10-19 20:37:59', '2025-10-19 20:37:59'),
(5, 'Театр крови и костей (Live)', '', '/public/uploads/album_covers/68f5233f80410.png', '2025-06-27', '2025-10-19 20:43:27', '2025-10-19 20:43:27'),
(6, 'Нескоренна земля', '', '/public/uploads/album_covers/68f7301192cbb.jpg', '2024-12-30', '2025-10-21 10:02:41', '2025-10-21 10:02:41'),
(7, 'Вільний альбом', '\"Вільний альбом\" — це потужне музичне висловлювання гурту Master of Illusion, що поєднує елементи симфо-року, пост-металу, ліричних балад та протестного драйву. Це альбом про свободу, боротьбу, біль, надію та внутрішнє світло, яке не згасає навіть у найтемніші часи.\r\n\r\nКожна з 13 композицій є окремою історією, але разом вони формують цілісне полотно — емоційну подорож через тіні минулого, буремну реальність і незламну віру в майбутнє. Від епічних гімнів типу \"Воля в ланцюгах\" і \"За межу\", до тендітних балад \"Незгасна\" та \"Твоє ім’я\", цей альбом балансує між ліричністю й бунтарством.\r\n\r\nТематика варіюється від особистого болю до колективного опору, від ніжних почуттів до вогняної рішучості. У текстах звучать голоси самітників, воїнів, коханих, шукачів світла. Центральною метафорою стає стріла свободи — палаюча, небезпечна, але правдива.\r\n\r\nЦе — музика для тих, хто не зраджує себе. Це — Вільний альбом.', '/public/uploads/album_covers/68fbc287e8c00.png', '2025-04-20', '2025-10-24 21:16:39', '2025-10-24 21:16:39'),
(8, 'Гримуар Греха vol.1', 'Гримуар Греха. Vol.1\r\n\r\nКогда страницы мира исписаны кровью, остаётся лишь открыть Гримуар Греха — и дочитать его до конца.\r\n\r\n\"Гримуар греха\" — это концептуальный трибьют-альбом, посвящённый трём мирам: Hellsing, Devil May Cry и Bayonetta.\r\nКаждая арка — это самостоятельная музыкальная глава, где переплетаются кровь и вера, стиль и безумие, братство и одиночество.\r\n\r\nВ жанровом ядре альбома — симфонический метал, готический оркестровый пафос, мощные гитары и вокальные дуэли, перемежающиеся бархатным речитативом и боевыми хорами.\r\n\r\nЗдесь нет спасения. Нет праведников. Только герои, которые не просят прощения, и враги, что не умрут без аплодисментов.', '/public/uploads/album_covers/690629c14d144.png', '2025-02-04', '2025-11-01 17:39:45', '2025-11-01 17:39:45'),
(9, 'Гримуар Гнева vol.2', 'Гримуар гнева. Vol.2\r\n\r\n\"Гримуар гнева\" - это апокалиптическая симфония о падении героев и рождении истинных монстров. Второй альбом концептуальной дилогии продолжает историю, начатую в \"Гримуаре греха\", но выводит её на космический уровень разрушения.\r\nАльбом открывается освобождением древних сил - Алукард разрывает оковы служения, становясь тем кошмаром, которым был создан быть. Это запускает цепную реакцию: каждый герой переходит свою точку невозврата, принимая самые тёмные аспекты своей природы. Серас становится полноценным хищником, Вергилий сливается с Ямато в поисках абсолютной силы, а новые игроки входят в эту симфонию разрушения со своими мотивами мести и власти.\r\nКульминацией становится появление силы, превосходящей всех - древнего зла за гранью самого понятия греха. Перед лицом космического ужаса все конфликты героев становятся бессмысленными. Финальные треки рисуют картину полного поражения - даже объединившись, легендарные воины не могут противостоять тому, что старше самого творения.\r\n\"Гримуар гнева\" - это не история о героизме или искуплении. Это эпос о гордыне, падении и осознании собственной ничтожности перед лицом истинной тьмы. Альбом задаёт вопрос: что происходит, когда монстры, считающие себя богами, встречают настоящую бездну?\r\nМузыкально альбом сочетает симфонический металл с элементами готики, индастриала и блэка, создавая звуковой ландшафт апокалипсиса. От интимных баллад одиночества до эпических батальных гимнов - каждый трек добавляет новый мазок к общей картине конца света.', '/public/uploads/album_covers/69062d800f411.png', '2025-05-25', '2025-11-01 17:55:44', '2025-11-01 17:55:44'),
(10, 'Гримуар вечности vol.3', 'В финальном акте из пепла катастрофы рождается новая надежда. Герои перерождаются, находя силу не в разрушении, а в защите. Алукард становится хранителем жизни, Серас учится милосердию, братья объединяются против общего врага.', '/public/uploads/album_covers/690630ce1802c.png', '2025-08-19', '2025-11-01 18:09:50', '2025-11-01 18:09:50'),
(11, 'Перекрестки времен', '\"Перекрестки Времён\" — концептуальный металл-альбом группы Master of Illusion, представляющий собой эпическое музыкальное путешествие через ключевые моменты человеческой истории. От античных сражений до цифровой эры — каждый трек это портал в определённую эпоху, где решалась судьба цивилизаций.\r\nАльбом объединяет различные направления металла: от яростного power metal и атмосферного heavy до симфонического величия и индустриального футуризма. Два инструментальных трека служат музыкальными мостами между эпохами, создавая ощущение единого повествования.\r\nЭто не просто сборник песен о войнах — это размышление о цене свободы, чести, верности и о том, как меняется человечество, проходя через \"перекрестки времён\". Финальный бонус-трек замыкает круг, обращая взгляд в будущее, где человек встречается лицом к лицу с собственным творением — искусственным разумом.', '/public/uploads/album_covers/690ef6aee4cea.png', '2025-11-08', '2025-11-08 09:52:14', '2025-11-08 09:52:14'),
(12, 'Забытые Сказки', 'Есть сказки, которые не заканчиваются хорошо.\r\nЕсть герои, которых не принято вспоминать.\r\nЕсть истории, которые рассказывают только ночью — и только тем, кто готов слушать.\r\n\r\nMaster of Illusion собрали их все в одном альбоме.\r\n\r\n«Забытые Сказки» — шестнадцать живых концертных треков, записанных на одном дыхании. Здесь нет студийного глянца и компьютерных правок. Только сцена, зал и истории, которые давно просились наружу. Тёмный панк, folk punk, психобилли, тяжёлый металл и две баллады, которые останутся с тобой надолго — вот из чего сшит этот альбом.\r\nГруппа намеренно работала в живом формате — каждый трек дышит залом, каждый припев написан так, чтобы его орали хором. Никакой дистанции между сценой и первым рядом.\r\n\r\nАльбом был собран при участии SUNO, его роль в этой работе, музыкальный композитор, тексты оригинальны и написаны лично группой Master Of Illusion', '/public/uploads/album_covers/69bfc6c36f267.png', '2026-03-22', '2026-03-22 10:38:59', '2026-03-22 10:38:59'),
(13, 'Эхо миров (REMASTER)', 'Переиздание самого первого релиза - Эхо миров. Создан в совершенно новом и свежем варианте и звучании.', '/public/uploads/album_covers/69bfe94a89ba2.png', '2026-01-22', '2026-03-22 13:06:18', '2026-03-22 13:06:18'),
(14, 'Повелитель теней', 'Альбом «Повелитель теней» — это путешествие от тьмы к тьме, но через огонь. Десять историй о людях которые не сгибаются — под властью, под потерей, под одиночеством, под самой смертью. Русский тяжёлый металл в лучших традициях Арии и Manowar — с душой, с образами, с достоинством.', '/public/uploads/album_covers/13ec95a2cb83398325f3a90a2be34d1e0d26ef6ecf29dc49d005709318842eea.png', '2026-04-11', '2026-04-11 21:54:49', '2026-04-11 21:54:49');

