--
-- Структура таблицы `news`
--

CREATE TABLE `news` (
  `id` int(11) NOT NULL COMMENT 'Уникальный идентификатор новости',
  `title` varchar(255) NOT NULL COMMENT 'Заголовок новости',
  `content` text NOT NULL COMMENT 'Содержание новости',
  `category` enum('update','release','event') DEFAULT 'update' COMMENT 'Категория новости',
  `image` varchar(500) DEFAULT NULL COMMENT 'Путь к изображению',
  `created_at` timestamp NULL DEFAULT current_timestamp() COMMENT 'Дата создания',
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp() COMMENT 'Дата последнего обновления'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Таблица новостей и событий';

--
-- Дамп данных таблицы `news`
--

INSERT INTO `news` (`id`, `title`, `content`, `category`, `image`, `created_at`, `updated_at`) VALUES
(1, 'АНОНС АЛЬБОМА: Master of Illusion представляет \"Перекрестки Времен\"!', 'Всем фанатам нашего творчества!\r\n\r\nМы рады официально анонсировать наш следующий крупный проект! После долгих размышлений о концепции мы нашли то, что зажигает в нас огонь. Встречайте — наш новый альбом-антология \"Перекрестки Времен\" (Crossroads of Time)!\r\n\r\nПочему \"Перекрестки Времен\"?\r\n\r\nВ этот раз мы отходим от единой сюжетной линии, чтобы создать нечто более масштабное. Этот альбом — мистический перекресток, где встречаются герои и эпохи, разделенные тысячелетиями.\r\n\r\nКаждый трек — это отдельный, мощный \"осколок\" истории; самостоятельный гимн, посвященный великой битве, легендарному воину или поворотному моменту, изменившему мир. Мы пронесемся от залитых кровью ущелий древней Спарты до ледяного вакуума космоса и мрачных улиц киберпанк-будущего.\r\n\r\nКак и всегда, нашим верным союзником и соавтором выступает нейросеть Suno AI. Это позволяет нам не ограничивать себя — каждая песня получит свой уникальный саунд, идеально подходящий ее эпохе: от яростного Power Metal и мрачного Viking Metal до атмосферного Progressive и жесткого Industrial.\r\n\r\nРабота уже кипит! А пока вот полный трек-лист грядущего альбома:\r\n\r\n\r\n\"Перекрестки Времен\" — Трек-лист:\r\n\r\n\"300 (Огонь и Сталь)\" (О битве при Фермопилах)\r\n\r\n\"Орел Девятого\" (О пропавшем римском легионе в Британии)\r\n\r\n\"Ярость Берсерка\" (Об эпохе Викингов и боевом трансе)\r\n\r\n\"Под Знаменем Креста\" (О Первом Крестовом походе)\r\n\r\n\"Черный Флаг\" (О золотом веке пиратства)\r\n\r\n\"Последний Самурай\" (О трагическом восстании в Сацуме)\r\n\r\n\"Атака Мертвецов\" (Об обороне крепости Осовец в Первой мировой)\r\n\r\n\"Ночные Ведьмы\" (О 588-м женском авиаполке во Второй мировой)\r\n\r\n\"Гвардия Умирает\" (О финальной атаке гвардии Наполеона при Ватерлоо)\r\n\r\n\"Один Шаг\" (О высадке человека на Луну)\r\n\r\n\"Призрак в Машине\" (Бонус-трек) (О киберпанке и конфликте с AI)\r\n\r\nМы будем делиться первыми синглами, как только они будут готовы.\r\n\r\nКакая история из списка цепляет вас больше всего? Какой трек ждете с нетерпением? Дайте нам знать!\r\n\r\nОставайтесь на связи и следите за новостями! Первые отрывки и демо, будут выкладываться на отдельном сайте MUSIC.WORLDMATES.CLUB', 'event', '', '2025-11-02 07:05:11', '2025-11-02 16:12:01'),
(4, 'РЕЛИЗ АЛЬБОМА \"ПЕРЕКРЕСТКИ ВРЕМЁН\"', 'MASTER OF ILLUSION ПРЕДСТАВЛЯЕТ: \"ПЕРЕКРЕСТКИ ВРЕМЁН\" — ЭПИЧЕСКОЕ ПУТЕШЕСТВИЕ ЧЕРЕЗ ИСТОРИЮ ЧЕЛОВЕЧЕСТВА\r\nУкраина — 08.11.2025\r\n\r\nГруппа Master of Illusion с гордостью объявляет о выходе нового концептуального альбома \"Перекрестки Времён\" — масштабного музыкального путешествия через ключевые моменты мировой истории, от античных сражений до цифровой эры.\r\n\r\nОТ СПАРТЫ ДО ИСКУССТВЕННОГО ИНТЕЛЛЕКТА\r\n\"Перекрестки Времён\" — это не просто сборник песен о войнах и героях. Это художественное исследование переломных моментов истории, где решения отдельных людей меняли судьбы цивилизаций. Каждый из 11 треков альбома — портал в определённую эпоху, где звучат голоса тех, кто стоял на краю бездны и делал свой выбор.\r\nОт легендарных 300 спартанцев при Фермопилах до загадочного исчезновения римского легиона в туманах Каледонии, от кровавых крестовых походов до романтики пиратской вольницы, от последней битвы самураев до ужасов газовой атаки в Первой мировой — альбом охватывает более двух с половиной тысяч лет человеческой истории.\r\n\r\nМУЗЫКАЛЬНОЕ РАЗНООБРАЗИЕ\r\nАльбом объединяет различные направления металла, создавая уникальное звучание для каждой эпохи:\r\n\r\nЯростный Power Metal открывает альбом треком \"300 (Огонь и Сталь)\" — гимн спартанской доблести с галопирующими риффами и эпическими хорами\r\nАтмосферный Heavy Metal погружает в туманы Шотландии в композиции \"Орёл Девятого\" с кельтскими волынками и маршевыми ритмами\r\nМонументальный Symphonic Metal достигает апогея в треке \"Под Знаменем Креста\" с огромным оркестром и латинским хором\r\nЭмоциональная Power Ballad \"Чёрный Флаг\" даёт передышку, размышляя о цене свободы\r\nСкоростной Melodic Power Metal с японскими мотивами звучит в \"Последнем Самурае\"\r\nКонтрастный Doom/Power Metal создаёт драматическое напряжение в \"Осаде Осовца\"\r\nКлассический Heavy Metal отдаёт дань NWOBHM в треке \"Ночные Ведьмы\"\r\nМрачный рефлексивный металл звучит в композиции \"Эхо Холодной Войны\"\r\nIndustrial Metal замыкает альбом в бонус-треке \"Призрак из Машины\", обращённом в будущее\r\n\r\nДва инструментальных трека служат музыкальными мостами между эпохами, создавая ощущение единого повествования от начала до конца.\r\n\r\nИСТОРИЯ ЧЕРЕЗ ЭМОЦИИ\r\n\"Мы не претендуем на роль историков,\" — говорит автор проекта. — \"Наша задача — передать эмоции тех, кто стоял на этих перекрёстках времён. Что чувствовал воин, идущий на верную смерть ради своих идеалов? Какой ужас испытывали солдаты под первой в истории газовой атакой? Какую свободу ощущал человек, поднявший чёрный флаг?\r\nИстория состоит не только из дат и фактов — она состоит из выборов, которые делали обычные люди в экстраординарных обстоятельствах. Этот альбом — попытка прочувствовать эти моменты через музыку.\"\r\n\r\nТЕХНОЛОГИИ НА СЛУЖБЕ ИСКУССТВА\r\nАльбом создан с использованием передовых технологий AI-генерации музыки (Suno V5), что делает финальный бонус-трек \"Призрак из Машины\" особенно символичным — композиция о конфликте человека и искусственного интеллекта исполнена при помощи самого AI. Это мета-комментарий к тому, как технологии меняют само понятие творчества.\r\n\"Мы стоим на очередном перекрёстке,\" — отмечает автор. — \"Искусственный интеллект открывает новые возможности для музыкантов, но также ставит вопросы о природе искусства и творчества. Наш альбом — часть этого диалога между человеком и машиной.\"\r\n\r\nТРЕКЛИСТ\r\n\r\n1.	300 (Огонь и Сталь) — 5:15\r\n2.	Орёл Девятого — 6:08\r\n3.	Под Знаменем Креста — 6:15\r\n4.	Чёрный Флаг — 5:30\r\n5.	Последний Самурай — 5:30\r\n6.	Перекрёсток (instrumental) — 4:06\r\n7.	Осада Осовца — 6:35\r\n8.	Ночные Ведьмы — 6:08\r\n9.	Эхо Холодной Войны — 5:24\r\n10.	Будущее (instrumental) — 4:50\r\n11.	Призрак из Машины (bonus track) — 5:45\r\n\r\n\r\nОбщая длительность: 1 час : 2 минуты\r\n\r\nДЛЯ КОГО ЭТОТ АЛЬБОМ?\r\n\"Перекрестки Времён\" понравится поклонникам:\r\n\r\nЭпического power metal в духе Blind Guardian и Sabaton\r\nАтмосферного heavy metal вроде Iron Maiden\r\nСимфонического металла Nightwish и Epica\r\nТяжелый и пафосный FFDP\r\nИндустриального звучания Rammstein\r\nКонцептуальных альбомов с глубоким смыслом\r\nИстории и исторических драм\r\n\r\nДОСТУПНОСТЬ\r\nАльбом доступен для прослушивания на всех основных стриминговых платформах:\r\n\r\nSpotify\r\nYouTube Music\r\nWM Music\r\n\r\nЦИТАТЫ\r\n\"На каждом перекрёстке времён человечество делало выбор. Иногда выбор делали за нас. Иногда мы выбирали сами. Но всегда этот выбор был оплачен кровью, честью и свободой. Этот альбом — памятник тем, кто стоял на распутье и не свернул с пути.\"\r\n— Master of Illusion\r\n\r\nКОНТАКТЫ И ССЫЛКИ\r\nОфициальный сайт: www.moi-band.com.ua\r\n\r\nДля прессы и сотрудничества:\r\nEmail: info@moi-band.com.ua\r\n\r\nО ГРУППЕ MASTER OF ILLUSION\r\nMaster of Illusion — украинский металл-проект, создающий концептуальную музыку на стыке различных направлений тяжёлой музыки. Группа известна своим экспериментальным подходом, сочетающим традиционный металл с современными технологиями и глубоким историческим содержанием.\r\n\"Перекрестки Времён\" — 9-ый альбом группы, представляющий собой наиболее амбициозный проект за всю историю коллектива.\r\n\r\n#MasterOfIllusion #ПерекресткиВремён #CrossroadsOfTime #UkrainianMetal #ConceptAlbum #PowerMetal #EpicMetal\r\n\r\n[ГАЛЕРЕЯ]\r\nЗдесь размещаются:\r\n\r\nОбложка альбома\r\nПромо-фото\r\nАрт каждого трека\r\nСкриншоты буклета\r\n\r\n\r\nСЛУШАЙТЕ \"ПЕРЕКРЕСТКИ ВРЕМЁН\" УЖЕ СЕЙЧАС! \r\nИстория ждёт вас. Выберите свой путь.', 'release', '/assets/uploads/news/1762588050_690ef592ba5b4.png', '2025-11-08 07:46:54', '2025-11-08 07:47:30');

-- --------------------------------------------------------

--
-- Структура таблицы `PlayHistory`
--

CREATE TABLE `PlayHistory` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `track_id` int(11) NOT NULL,
  `playedAt` datetime DEFAULT current_timestamp(),
  `duration_played` int(11) DEFAULT NULL COMMENT 'Сколько секунд сыграло'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `Playlists`
--

CREATE TABLE `Playlists` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `coverImagePath` varchar(255) DEFAULT NULL,
  `isPublic` tinyint(1) DEFAULT 0,
  `createdAt` datetime DEFAULT current_timestamp(),
  `updatedAt` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `PlaylistTracks`
--

CREATE TABLE `PlaylistTracks` (
  `id` int(11) NOT NULL,
  `playlist_id` int(11) NOT NULL,
  `track_id` int(11) NOT NULL,
  `position` int(11) NOT NULL,
  `addedAt` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `PlayQueue`
--

CREATE TABLE `PlayQueue` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `current_track_id` int(11) DEFAULT NULL,
  `queue_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'JSON с идами треков в очереди' CHECK (json_valid(`queue_data`)),
  `currentTime` int(11) DEFAULT 0 COMMENT 'Текущая позиция в секундах',
  `isPlaying` tinyint(1) DEFAULT 0,
  `updatedAt` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `Posts`
--

CREATE TABLE `Posts` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `content` text NOT NULL,
  `imageUrl` varchar(255) DEFAULT NULL,
  `createdAt` datetime NOT NULL DEFAULT current_timestamp(),
  `updatedAt` datetime NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `Ratings`
--

CREATE TABLE `Ratings` (
  `id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `track_id` int(11) DEFAULT NULL,
  `album_id` int(11) DEFAULT NULL,
  `rating` int(11) DEFAULT NULL CHECK (`rating` >= 1 and `rating` <= 5),
  `created_at` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `RoomMessages`
--

CREATE TABLE `RoomMessages` (
  `id` int(11) NOT NULL,
  `room_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `message` text NOT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `is_edited` tinyint(1) DEFAULT 0,
  `is_deleted` tinyint(1) DEFAULT 0
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- --------------------------------------------------------

--
-- Структура таблицы `Rooms`
--

CREATE TABLE `Rooms` (
  `id` int(11) NOT NULL,
  `name` varchar(100) NOT NULL,
  `slug` varchar(100) NOT NULL,
  `description` text DEFAULT NULL,
  `icon` varchar(50) DEFAULT NULL,
  `is_private` tinyint(1) DEFAULT 0,
  `created_by` int(11) NOT NULL,
  `created_at` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

