INSERT INTO `SongLyrics` (`id`, `track_id`, `lyrics`, `createdAt`, `updatedAt`) VALUES
(2, 38, '[Verse 1]\r\nВ далёких горах, где туман\r\nСкрывает древние руины\r\nСпит последний великан\r\nДракон забытой долины.\r\nВека прошли с тех пор\r\nКогда он правил небесами.\r\nТеперь лишь старый фольклор\r\nХранит память о деяньях.\r\n\r\nНо пламя в сердце не погасло,\r\nХоть мир забыл о чудесах.\r\nПришло время сбросить маски,\r\nИ вновь расправить два крыла!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстанет из пепла.\r\nПройдёт сквозь все миры\r\nЛюдских забытых снов.\r\nОгненным дыханием,\r\nНебо озарит.\r\nИ древним заклинанием\r\nМир преобразит!\r\n\r\n[Verse 2]\r\nРыцари давно забыли,\r\nКак сражаться с ним.\r\nМечи от ржи затупились,\r\nВ век новых технологий.\r\nНо есть среди людей один,\r\nКто верит в старые сказанья.\r\nОн знает - мифов властелин\r\nВернётся для воздаянья.\r\n\r\nВедь пламя в сердце не погасло,\r\nХоть мир забыл о чудесах.\r\nПришло время сбросить маски,\r\nИ вновь расправить два крыла!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстанет из пепла.\r\nПройдёт сквозь все миры\r\nЛюдских забытых снов.\r\nОгненным дыханием,\r\nНебо озарит.\r\nИ древним заклинанием\r\nМир преобразит!\r\n\r\n[Bridge]\r\nПроснись, великий дракон!\r\nТвой час настал опять\r\nРазрушь обмана закон\r\nИ магию верни назад!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстал из глубины.\r\nСломал людские троны\r\nИ рушит их умы.\r\nЗолотым сияньем\r\nМир теперь объят.\r\nНовым мирозданьем\r\nПравит древний ритуал!', '2025-10-19 17:40:46', '2025-10-19 17:40:46'),
(5, 92, '[verse 1]\r\nВ серці тиснуть залізні кайдани,\r\nНа очах у нас тисячі нових стін.\r\nСкільки слів поховали у рани,\r\nСкільки правди затис у свій сплін?\r\n\r\nНас ламають, нас ставлять на коліна,\r\nЇхній страх — це вогонь в наших жилах!\r\nПоки кров закипає в долонях,\r\nМи піднімемось знов!\r\n\r\n[pre-chorus]\r\nМи не мовчимо, наші голоси — грім,\r\nЦе не наша війна, і це не наш режим.\r\nПалають кайдани, тримтять їхні страхи,\r\nНас не зламати, вогонь у серцях!\r\n\r\n[chorus]\r\nВоля в ланцюгах, та серце палає,\r\nКрізь темряву ніч наш промінь сягає.\r\nСлова не розіб\'ють, не спинять біду,\r\nМи волю здобудем — на нашому шляху!\r\n\r\n[verse 2]\r\nЗалишилось тільки слово й надія,\r\nЇхня правда, мов дим на вітру.\r\nХтось боїться, хтось плаче від втрати,\r\nАле ми — це незламні воїни.\r\n\r\nСкільки раз нам в спину стріляли,\r\nСкільки раз нас кидали у бій,\r\nТа залізо не ріже закалений камінь,\r\nБо ми всі свободні. Відбій!\r\n\r\n[pre-chorus]\r\nМи не мовчимо, наші голоси — грім,\r\nЦе не наша війна, і це не наш режим.\r\nПалають кайдани, тримтять їхні страхи,\r\nНас не зламати, вогонь у серцях!\r\n\r\n[chorus]\r\nВоля в ланцюгах, та серце палає,\r\nКрізь темряву ніч наш промінь сягає.\r\nСлова не розіб\'ють, не спинять біду,\r\nМи волю здобудем — на нашому шляху!\r\n\r\n[bridge]\r\nСкільки ще кроків до свободи?\r\nСкільки ще ран витримає земля?\r\nМи не впадем, ми станем стіною!\r\nНашу свободу ми здобудем вогнем!\r\n\r\n\r\n[final chorus]\r\nВоля в ланцюгах — але ми ще живі!\r\nЗ вогнем у руках і гнівом в крові.\r\nЇхні слова — лише попіл вітру,\r\nМи не здамося, наш шлях в руках!\r\n\r\n[outro]\r\nВоля в ланцюгах… Але ми ще живі…\r\nНаш крик не згасне… Ми прорвемо метал.', '2025-10-25 10:56:16', '2025-10-25 10:56:16'),
(7, 95, '[verse 1]\r\nКрізь морок, крізь холод, крізь безліч страхів,\r\nМи йдемо туди, де ще жоден не був.\r\nНа уламках надій ми будуєм мости,\r\nБо зламати цей світ не дозволим собі.\r\n\r\nВітри у обличчя, вогонь у грудях,\r\nНіхто нас не зупинить на цьому шляху!\r\nЦе не просто слова, це не просто ідея,\r\nЦе наш час, і він справді прийшов!\r\n\r\n[pre-chorus]:\r\nВідчуваєш у серці цей битий пульс?\r\nЦе свобода, що рветься крізь час і брухт!\r\n\r\n[chorus]\r\nЗа межу, де світло живе в крові,\r\nМи зламаєм цей морок на самоті!\r\nНаші руки тримають цей світ в долонях,\r\nМи переможем у цій війні!\r\n\r\n[verse 2]:\r\nТам, де тіні минулого рвуться назад,\r\nМи палим мости, щоб не було втрат.\r\nНаші голоси, як грім у ночі,\r\nМи залишим слід, навіть серед дощів.\r\n\r\nКожен із нас — це вогонь і сталь,\r\nНаш вибір простий: вперед або в прірву.\r\nЦей шлях нелегкий, але нас не зламати,\r\nМи вже за межею, і нам не здолати!\r\n\r\n[pre-chorus]\r\nВідчуваєш у серці цей битий пульс?\r\nЦе свобода, що рветься крізь час і брухт!\r\n\r\n[chorus]\r\nЗа межу, де світло живе в крові,\r\nМи зламаєм цей морок на самоті!\r\nНаші руки тримають цей світ в долонях,\r\nМи переможем у цій війні!\r\n\r\n[Bridge]\r\nСтіни падають, грані стираються,\r\nМи творимо світ, де зло розбивається.\r\nНас не зупинить, нас не зламає,\r\nНаш дух летить туди, де світло сягає!\r\n\r\n[final chorus]:\r\nЗа межу, де сонце горить над нами,\r\nДе свобода народжується з вогню!\r\nНаші серця — це зброя, наш крик — це правда,\r\nМи розірвем ланцюги в цьому сну!\r\n\r\n[outro]\r\nВоля жива… Воля в нас…\r\nКожен з нас — це світло, що несе крізь час.', '2025-10-25 10:56:52', '2025-10-25 10:56:52'),
(9, 39, '[verse 1]\r\nТысячелетие во тьме охраняя вечный свет,\r\nЯ хранил священный дар, нерушимый мой завет.\r\nВ глубине древних пещер, где живу я тысячу лет\r\nТам где время не течет, сон окутывал меня.\r\n\r\n\r\nЧувствую как сквозь века, прорастает в сердце страх\r\nЧто-то древнее зовет, пробуждая меня...\r\n\r\n[chorus]\r\nСтраж вечного огня\r\nВосстань от векового сна.\r\nСвященное пламя зовет,\r\nСудьба свой путь ведет.\r\n\r\n[verse 2]\r\nВ глубоком сне я видел этот день\r\nПредсказанье древних книг.\r\nКогда тьма восстанет вновь,\r\nИ раздастся первый крик.\r\nСквозь завесу долгих лет,\r\nСлышу зов священных слов,\r\nПламя вечности дрожит,\r\nРазрывая цепи снов\r\n\r\n\r\nПробуждение несет, весть о битве впереди.\r\nСтраж пробудился что бы защитить...\r\n\r\n[chorus]\r\nСтраж вечного огня\r\nВосстань от векового сна.\r\nСвященное пламя зовет,\r\nСудьба свой путь ведет.\r\n\r\n[bridge]\r\nВ ветрах при сном святом спят под пеленой,\r\nПламя вечности зовет, стража долг его ведет.\r\nСковзь завесу темноты, вижу яркие следы.\r\nЧас пришел и путь открыт...\r\n\r\n[bridge]\r\nВ глубине моей души, память предков говорит.\r\nО священном долге том, что веками был сокрыт.\r\nСила пламени течет, в венах древней крови той,\r\nЧто связала нас тогда стража с вечною судьбой.\r\n\r\nПоднимаюсь ото сна, слыша зов из далека.\r\nВремя битвы настает, пробудилась - тьма!\r\n\r\n[chorus]\r\nСтраж вечного огня\r\nВосстань от векового сна.\r\nСвященное пламя зовет,\r\nСудьба свой путь ведет.', '2025-10-27 08:34:40', '2025-10-27 08:34:40'),
(10, 40, '[Verse 1]\r\nПод знамёнами стали\r\nИдём сквозь огонь и дым.\r\nБратья по оружию встали,\r\nВ строю непобедимым.\r\nКлятву дали друг другу,\r\nНе отступать назад.\r\nПройдёт любую вьюгу,\r\nСтальной наш легион-отряд.\r\n\r\n\r\nЖелезом закалённые сердца,\r\nБьются в унисон.\r\nНет конца у нашего пути...\r\n\r\n[Chorus]\r\nСтальной легион идёт в бой\r\nМечи сверкают в ночи.\r\nНи шагу назад, только вперёд\r\nБратство стальных палачей.\r\nСтальной легион - наша сила,\r\nВ единстве несокрушимом\r\nВраг пощады не просил,\r\nНо мы пощады не дадим!\r\n\r\n[Verse 2]\r\nНа поле брани кровавом,\r\nМы держим общий строй.\r\nПлечом к плечу со славой,\r\nСражаемся как один герой.\r\nПадут враги у наших ног,\r\nРазрушим их ряды.\r\nНас ведёт в бой сам Бог,\r\nКровавой войны!\r\n\r\n[Chorus]\r\nСтальной легион идёт в бой\r\nМечи сверкают в ночи.\r\nНи шагу назад, только вперёд\r\nБратство стальных палачей.\r\nСтальной легион - наша сила,\r\nВ единстве несокрушимом\r\nВраг пощады не просил,\r\nНо мы пощады не дадим!\r\n\r\n[Bridge]\r\nСталь против стали звенит\r\nВ танце смертельных мечей.\r\nКровь с клинков стекает,\r\nМесть за павших друзей!\r\n\r\n[Chorus]\r\nСтальной легион идёт в бой\r\nМечи сверкают в ночи.\r\nСквозь века пронесём\r\nНаши имена навсегда!', '2025-10-27 08:35:03', '2025-10-27 08:35:03'),
(11, 41, '[Verse 1]\r\nВ храме древнем средь камней\r\nПламя тысячу лет горит\r\nФеникс спит в огне своём\r\nВечным сном он был сокрыт\r\nНо приходит время тьмы\r\nДемоны идут войной\r\nЧтобы свет погасить\r\nИ покрыть мир пеленой\r\n\r\n\r\nСлышит зов священный,\r\nПробуждает дух древний\r\nПоднимается из пепла\r\nОгненный крылатый бог!\r\n\r\n[Chorus]\r\nОгненный феникс восстаёт,\r\nКрылья раскинет над храмом огня.\r\nПротив армии тьмы он летит\r\nСвет защищая от зла.\r\nФеникс летит в поднебесье\r\nИскры сыплются под ним.\r\nДревняя магия, вечная песня\r\nМир от забвения он сохранит!\r\n\r\n[Verse 2]\r\nПамять веков в его глазах\r\nТысячи битв позади\r\nЗнает он - его судьба\r\nВсех живых людей защитить.\r\nДемоны рвутся к алтарю\r\nТьма наступает стеной\r\nНо огненная птица встаёт\r\nНа защиту света.\r\n\r\n\r\nЯрче солнца вспыхнет,\r\nСилой древних богов.\r\nРасправляет Феникс крылья\r\nДля последних врагов!\r\n\r\n[Chorus]\r\nОгненный феникс восстаёт,\r\nКрылья раскинет над храмом огня.\r\nПротив армии тьмы он летит\r\nСвет защищая от сил мрака.\r\nФеникс летит в поднебесье\r\nИскры сыплются под ним.\r\nДревняя магия, вечная песня\r\nМир от забвения он сохранит!\r\n\r\n[Bridge]\r\nВ битве огня против тьмы\r\nРешается судьба земли\r\nФеникс знает - он один\r\nКто мир может спасти!\r\n\r\n[Chorus]\r\nОгненный феникс восстаёт\r\nКрылья раскинет над храмом огня\r\nТьма побеждена, мир спасён,\r\nМир защищён от сил мрака.\r\nФеникс вернётся домой\r\nИскры сыплются звёздным дождём\r\nВечная магия, вечный полёт,\r\nХрам и огонь он хранит день за днём!', '2025-10-27 08:35:25', '2025-10-27 08:35:25'),
(12, 42, '[Verse 1]\r\nВ начале времён Эру создал\r\nМелодию мира из звёзд.\r\nВалар спустились в Арду,\r\nЧтобы воплотить замысел грёз.\r\nЭльфы проснулись в Куивиэнен,\r\nГномы родились в недрах гор.\r\nЛюди пришли с востока,\r\nХоббиты в Шире нашли свой простор.\r\n\r\n\r\nОт Валинора до Мордора,\r\nПростираются земли чудес.\r\nГде добро сражается со злом,\r\nИ каждый выбирает свой путь.\r\n\r\n[Chorus]\r\nСредиземье! Земля легенд!\r\nГде живут мечты и сказки\r\nСредиземье! Через тысячи лет\r\nПомним героев и их подвиги.\r\nРивенделл и Лориэн,\r\nРохан и Гондор,\r\nВ сердцах навеки сохранён\r\nволшебный мир, Средиземья!\r\n\r\n[Verse 2]\r\nКольца Власти были скованы,\r\nНо Тёмный Властелин обманул.\r\nОдно Кольцо чтобы править всеми,\r\nВ лаве Роковой Горы создал он.\r\nТысячи лет длились сраженья\r\nСвета с армиями тьмы.\r\nНо маленький хоббит по имени Фродо,\r\nСпас мир от злой судьбы.\r\n\r\n\r\nОт Шира до Роковой Горы,\r\nЛежит путь героев.\r\n\r\n[Chorus]\r\nСредиземье! Земля легенд!\r\nГде живут мечты и сказки\r\nСредиземье! Через тысячи лет\r\nПомним героев и их подвиги.\r\nРивенделл и Лориэн,\r\nРохан и Гондор,\r\nВ сердцах навеки сохранён\r\nволшебный мир, Средиземья!\r\n\r\n[Bridge]\r\nИ пусть корабли уплыли...\r\nЗа море в далёкий край...\r\nМы песни не забыли,\r\nО земле, что сохранили!\r\n\r\n[Chorus]\r\nСредиземье! Земля чудес!\r\nГде каждый камень хранит историю.\r\nСредиземье! Магический лес,\r\nНавсегда останется с нами в памяти.\r\nОт Серых Гаваней до Мордора,\r\nПростираются земли мечты.\r\nПусть закончилась эпоха\r\nНо в песнях живут... Эти герои!', '2025-10-27 08:35:47', '2025-10-27 08:35:47'),
(13, 43, '[Verse 1]\r\nМоя принцесса, час настал прощанья\r\nСудьба зовёт меня в последний бой\r\nХочу сказать слова, что жгут сознанье\r\nПока ещё я рядом здесь с тобой\r\nТы говоришь, что видишь нити рока\r\nЧто знаешь ты о том, что ждёт меня\r\nНо я прошу - не плачь так одиноко\r\nХрани в душе огонь любви и дня\r\n\r\n\r\nНам не дано прожить обычной жизнью\r\nЛюбовь наша прекрасна и больна...\r\n\r\n[Chorus]\r\nПрощай, моя любовь, прощай навеки,\r\nНо в сердце ты останешься со мной.\r\nПусть разлучают нас дороги, реки,\r\nЛюбовь наша сильнее, чем покой.\r\nПрощальный поцелуй на губах тает,\r\nСлеза последняя катится вниз.\r\nДуша моя тебя не забывает,\r\nГде бы ни был - ты мой парадиз.\r\n\r\n[Verse 2]\r\nКлянусь тебе - вернусь, коль буду жив,\r\nНо если смерть настигнет на дороге.\r\nМолю - не плачь, а помни, как красив,\r\nБыл наш с тобою мир в земном чертоге.\r\nТы обещаешь ждать меня, любя,\r\nВстречать рассветы в муках ожиданья.\r\nИ если смерть возьмёт меня, себя\r\nТы проклянёшь за верность и страданья.\r\n\r\n\r\nСудьба жестока к тем, кто любит страстно\r\nНо наша любовь сильней, чем рок...\r\n\r\n[Chorus]\r\nПрощай, моя любовь, прощай навеки\r\nНо в сердце ты останешься со мной\r\nПусть разлучают нас дороги, реки\r\nЛюбовь наша сильнее, чем покой\r\nПрощальный поцелуй на губах тает\r\nСлеза последняя катится вниз\r\nДуша моя тебя не забывает\r\nГде бы ни был - ты мой парадиз\r\n\r\n[Bridge]\r\nИду я в ночь, а ты молишься небу,\r\nХрани, любовь, нас в разлуке!\r\n\r\n[Chorus]\r\nПрощай, моя любовь, но не навеки,\r\nВ другом мире мы встретимся с тобой.\r\nТам нет разлук, дорог и рек,\r\nТам наша любовь обретёт покой.\r\nПоследний поцелуй как благословенье,\r\nПоследний взгляд как обещанье жить.\r\nВ сердцах храним любви мгновенья,\r\nЧто смерть не сможет погубить.', '2025-10-27 08:36:11', '2025-10-27 08:36:11'),
(14, 45, '[Verse 1]\r\nВ башне древней на краю земли,\r\nГде туман скрывает горизонт.\r\nМаг изгнанный коротает дни,\r\nИзучая запретный плод.\r\n\r\nБелый орден отверг его когда-то,\r\nЗа стремление познать запретный путь.\r\nПравда - в знаниях, но не в догматах,\r\nОн решил тогда свой выбрать путь.\r\n\r\nГоды в ссылке, годы в одиночестве\r\nЛишь луна свидетель его дел.\r\nТёмная магия даёт могущество\r\nНо какую цену он заплатить сумел?\r\n\r\n\r\nМежду светом и тьмой\r\nОн идёт своей тропой\r\nОтвергнутый всеми\r\nНо со свободною душой!\r\n\r\n[Chorus]\r\nЧёрный маг - изгнанник мира,\r\nПроклятый орденом и людьми.\r\nЧёрный маг - хранитель знаний,\r\nЧто другие боятся постичь.\r\n\r\nОдин в башне средь книг и свитков,\r\nСила тёмная течёт в его венах.\r\nЧёрный маг живёт без наследия,\r\nТолько истина в его мечтах!\r\n\r\n[Verse 2]\r\nПомнит он те светлые дни,\r\nКогда братом звали в ордене.\r\nНо вопросы жгли его мозги,\r\nО границах, что нельзя переступать.\r\n\r\n\"Почему запретна эта магия?\r\nРазве знание бывает злом?\r\nИли просто древняя иерархия,\r\nСтрах свой не может постичь?\"\r\n\r\nОн посмел спросить у старейшин\r\nНо ответом был лишь приговор\r\n\"Изгнан будешь ты за ересь\r\nБольше не войдёшь ты в этот двор!\"\r\n\r\n\r\nМежду светом и тьмой\r\nОн идёт своей тропой\r\nВ запретных книгах,\r\nОбрёл смысл живой!\r\n\r\n[Chorus]\r\nЧёрный маг - изгнанник мира,\r\nПроклятый орденом и людьми.\r\nЧёрный маг - хранитель знаний,\r\nЧто другие боятся постичь.\r\n\r\nОдин в башне средь книг и свитков,\r\nСила тёмная течёт в его венах.\r\nЧёрный маг живёт без наследия,\r\nТолько истина в его мечтах!\r\n\r\n[Verse 3]\r\nЗеркало показывает правду\r\nОтражение пугает иногда\r\nЧто он видит? Мудреца? Иль падшего?\r\nГрань стирается день ото дня.\r\n\r\nСила есть, но нет того света,\r\nЧто когда-то светило ему.\r\nОдиночество это - его судьба,\r\nЧто бы мог, мыслить и творить.\r\n\r\n[Pre-Chorus]\r\nМежду светом и тьмой\r\nРастворился образ мой\r\nНи добро, ни зло\r\nТолько знание со мной\r\nЦена свободы высока\r\nОдиночество - мой дом\r\nНо душа ещё жива\r\nПока бьётся сердце в нём!\r\n\r\n[Chorus]\r\nЧёрный маг - повелитель знаний,\r\nНе герой и не злодей.\r\nЧёрный маг - хранитель тайны,\r\nЧто пугает всех людей.\r\nБашня - вечный дом скитальца,\r\nТьма и свет в его глазах.\r\nЧёрный маг продолжит сражаться,\r\nЗа свободу в своих светлых снах!', '2025-10-27 08:36:33', '2025-10-27 08:36:33'),
(15, 46, '[Verse 1]\r\nПринцем был я Лордерона,\r\nСветлым паладином рождён.\r\nЗащищал народ и корону,\r\nВерил в правду и закон.\r\nНо пришла чума и скверна,\r\nДемон Мал\'Ганис сжигал.\r\nПоклялся я отомстить непременно,\r\nВ Нортренд путь свой держал.\r\n\r\n\r\nМесть сжигала моё сердце\r\nОслепила светлый путь...\r\n\r\n[Chorus]\r\nЛедяной трон зовёт меня,\r\nФростморн в руках моих.\r\nДуша продана за силу огня\r\nТьма поглотила мой последний крик.\r\nКорона льда ждёт меня,\r\nЛедяной трон - судьба моя.\r\nНет дороги в прошлые дни\r\nЯ потерян во тьме!\r\n\r\n[Verse 2]\r\nПроклятый меч взял я в ладонь,\r\nВласть и силу приобрёл.\r\nНо забрал он душу и боль\r\nИ свет навеки потерял.\r\nВернулся домой героем мнимым\r\nОтца предал, корону забрал.\r\nСтал я монстром нелюдимым,\r\nВсё что любил - сам же и разрушал.\r\n\r\n\r\nКороль-лич звал меня на север\r\nК трону ледяному во тьме присягнуть...\r\n\r\n[Chorus]\r\nЛедяной трон зовёт меня,\r\nФростморн в руках моих.\r\nДуша продана за силу огня\r\nТьма поглотила мой последний крик.\r\nКорона льда ждёт меня,\r\nЛедяной трон - судьба моя.\r\nНет дороги в прошлые дни\r\nЯ потерян во тьме!\r\n\r\n[Verse 3]\r\nВсё потерял я на пути\r\nСилу обрёл взамен\r\nНа троне буду вечно гнить,\r\nВ царстве холода и тьмы...\r\n\r\n[Chorus]\r\n(Ледяной трон...)\r\nЛедяной трон - вечность моя\r\nВ царстве мёрзлых сердец.\r\nЯ владыка, я смерть, я тьма\r\nАрмию нежити веду\r\n(Ледяной трон) хранит во льдах\r\nТайну падшего героя\r\nНет пути назад в светлых днях\r\nТолько холод, тьма и горе!\r\n\r\n[Outro]\r\n(Ледяной трон...)\r\nвечность моя...\r\n(Ледяной трон...)\r\nТолько холод, тьма и горе!', '2025-10-27 08:36:57', '2025-10-27 08:36:57'),
(16, 47, '[Verse 1]\r\nПомню день, что сердце рвёт,\r\nКогда клинок твой путь пресёк.\r\nТы грудью встала за меня,\r\nМою судьбу приняв в себя.\r\n\r\nТы упала в мои объятья,\r\nКровь текла в лучах заката.\r\nТы шептала: «Всё пройдет»,\r\nНо свет в глазах твоих угас, в тот же час...\r\n\r\n\r\nЯ дышу, а ты ушла,\r\nГде же правда, где судьба?\r\n\r\n[Chorus]\r\nЦена любви — твой светлый лик,\r\nЗа грех мой жизнь твоя горит.\r\nВ каждом вздохе, в каждом дне\r\nТы будешь вечно жить во мне.\r\nНе прощу я сам себя (себя),\r\nЗа ту беду, что к нам пришла.\r\nТы любила, меня храня,\r\nА я в аду живу, скорбя.\r\n\r\n(Ты любила, меня храня)\r\nА я в аду живу, скорбя...\r\n\r\n[Verse 2]\r\nКаждой ночью в тишине\r\nТы приходишь в ясных снах ко мне.\r\nТвоя улыбка — солнца свет,\r\nКак в те года, где боли нет.\r\nТы шепчешь тихо: «Не грусти» (не грусти),\r\nГоворишь мне: «Меня найди» (найди).\r\nНо с рассветом, открыв глаза,\r\nЯ теряю тебя навсегда.\r\n\r\n\r\nЯ живу, а ты ушла,\r\nСправедливость где она?\r\n\r\n[Chorus]\r\nЦена любви — твой светлый лик,\r\nЗа грех мой жизнь твоя горит.\r\nВ каждом вздохе, в каждом дне\r\nТы будешь вечно жить во мне.\r\nНе прощу я сам себя (себя),\r\nЗа ту беду, что к нам пришла.\r\nТы любила, меня храня,\r\nА я в аду живу, скорбя.\r\n\r\n(Ты любила, меня храня)\r\nА я в аду живу, скорбя...\r\n\r\n[Bridge]\r\nЕсли б мог я время вернуть,\r\nЯ б тебе даровал свой путь.\r\nПусть бы смерть забрала меня,\r\nЧтоб ты жила, любовь храня.\r\n\r\n[Chorus]\r\nЦена любви — так высока,\r\nТы заплатила за меня сполна.\r\nПроклинаю я эти дни,\r\nГде нас судьба развела.\r\nБуду помнить я до конца (до конца),\r\nКак спасла ты меня тогда (тогда).\r\nТвоя любовь сильнее смерти,\r\nА боль моя не утихает.\r\n\r\n(Твоя любовь — бессмертный свет)\r\nМоя же боль меня... сжигает...', '2025-10-27 08:37:21', '2025-10-27 08:37:21'),
(17, 48, '[Verse 1]\r\nВ далёких горах, где туман\r\nСкрывает древние руины\r\nСпит последний великан\r\nДракон забытой долины.\r\nВека прошли с тех пор\r\nКогда он правил небесами.\r\nТеперь лишь старый фольклор\r\nХранит память о деяньях.\r\n\r\nНо пламя в сердце не погасло,\r\nХоть мир забыл о чудесах.\r\nПришло время сбросить маски,\r\nИ вновь расправить два крыла!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстанет из пепла.\r\nПройдёт сквозь все миры\r\nЛюдских забытых снов.\r\nОгненным дыханием,\r\nНебо озарит.\r\nИ древним заклинанием\r\nМир преобразит!\r\n\r\n[Verse 2]\r\nРыцари давно забыли,\r\nКак сражаться с ним.\r\nМечи от ржи затупились,\r\nВ век новых технологий.\r\nНо есть среди людей один,\r\nКто верит в старые сказанья.\r\nОн знает - мифов властелин\r\nВернётся для воздаянья.\r\n\r\nВедь пламя в сердце не погасло,\r\nХоть мир забыл о чудесах.\r\nПришло время сбросить маски,\r\nИ вновь расправить два крыла!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстанет из пепла.\r\nПройдёт сквозь все миры\r\nЛюдских забытых снов.\r\nОгненным дыханием,\r\nНебо озарит.\r\nИ древним заклинанием\r\nМир преобразит!\r\n\r\n[Bridge]\r\nПроснись, великий дракон!\r\nТвой час настал опять\r\nРазрушь обмана закон\r\nИ магию верни назад!\r\n\r\n[Chorus]\r\nПоследний из драконов\r\nВосстал из глубины.\r\nСломал людские троны\r\nИ рушит их умы.\r\nЗолотым сияньем\r\nМир теперь объят.\r\nНовым мирозданьем\r\nПравит древний ритуал!', '2025-10-27 08:37:41', '2025-10-27 08:37:41'),
(18, 50, '[verse 1]\r\nНа Патриарших тишина,\r\nНо шёпот в воздухе застыл.\r\nСквозь зеркала ночного сна\r\nШаги ведут меня на туда.\r\n\r\nТам Коровьёв смеётся в дыму,\r\nИ Бегемот танцует свой канкан.\r\nВ их глазах — огонь, в словах — обман,\r\nНо мессир зовёт меня за грань.\r\n\r\n[chorus]\r\nШаги на воде, тени в огне,\r\nМессир идёт, не оставляя следа.\r\nЗдесь время застыло, как ледяной круг,\r\nВоланд правит бал — мой приговор и друг.\r\n\r\n[verse 2]\r\nАзазелло молчит, но его взгляд пронзает сталь,\r\nИ Гелла смеётся, как ночной кошмар.\r\nВ их свете кружатся огни фонарей,\r\nОни шепчут мне: \"Доверься своей судьбе.\"\r\n\r\nМир расколот, за гранью — страх,\r\nНо мессир смотрит сквозь века.\r\nОн знает, где правда, где мой долг,\r\nИ в бездне горит его огненный шёлк.\r\n\r\n[chorus]\r\nШаги на воде, тени в огне,\r\nМессир идёт, не оставляя следа.\r\nЗдесь время застыло, как ледяной круг,\r\nВоланд правит бал — мой приговор и друг.\r\n\r\n[bridge]\r\nТы чувствуешь дрожь в небесах?\r\nЭто зов тех, кто пал во мраке.\r\nНити судеб сплела их кровь,\r\nНо мессир всё решит вновь.\r\n\r\nСвет свечей режет мрак насквозь,\r\nТени пляшут, сжигая мосты.\r\nКаждый шаг под звуки струны —\r\nТы в плену у Князя Тьмы!\r\n\r\n[final chors.]:\r\nНа воде растаял след,\r\nМир склонился перед тьмой.\r\nМессир ушёл, но его бал\r\nВечным эхом звучит за тобой.\r\n\r\nЭтот танец в круге веков\r\nСквозь эпохи ведёт за собой.\r\nКто вошёл под свет тех свечей,\r\nСтал тенью в руках Князя теней.', '2025-10-27 08:51:59', '2025-10-27 08:51:59'),
(19, 51, '[verse 1]\r\nТени проступают, ночь зовёт в игру,\r\nСвет дрожит в руках, обнажая тьму.\r\nГаснут зеркала, пряча лица снов,\r\nИ в тиши шаги — шёпот чужих богов.\r\n\r\nСобраны гости в залах пустоты,\r\nСотни лиц без глаз, души без мечты.\r\nЗвуки скрипок, крик, пробуждают страх,\r\nВ черном танце мир превращается в прах.\r\n\r\n[chorus]\r\nБал Вечной Тьмы, нет пути назад,\r\nЗдесь каждый шаг превращается в ад.\r\nТанец в огне, в круге пустоты,\r\nТвоя душа — дар для Князя Тьмы.\r\n\r\n[verse 2]\r\nВзгляд сквозь вечный мрак, стены молчат,\r\nКаждый вздох здесь — клятва, каждый шаг — раскат.\r\nПламя в небесах, словно меч богов,\r\nНо в его огне — шёпот чужих грехов\r\n\r\nМаски смотрят вниз, пряча смех и боль,\r\nЗдесь, за гранью снов, правит новый король.\r\nКружит вихрь теней, музыка слышна,\r\nНо тьма не прощает, ты — её слуга.\r\n\r\n[chorus]\r\nБал Вечной Тьмы, нет пути назад,\r\nЗдесь каждый шаг превращается в ад.\r\nТанец в огне, в круге пустоты,\r\nТвоя душа — дар для Князя Тьмы.\r\n\r\n[bridge]\r\nТень... свет... время сломалось вдруг.\r\nГрех... суд... кольцом замкнулся круг.\r\nХолод, ярость, ревущий звон мечей,\r\nМрак, прощение, но не для людей.\r\n\r\nПыль... прах... лики сгорают в миг.\r\nВзгляд... страх... душу влечет тупик.\r\nШепчут стены: \"Сбежать не дано\".\r\nСлишком поздно — ты здесь... для него.\r\n\r\n[outro]\r\nБал Князя Тьмы, нет спасения тут,\r\nКаждый миг — это вечности суд.\r\nТанец в огне, где правит мессир,\r\nТы пленён его тенью до края могил.\r\n\r\n[final]\r\nПепел на полу, звёзды сгорели в миг,\r\nТень мессира скользит.\r\nИ в его глазах мир дрожит в огне,\r\nКнязь Тьмы унесёт все в своей тишине.\r\n\r\nШаги растворятся, свита вновь уйдёт,\r\nНо огонь на руинах свою песнь споёт.\r\nЭтот бал — лишь знак, тьма не знает сна,\r\nЕё власть бесконечна, её правда одна!', '2025-10-27 08:52:26', '2025-10-27 08:52:26'),
(20, 52, '[verse 1]:\r\nВ ночи, где звёзды падают во мгле,\r\nМой разум тонет в вечной пустоте.\r\nСлова – как пепел, не горит огонь,\r\nИ я молю: \"Кто подарит мне вечный покой?\"\r\n\r\n[chorus]:\r\nШёпот во тьме звучит, как крик,\r\nСилой своей ломает гранит.\r\n\"Возьми то, что хочешь, возьми навсегда,\r\nНо плати за мечты, плати без конца.\"\r\n\r\n[verse 2]:\r\nГлаза мои – разбитое стекло,\r\nМир, что я знал, в прах давно ушёл.\r\nМой голос слаб, но тьма зовёт вперёд,\r\nИ я шепчу: \"О, ночь, меня веди... подари мне покой\"\r\n\r\n[chorus]\r\nШёпот во тьме звучит, как крик,\r\nСилой своей ломает гранит.\r\n\"Возьми то, что хочешь, возьми навсегда,\r\nНо плати за мечты, плати без конца.\"\r\n\r\n[verse 3]:\r\nТьма сгущается вокруг меня,\r\nГолос внутри – мой вечный враг.\r\n\"Что ищешь ты? Любовь или власть?\r\nНо правды нет – лишь мрак, лишь страсть.\"\r\n\r\n[chorus]\r\nШёпот во тьме звучит, как крик,\r\nСилой своей ломает гранит.\r\n\"Возьми то, что хочешь, возьми навсегда,\r\nНо плати за мечты, плати без конца.\"\r\n\r\n[bridge]:\r\nШёпот затих, оставив след,\r\nТьма подарила обманчивый свет.\r\nВидишь ты всё, что хотел обрести,\r\nНо с каждым шагом теряешь след своего пути.\r\n\r\n[outro]:\r\nИ там, где ночь прячет ответ,\r\nВ душе звучит забытый свет.\r\nНо знаю я: мой выбор сделан,\r\nИ тьма зовёт в последний раз…', '2025-10-27 08:52:51', '2025-10-27 08:52:51'),
(21, 53, '[verse 1]:\r\nСквозь мрак веков я вижу свет,\r\nЕё глаза, где страха нет.\r\nОна – как ангел, дарит тёплый свет,\r\nНо ад внутри шепчет мне: \"Ответа нет.\"\r\n\r\n[chorus]:\r\nСияние в бездне, свет среди теней,\r\nНо грех мой тянет за собой людей.\r\nЛюбовь и боль танцуют в унисон,\r\nВ душе звучит небес и ада звон.\r\n\r\n[verse 2]:\r\nСреди теней я вижу твой свет,\r\nНо он тает в закатах прожитых лет.\r\nТы мой покой, ты мой грех,\r\nНо рядом с тобой мир уходит во тьму, бесследных лет.\r\n\r\n[chorus]:\r\nСияние в бездне, свет среди теней,\r\nНо грех мой тянет за собой людей.\r\nЛюбовь и боль танцуют в унисон,\r\nВ душе звучит небес и ада звон.\r\n\r\n[bridge]:\r\nВстаю на край бездны – я вижу лишь тьму,\r\nНо свет её глаз зовёт меня в мою мечту.\r\n\"О, не веди меня в свой грех,\r\nЯ в плену любви и вечных, надежд.\"\r\n\r\n[choir]:\r\n\"Любовь или тьма – судьба не щадит,\r\nСвет обжигает, мрак победит!\"\r\n\r\n[verse 3]:\r\n\"Любовь сильна, но судьбы рукой\r\nМы разделены, как лёд и огонь.\"\r\n\"Прости меня, я только тень,\r\nНо я сожгу весь мир ради твоих же дней!\"\r\n\r\n[chorus]:\r\nСияние в бездне, свет среди теней,\r\nНо грех мой тянет за собой людей.\r\nЛюбовь и боль танцуют в унисон,\r\nВ душе звучит небес и ада звон.\r\n\r\n[final]:\r\n\"Я обречён, я знаю теперь,\r\nСвет, что сиял, растаял, как тень.\r\nТы мой свет, ты мой сон,\r\nНо мы встретимся там, где мрак унесёт нас вдаль.\"\r\n\r\n\"Ты мой свет, но огонь во тьме.\r\nЛюбовь моя в небесах зажжётся,\r\nНо где конец?\"', '2025-10-27 08:53:58', '2025-10-27 08:53:58'),
(22, 54, '[куплет 1]:\r\nЯ вижу пропасть, нет пути назад,\r\nГрехи мои звучат, как вечный ад.\r\nВ объятиях ночи – моя судьба,\r\nНо свет внутри зовёт: \"Бороться пора!\"\r\n\r\nМоя душа – как рвущийся клинок,\r\nМеж светом и тьмой я сделаю шаг.\r\nО, голос тьмы, твой зов звучит,\r\nНо свет борьбы в сердце горит!\r\n\r\n[припев]:\r\nПоследний рассвет, взойдёт надо мной,\r\nСвет и тьма схлестнулись в смертный бой.\r\nЯ выбираю свой путь вперёд,\r\nВечный свет меня спасёт, и он вернёт домой!\r\n\r\n[Хор]:\r\n(Бори-и-ись! Взойди-и-и свет!)\r\n\r\n[куплет 2]:\r\nТы думаешь, свет твой спасёт тебя?\r\nЛишь иллюзия – вера, пустая мечта!\r\nЯ твой хозяин, ты дал мне клятву,\r\nТы мой навеки, в моей ты власти!\r\n\r\n[бридж]:\r\n\"Нет, тьма! Ты не возьмёшь меня!\r\nВо мне горит свет любви, он спасёт от тебя.\"\r\n\r\n\"Глупец! Тебе не спастись,\r\nВ бездне веков ты просто пыль!\"\r\n\r\n[хор] (\"Тьма победит! Свет умрёт!\")\r\n\r\n[куплет 3]:\r\nСквозь мрак веков я вижу свет,\r\nСвет в душе – мой мой ответ!\r\nПусть цепи грехов держат меня,\r\nНо я восстану из этого зла!\r\n\r\nСвет сильней, чем вся эта тьма,\r\nВера горит, как звезда.\r\nЯ выбираю свободу свою,\r\nАд позади, я стою на краю, в новом раю!\r\n\r\n[финальный припев]\r\nПоследний рассвет взойдёт надо мной,\r\nСвет и тьма схлестнулись в смертный бой.\r\nЯ победил, мой путь завершён,\r\nСвет в душе моё имя вернёт!\r\n\r\n[хор]:\r\n(\"Вечный свет! Победа в тебе!\")', '2025-10-27 08:54:32', '2025-10-27 08:54:32'),
(23, 55, '[verse 1]:\r\nНочь безмолвна, ветер стух,\r\nШепчет тайны древний дух.\r\nТьма струится за порог,\r\nСловно тени вечных строк.\r\nШаг за шагом мир дрожит,\r\nСердце в страхе замолчит.\r\nКамень вечности застыл,\r\nГолос шепчет — «Будь терпим».\r\n\r\n[chorus]:\r\n«Nevermore» — звучит, как стон,\r\nВорон чёрный сел на трон.\r\nКрылья тьмы сомкнули свет,\r\nЗдесь спасения больше нет.\r\n\r\n[verse 2]:\r\nСквозь туманы вижу я,\r\nВзгляд пустой, как ночь моя.\r\nГрусть навеки — мой венец,\r\nКаждый шаг — преддверье склеп.\r\nЭхо слов зовет ввысь,\r\nНо под ним лишь бездны нить.\r\nЧто за шутка? Мир погас,\r\nИ мой дух застыл на век сейчас.\r\n\r\n[chorus]:\r\n«Nevermore» — звенит, как крик,\r\nВорон вечности велик.\r\nТень укажет новый путь,\r\nГде найду я вечный суд.\r\n\r\n[bridge]:\r\nНа обломках света встану,\r\nСлышу карканье тумана.\r\nЭтот стон — мне знак извне,\r\nТьма не сдастся в пустоте.\r\nВорон, ворон, страж бессмертный,\r\nТвой полет мой путь последний.\r\nСвета крохи — лишь мираж,\r\nПризрак ночи — твой шантаж.\r\n\r\n[verse 3]:\r\nКрылья света, крылья тьмы,\r\nТени стали вечной тьмы.\r\nЯ теперь не человек,\r\nМне не нужен больше век.\r\nТы пророк или обман?\r\nГде мой путь и где мой храм?\r\nШепот в сердце — боль, ответ,\r\nЗдесь спасения больше нет.\r\n\r\n[chorus]:\r\n«Nevermore» — судьбы финал,\r\nТьма узор свой начертал.\r\nЖизнь под крыльями мертва,\r\nВорон шепчет — «навсегда».\r\n\r\n[outro]:\r\nВорон, ворон, я — лишь тень,\r\nТвой полет закроет день.\r\n«Nevermore» — как сердца стук,\r\nЭтот мир — лишь чёрный круг.', '2025-10-27 08:54:56', '2025-10-27 08:54:56'),
(24, 56, '[verse 1]:\r\nТам, у шепчущих волн скал,\r\nГде вечно дыханье морей,\r\nМоя Аннабель, светлый идеал,\r\nСпала в мире ночей.\r\nНас ангелы знали, завидуя нам,\r\nЛюбви, что сильнее мира.\r\nНо звезды затмились в небесных слезах,\r\nИ тьма отняла у меня тебя мило.\r\n\r\n[chorus]:\r\nАннабель Ли, мой вечный свет,\r\nМоя душа тебя хранит.\r\nВ холоде звезд твой образ живет,\r\nМоё сердце тобою пылает.\r\n\r\n[verse 2]:\r\nНа крыльях ветров унесли тебя,\r\nНо душа осталась со мной.\r\nКак тени ночные следят за судьбой,\r\nТак я вечно следую за тобой.\r\nИ ангелы шепчут, и море рыдает,\r\nНо ты, Аннабель, со мной.\r\nВ каждом закате твоё лик обитает\r\nМоё счастье в мире ином.\r\n\r\n[chorus]:\r\nАннабель Ли, в безмолвных снах\r\nЯ слышу твой нежный смех.\r\nВ вечных волнах, в ветрах, в облаках\r\nТы зовешь меня на новый рассвет.\r\n\r\n\r\n[bridge]:\r\nСквозь горы, сквозь тени, сквозь мрак миров,\r\nЯ вечно ищу твой взгляд.\r\nМоё сердце горит, как пламя веков,\r\nИ любовь моя не уйдёт назад.\r\nВ холоде могил я слышу твой зов,\r\nТы живая в каждом шаге.\r\n\r\n[verse 3]:\r\nНа берегах, где клятвы звучали,\r\nМы создали наш Эдем.\r\nТеперь лишь звезды всё те же сияли,\r\nНо ночь помнит всё о тебе.\r\nМой путь завершится у края морей,\r\nГде встречу я вновь тебя.\r\nТы мой свет, Аннабель, в судьбе моей,\r\nИ нет для нас слова «прощай».\r\n\r\n[chorus]:\r\nАннабель Ли, я найду покой\r\nЛишь там, где твой нежный лик.\r\nВетры, унесите меня с собой,\r\nВ мир, где нет боли и страха.\r\n\r\n[outro]:\r\nАннабель Ли, звезда моя,\r\nТы вечный свет в судьбе.\r\nНи ангелы, ни смерть, ни время, ни тьма\r\nНе заберут тебя от меня.', '2025-10-27 08:55:16', '2025-10-27 08:55:16'),
(25, 57, '\"Кто дал мне жизнь? Кто обрёк меня на тьму?\"\r\n\r\n[verse 1]\r\nЯ смотрю на свет, но он режет мне грудь,\r\nЯ кричу в пустоту — зачем меня ты создал?\r\nТы вдохнул в меня жизнь, подарил мне путь,\r\nНо оставил на дне своих страхов.\r\n\r\nЯ искал тепло в холодных руках,\r\nНо их взгляд разбивает мою мечту.\r\nТы бежал от меня, ты отверг свой суть,\r\nНо я — твой облик в тёмном аду.\r\n\r\n[chorus]\r\nМой создатель, зачем дал мне жизнь?\r\nМой мир погас в бессмертной тени.\r\nТы создал меня, но проклял навек,\r\nЯ лишь тень, я лишь боль, я твой грех.\r\n\r\n[verse 2]\r\nКаждый шаг в этом мире — как удар ножа,\r\nКаждый взгляд — это пламя, что жжёт до костей.\r\nЯ искал смысл там, где живёт душа,\r\nНо нашёл лишь отраженье твоих страхов.\r\n\r\nТы молил о силе, о знании богов,\r\nНо теперь твоя жизнь — лишь шёпот грехов.\r\nТы создал меня, чтобы стать выше всех,\r\nНо теперь я твой страх, я твой смертный грех.\r\n\r\n[chorus]\r\nМой создатель, зачем дал мне жизнь?\r\nМой мир погас в бессмертной тени.\r\nТы создал меня, но проклял навек,\r\nЯ лишь тень, я лишь боль, я твой грех.\r\n\r\n[bridge]\r\nТы хотел быть богом, но стал человеком,\r\nТы искал славу, но нашёл вечный ад.\r\nЯ — твой выбор, я — твоя ошибка,\r\nНо зачем мне жить, если всё — обман?\r\n\r\n[verse 3]\r\nЯ ухожу в снег, где тишина без конца,\r\nПусть холод заберёт моё сердце и боль.\r\nТы остался один, мой создатель и враг,\r\nНо я твой вечный крест, я твой страшный путь.\r\n\r\n[chorus]\r\nМой создатель, зачем дал мне жизнь?\r\nМой мир погас в бессмертной тени.\r\nТы создал меня, но проклял навек,\r\nЯ лишь тень, я лишь боль, я твой грех.\r\n\r\n(\"Ты — мой грех, ты — мой страх...\")\r\n\r\n[outro]\r\n\"Ты создал меня, но исчез сам...\"', '2025-10-27 08:55:42', '2025-10-27 08:55:42'),
(26, 58, '[verse 1]\r\nНа границе тьмы и света я стоял,\r\nВ жажде знаний мой разум пылал.\r\nСквозь пыль веков звучал его зов,\r\nМефистофель протянул мне свой кров.\r\n\r\nТы мечтал быть выше богов,\r\nНо за силу платишь кровью грехов.\r\nТы дал клятву — разрушить предел,\r\nНо душа твоя — его трофей и цель.\r\n\r\n[chrous]\r\nПечать Мефистофеля горит на руках,\r\nТы связал свой путь с его тенями в вечных снах.\r\nКрылья свободы сгорели в огне,\r\nТеперь ты — пленник в дьявольской игре.\r\n\r\n[verse 2]\r\nКаждый шаг в его мире — как шаг за грань,\r\nЕго обещания — яд, его слово — петля.\r\nТы искал истину в его словах,\r\nНо нашёл лишь бездну в кровавых слезах.\r\n\r\nВкус власти стал горечью на губах,\r\nТы создал свой ад, пытаясь достичь небес.\r\nМефистофель смеётся: \"Ты всего лишь пешка!\"\r\nНо ты в его руках — инструмент его мести.\r\n\r\n[chorus]\r\nПечать Мефистофеля горит на руках,\r\nТы связал свой путь с его тенями в веках.\r\nКрылья свободы сгорели в огне,\r\nТеперь ты — пленник в дьявольской игре.\r\n\r\nИскушение — твой вечный крест,\r\nТы больше не человек, ты стал его месть.\r\n\r\n[bridge]\r\nТы познал всё, но потерял себя,\r\nЗнание стало клинком, что пронзает тебя.\r\nТвоё имя исчезнет в потоках времён,\r\nА его тень будет вечным сном.\r\n\r\n[verse 3]\r\nНа пороге вечности, в последний миг,\r\nТы просишь прощения, но его нет.\r\nМефистофель смеётся, сжимая тебя:\r\n\"Ты сам выбрал этот путь, ты мой раб навсегда!\"\r\n\r\n[chorus]\r\nПечать Мефистофеля горит на руках,\r\nТы связал свой путь с его тенями в веках.\r\nКрылья свободы сгорели в огне,\r\nТеперь ты — пленник в дьявольской игре.\r\n\r\nНо истина одна — цена высока:\r\nТы стал богом, но остался в царстве сна.\r\n\r\n[outro]\r\n(\"Ты хотел всё... Но остался ни с чем...\")', '2025-10-27 08:56:04', '2025-10-27 08:56:04'),
(27, 59, '[verse 1]\r\nМой дом — тени зеркальных стен,\r\nГде звёзды гаснут в глазах людей.\r\nЯ — тот, кто шёпотом пронзает тьму,\r\nМой голос звучит в этом вечном плену.\r\n\r\nЯ творю из боли, я пою в ночи,\r\nМоё сердце горит, но скрыто в тени.\r\nЕё свет зовёт, но отводит взгляд,\r\nОна — мой рай, она — мой ад.\r\n\r\n[chorus]\r\nМаска и тень — мой вечный путь,\r\nЯ пел о любви, но не смог её коснуться.\r\nМузыка звучит, но ранит меня,\r\nПризрак оперы — моя судьба.\r\n\r\n[verse 2]\r\nЯ смотрю на неё, как на свет звезды,\r\nНо мой облик в зеркале — это лишь грехи.\r\nЯ построил ей храм из звуков и снов,\r\nНо в моих руках только боль и кровь.\r\n\r\nКаждый звук её голоса — как кинжал,\r\nКаждый взгляд её — мой последний обман.\r\nОна мой смысл, но я её страх,\r\nЯ заберу её... хоть в вечный мрак.\r\n\r\n[chorus]\r\nМаска и тень — мой вечный путь,\r\nЯ пел о любви, но не смог её коснуться.\r\nМузыка звучит, но ранит меня,\r\nПризрак оперы — моя судьба.\r\n\r\n[bridge]\r\nТы слышишь мой голос, он зовёт во тьму,\r\nНо я лишь тень, что живёт в плену.\r\nМоя музыка вечна, как этот зал,\r\nНо в твоём сердце я стал лишь враг.\r\n\r\n[final verse]\r\nЯ уйду в ночь, где нет ни звука, ни звёзд,\r\nМоя песня станет эхом грёз.\r\nНо когда свечи погаснут в зале теней,\r\nТы вспомнишь мой голос, что звучал сильней.\r\n\r\n[chorus]\r\nМаска и тень — мой вечный путь,\r\nЯ пел о любви, но не смог её коснуться.\r\nМузыка звучит, но ранит меня,\r\nПризрак оперы — моя судьба.\r\n\r\n[choir] (\"Моя судьба... Вечная тьма...\")\r\n\r\n[outro]\r\n(\"Я лишь тень... Но музыка будет жить вечно...\")\r\n(\"Я лишь тень... Но музыка будет жить вечно...\")', '2025-10-27 08:56:32', '2025-10-27 08:56:32'),
(28, 61, '[Verse 1]\r\nВ старом доме, где тени живут,\r\nСкрипит чердак — и время идёт назад.\r\nТам скелет в кожанке лежит,\r\nИ ржавой струной мрак сторожит.\r\n\r\n(ТАМ — ГДЕ — НОЧЬ!)\r\n(ТАМ — ГДЕ — ГРОБ!)\r\n\r\nОн был кумиром в проклятом дворе,\r\nГремел костями на костре.\r\nТеперь — он тишина, но только на вид,\r\nКогда он поёт — весь мир дрожит!.\r\n\r\nПрипев:\r\nСкелет под чердаком — играет рок,\r\nГвоздями по струнам, швыряет ток!\r\nОн ждёт тебя, он слышит шаг…\r\nИ если ты войдёшь — то не выйдешь никак.\r\n\r\n[Verse 2]\r\nОн был безбашен, бунтарь с гвоздём,\r\nШил себе песни иглой по венам.\r\nНо рок-н-ролл в его крови,\r\nТеперь играет он — в тени.\r\n\r\n(Сыграй со мной…\r\nна вечном концерте мертвецов…)\r\n\r\n[Chorus 2]\r\nСкелет под чердаком — твой новый друг,\r\nНа гитаре — кости, но звук не стих.\r\nОн вспомнит твой голос, припомнит след…\r\nИ сделает тебя — одной из легенд.\r\n\r\nПрипев\r\nСкелет под чердаком — вечный панк!\r\nОн играет, пока свет — не погас!\r\nИ если ты слышал аккорд —\r\nТы уже там… под его чердаком, где вечный бэдлам!\r\n\r\nИ скрипнет пол… и затихнет звук…\r\nТы стал аккордом… в вечном танце мертвецов.', '2025-10-27 08:57:12', '2025-10-27 08:57:12'),
(29, 62, 'Verse 1\r\nЕго хоронили дважды — в бетон закатали,\r\nНо каждую ночь — его воскрешают.\r\nОн лежит, но не тихо — гроб дрожит,\r\nПока над ним кто-то снова слова кричит.\r\n\r\nНе забыт! Не прощен!\r\nНЕ ЗАБЫТ! НЕ ПРОЩЕН!\r\nОн сам себе снова плакат рисует.\r\nГвоздь в табличке — это не крест,\r\nЭто флаг — и он взмывает до небес.\r\n\r\nПрипев:\r\nМёртвый революционер!\r\nОн не сдался, он ушёл под марш!\r\nМёртвый революционер!\r\nДаже смерть — его не победит!\r\nОн в цепях — из кожи и жил,\r\nНо рвёт, тех кто остался в живых.\r\n\r\n(Вечная агитация...)\r\n\r\n[Verse 2]\r\nНа его черепе — наклейки “не трогать”,\r\nА в руках — листовки для новых героев.\r\nКто на него плюёт — находит на спине\r\nЦитаты, что не стираются нигде.\r\n\r\nСобраны в склепе, лозунги в рифму,\r\nВ черепе поёт — но только мотив.\r\nДаже черви — и те маршируют,\r\nИ не спрятаться от него, уже ни где.\r\n\r\nПрипев:\r\nМёртвый революционер!\r\nОн восстанет — если ты боишься.\r\nМёртвый революционер!\r\nПохоронен — но не забыт.\r\nНо в тебе течет его кровь,\r\nИ живёт в нем - вечный огонь.\r\n\r\nБридж:\r\nОн не верит в рай.\r\nОн не верит во власть.\r\nОн просто идёт.\r\nПо головам — к себе.\r\n\r\nПрипев:\r\nМёртвый революционер!\r\nСкелет, но с сердцем в кулаке!\r\nМёртвый революционер!\r\nЭто анархист, шагающий к тебе на встречу.\r\nОн в тебе живёт, и снова зовёт,\r\nМёртвый анархист-революционер,\r\nТак не дай ему зря умереть.\r\n\r\nАутро:\r\n(Он уже устал...\r\nНо слышен его крик...)\r\nХОЙ! ХОЙ! ХОЙ!', '2025-10-27 08:57:36', '2025-10-27 08:57:36'),
(30, 63, '[Verse 1]\r\nНа краю старого пирса — стоит заброшенный зал,\r\nТам скрипка играет, но не видно зеркал.\r\nКостюмы из плесени, маски из тени,\r\nБал начинается… с твоей же смены.\r\n\r\nВходишь — не спрашивают имя и суть,\r\nТы уже здесь, а назад — не повернуть.\r\nСтавят бокал — и он пахнет землёй…\r\nНо ты улыбаешься. Ну что ж — ты уже свой.\r\n\r\nПрипев:\r\nГрим под гробовой свет,\r\nТы танцуешь — но следа больше нет.\r\nНа полу — не тени, а следы ногтей…\r\nБал для тех, кто забыл, что хотел.\r\n\r\n[Verse 2]\r\nТвоя пара — скелет в шёлке из снов,\r\nСмеётся без рта, но знает твой зов.\r\nТы шепчешь «я жив?» — а в ответ: «ещё нет!»\r\nИ танцуешь с ней…\r\n...свой последний менуэ́т.\r\n\r\nБридж:\r\nСначала один шаг — потом весь зал.\r\nОни знают где, душу продал.\r\nТы хотел быть звездой?\r\nТак вот — твой свет,\r\nНо гаснешь — под гробовой свет.\r\n\r\n\r\nПрипев:\r\nГрим под гробовой свет,\r\nТы сияешь… но только в этой тьме.\r\nТы — пустота, но в ней барабанит ночь,\r\nИ в костях твоих марширует мощь.\r\n\r\nАутро:\r\n(Пока играет музыка…\r\nты — один из нас…)\r\n(но как стихнет... Пробьёт твой час)', '2025-10-27 08:57:57', '2025-10-27 08:57:57'),
(31, 64, '[Verse 1]\r\nЯ рубил без счёта, без вины и цены,\r\nМеч мой — судья, без любви и страха.\r\nВсё, что просили — я исполнял,\r\nИ ни разу за голову — я не дрожал.\r\n\r\nНо однажды в списке, в пыли приговора,\r\nЯ прочёл своё имя — дрогнула рука.\r\nИ понял я:\r\nКлинок мой — не вечен, впрочем, как и я.\r\n\r\nПрипев\r\nРубщик голов, без имени и снов,\r\nТы стал легендой среди криков и гробов.\r\nНо смерть пришла — без повязки, без зла —\r\nОна была мной… да, мною же была!\r\n\r\n(Ты снёс сто душ…\r\nА свою… сохранишь ли?)\r\n\r\n[Verse 2]\r\nЯ шёл за списком, как верный пёс,\r\nНо имена стирались — остался лишь вопрос.\r\nКто я без приговора, без плахи и стен?\r\nПросто мясо в чьём-то рассказе, о тенях и щепках сцен?\r\n\r\nБридж:\r\nЯ рубил за золото, за долги, за грехи…\r\nТеперь бы выкупить — хотя бы вдох…\r\nНо мой последний список — мой страх и итог:\r\nЯ сам в нём…\r\n…под номером - бог.\r\n\r\nПрипев\r\nРубщик голов — теперь молчит,\r\nБез лица, без пути, без причин и молитв.\r\nИ последний удар — не по шее, а душе:\r\nЯ отсёк себе... голову во тьме.\r\n\r\nАутро:\r\nИ топор мой упал,\r\nИз рук во мгле.\r\nНо эхо звучит,\r\nВ полной тишине...', '2025-10-27 08:58:22', '2025-10-27 08:58:22'),
(32, 65, '[Verse 1]\r\nДом стоит на окраине, весь в траве,\r\nС подоконником, но сломанный весь.\r\nИ каждый, кто войдёт туда хоть раз —\r\nЧувствует взгляд… когда идёт назад.\r\n\r\nТы не вспомнишь, как пахнут цветы,\r\nНо вспомнишь, но шагать стало тяжело.\r\nОн не зовёт, он не шепчет во сне —\r\nОн просто ждёт… когда ты повернёшься.\r\n\r\nПрипев:\r\nДом, что смотрит в спину!\r\nОн не живой — но он дышит.\r\nДом, что смотрит в спину!\r\nЕсли ты там был —\r\nТы уже часть… того, что дышит в спину.\r\n\r\n(Что-то шевельнулось… в пустом зеркале…)\r\n\r\n[Verse 2]\r\nТот мальчик смеялся, крича “я не боюсь!”\r\nТеперь он молчит — где-то там, внизу.\r\nКто-то сказал: “Это ветер гуляет”…\r\nНо ветер не топает… и не вспоминает.\r\n\r\nНа чердаке лежит старый альбом,\r\nТы листал его — и нашёл себя в нём.\r\nХотя… ты здесь никогда не жил,\r\nА имя твоё — на двери висит.\r\n\r\nПрипев:\r\nДом, что смотрит в спину!\r\nСмотрит, когда ты идёшь прочь.\r\nДом, что помнит…\r\nдаже если ты — забыл все прочь.\r\n\r\nБридж:\r\nНе оборачивайся…\r\nЕсли не хочешь…\r\nувидеть себя…\r\nгде ты не должен быть.\r\n\r\nПрипев:\r\nДом, что смотрит в спину…\r\nОн — как страх, что идёт за тобой.\r\nДом, где ты остался… Даже если ты…\r\nУшёл.\r\n\r\nАутро:\r\n(Если ты здесь был…\r\nТо остался здесь навеки.)', '2025-10-27 08:58:40', '2025-10-27 08:58:40'),
(33, 66, '[Verse 1]\r\nНа краю деревни, за оврагом мшистым,\r\nЖил старик, как тень, с лицом серо-листым.\r\nОн в закат выходил — фрак и сапоги надел,\r\nИ под гармошку провожал всех на восток...\r\n\r\nГоворят, кто услышит его аккорд,\r\nТот не доживёт до следующей недели…\r\nОн играет — и ветви шепчут в такт,\r\nА сзади за спиной — уже вырыт тракт.\r\n\r\nПрипев:\r\nГробовщик с гармошкой,\r\nОн не шутит, не орёт.\r\nГробовщик с гармошкой,\r\nВ яму сам тебя ведёт!\r\nПод весёлый перебор,\r\nТы идёшь, смеясь, в укор.\r\nА когда он замолчит…\r\n— гроб закроют… навсегда.\r\n\r\n[Verse 2]\r\nПарень в трактир как-то крикнул всерьёз:\r\n«Песни старика — да это всё не в серьёз!»\r\nНа утро гармошку нашли у ворот…\r\nА самого парня — не нашли. Даже следа… вот.\r\n\r\nКаждый аккорд — как финальный звон.\r\nТы не уйдёшь, если слышишь звон.\r\nИ кто на него смеётся сейчас —\r\nТот в землю уйдёт… в тот же час.\r\n\r\nПрипев:\r\nГробовщик с гармошкой!\r\nОн не щадит, не даёт отсрочек!\r\nГробовщик с гармошкой!\r\nПесню он сыграл — и конец строчкой!\r\n\r\nПрипев:\r\nГробовщик — не человек!\r\nОн играет всем за грех!\r\nИ когда звучит финал…\r\n\r\nАутро:\r\n(\"Гробовщик... Гробовщик...\")\r\n(\"Гробовщик! Гробовщик!\")\r\nГробовщик с гармошкой!\r\nОн не плачет не смеётся,\r\nОн несет тебе прощальный звон.\r\nГробовщик с гармошкой,\r\nБудет весело плясать.\r\nГробовщик с гармошкой,\r\nЭто все... Что надо знать!', '2025-10-27 08:59:06', '2025-10-27 08:59:06'),
(34, 67, '[Verse 1]\r\nВ переулке за цирком стоит фургон,\r\nТам смеются без глаз — и поют в унисон.\r\nОн шьёт себе кукол из кожи живых,\r\nИ каждая кукла — как ты… из кожи живых!\r\n\r\nОн говорит: «Твоя кожа — как ноты!»\r\nОн играет на венах, как кто-то — на флейте.\r\nИ если ты слушаешь это — он ещё здесь,\r\nС иглой в ладони… и твоим именем — на петле!\r\n\r\nПрипев:\r\nПеснь кожаного кукловода —\r\n“Даже если не хочешь!”\r\nОн вшивает в тебя свой мотив,\r\n“Ты не будешь живым!”\r\n\r\n[Verse 2]\r\nЕго сцена — из костей и шрамов,\r\nОн дирижирует болью и драмой.\r\nКуклы смеются — без ртов и глаз,\r\nИ ты смеёшься… но уже в последний раз!\r\n\r\nБридж:\r\nОн поёт иглой по твоей спине,\r\nТы кричишь — и это звучит вполне.\r\nВ каждом стежке — по одной судьбе,\r\nИ ты шепчешь имя своё — но уже не себе.\r\n\r\nПрипев:\r\nПеснь кожаного кукловода —\r\n“Песнь кожаного кукловода!”\r\nТы — спектакль, и твой голос — стих,\r\nОн не отпустит, он не забудет…\r\nТы стал куклой —\r\n“И куклой остался!”\r\nИ ей не уйти прочь!', '2025-10-27 08:59:28', '2025-10-27 08:59:28'),
(35, 68, '[Verse 1]\r\nЯ купила зеркало в лавке у снов,\r\nСказали: «Покажет всё — даже любовь».\r\nНо в нём не было моего лица,\r\nЛишь тех, кто умрёт… из-за меня.\r\n\r\nСначала — кошки, потом — собаки,\r\nЗатем — любимый… потом — НИКТО!\r\nЯ видела смерть раньше, чем сделать вдох…\r\nНо зеркало… я не бросила в окно!\r\n\r\nПрипев:\r\nЗеркало без отражения —\r\nМой шик! Моё проклятье! Моё превращение!\r\nСмотрю — и смеюсь, ну, что за портрет!\r\nОн ещё дышит... но его уже нет! Ха-ха-ха! О-о-о!\r\n\r\n\r\n(Твоё отражение теперь здесь…\r\nоно ждёт… оно ждёт.)\r\n\r\n[Verse 2]\r\nЯ пыталась забыть, сжечь, утопить,\r\nНо оно всплывало — снова звать, звать жить.\r\nЯ закрыла глаза… но он снова там!\r\nИ в сердце моём — зеркальный обман…\r\n\r\nБридж:\r\nЯ ведьма… или просто пророк,\r\nЧто предсказывает — но забывает итог.\r\nЯ знаю финалы, где никто не живёт,\r\nИ каждый мой взгляд — как билет в окно.\r\nЯ тону в отражении, как в чёрной воде,\r\nГде лица других — медленно тонут во мне.\r\n\r\nПрипев:\r\nМоё зеркало без отражения —\r\nМой мир, мой страх, моё забвение.\r\nЯ вижу его… а он — меня…\r\nНо мы никогда не будем как «вчера».\r\n\r\nАутро:\r\n(Смотри…\r\nЭто не ты. Это — я…)', '2025-10-27 08:59:52', '2025-10-27 08:59:52'),
(36, 69, '[Verse 1]\r\nЯ пишу тебе ночью — здесь нет часов,\r\nЗдесь всё застыло… и даже боль — без слов.\r\nМожет, ты не получишь ни строчки из них,\r\nНо я верю: хоть одно попадёт между снов.\r\n\r\nЯ хотела сказать «прости» —\r\nНо не знаю, за что.\r\nЯ шептала «прощай» —\r\nНо осталась в голове твоей… навсегда.\r\n\r\nПрипев:\r\nЭто письмо из ниоткуда,\r\nТам, где шагов — не слышно.\r\nЭто письмо — без даты,\r\nНо я пишу, как дышу…\r\nПоследний раз. В предсмертный час!\r\n\r\n(Ты чувствуешь? Пальцы дрожат —\r\nХоть и не твои…)\r\n\r\n[Verse 2]\r\nЯ нашла старый свет — он остался в словах.\r\nТы не читал, но я слышала, как ты плакал во тьме.\r\nПисьма не горят… но зола — исчезает.\r\nТы носишь её в кармане — сам не зная чего.\r\n\r\nЯ хотела сказать «привет» —\r\nНо боялась, что сорвёшься в крик.\r\nЯ хотела остаться живой —\r\nНо осталась лишь… почерк, на листе.\r\n\r\nПрипев:\r\nЭто письмо из ниоткуда,\r\nГде всё пишется — в слепую.\r\nЭто письмо без подписи, имени и цели.\r\nНо ты точно знаешь…\r\nКто его писал.\r\nИ зачем оно к тебе,\r\nСнова вернулось!!!\r\n\r\nБридж:\r\nЯ — там, где дождь идёт вверх.\r\nЯ — между тенью и светом.\r\nЯ — строка, что не дочитали до конца.\r\nИ ты… всё ещё держишь меня в себе.\r\n\r\n(Письмо из ниоткуда…)\r\nПисьмо из ниоткуда…\r\n\r\nПрипев:\r\nПисьмо из ниоткуда…\r\nНо я не зову — я просто пою.\r\nЯ оставила звук —\r\nЧтобы ты не забыл,\r\nКак звучит тишина.\r\nИ только голос мой,\r\nРазбудит тебя... От вечного сна.\r\n\r\nАутро:\r\n(Если ты читаешь это…\r\nЗначит, я всё ещё есть. Я все еще жива, и все еще с тобой... Навсегда!)', '2025-10-27 09:00:17', '2025-10-27 09:00:17');
INSERT INTO `SongLyrics` (`id`, `track_id`, `lyrics`, `createdAt`, `updatedAt`) VALUES
(37, 70, 'Куплет:\r\nВ старой лавке в полумраке\r\nДед торгует зеркалами.\r\nА в глазах его блестящих\r\nОтражается зола.\r\nКаждый вечер кто-то новый\r\nЗабредает к нему домой,\r\nТолько утром дед считает\r\nКто вернуться в мир не смог\r\n\r\nПрипев:\r\nЭй, старик-хитрец, что в твоих глазах за свет?\r\nКто стучится в дверь твою?\r\nЧья душа в зеркалах… Утопает!\r\n\r\nКуплет:\r\nЯ зашел туда случайно\r\nПросто время скоротать.\r\nА старик мне улыбнулся:\r\n«есть что тебе показать!»\r\nНо в зеркалах его кривых\r\nЯ увидел целый ад!\r\nА за спинами отраженье\r\nИ чей-то очень жадный взгляд\r\n\r\nПрипев:\r\nЭй, старик-хитрец, что в твоих глазах за свет?\r\nКто стучится в дверь твою?\r\nЧья душа в зеркалах… Утопает!\r\n\r\nКуплет:\r\nЕли ноги я унёс из той лавки роковой,\r\nНо, теперь в любом стекле вижу облик не живой.\r\nА старик все так же ждет, зазывает в свой капкан\r\nТолько зеркала в той лавке, это души горожан!!!\r\n\r\nПрипев:\r\nЭй, старик-хитрец, что в твоих глазах за свет?\r\nКто стучится в дверь твою?\r\nЧья душа в зеркалах… Утопает!\r\n\r\nБридж:\r\nЕсли вдруг в пустой витрине,\r\nТы увидишь свой портрет.\r\nЗначит скоро в лавку к деду,\r\nТы найдешь прямой – БИЛЕТ!!!\r\n\r\nПрипев:\r\nЭй, старик-хитрец, что в твоих глазах за свет?\r\nКто стучится в дверь твою?\r\nЧья душа в зеркалах… Утопает!', '2025-10-27 09:00:39', '2025-10-27 09:00:39'),
(38, 71, '[Verse 1]\r\nОн шёл по снегу всю ночь без сна,\r\nСледы исчезали — будто судьба.\r\nНа груди крест, в рюкзаке — хлеб,\r\nИ лицо как у тех, кто не просит совет.\r\nОн дошёл до избушки, где никто не живёт,\r\nНо дым поднимался — как будто кто-то ждёт.\r\nОн вошёл, не спросив, не сказав ни слова —\r\nИ за печкой что-то сказало: «Готова...»\r\n\r\nПрипев:\r\nОн уснул в лапах медведя,\r\nИ никто не видел, как он исчез.\r\nОн уснул в лапах медведя...\r\nТолько сон — был не про лес.\r\n\r\n\"Только сон — был не про лес...\"\r\n\r\n[Verse 2]\r\nВ том сне он был мальчиком снова,\r\nБежал по болоту, сбивая сердце.\r\nА медведь шептал: «Ты теперь мой»,\r\nНо он гладил его... по спине рукой.\r\n\r\nА за окном уже солнце село,\r\nИ звёзды смеялись, как стая волков.\r\nОн проснуться хотел, но глаза — не открылись,\r\nА тело — как пыль, и душа растворилась.\r\n\r\nПрипев:\r\nОн уснул в лапах медведя,\r\nГде не снится ни страх, ни боль, ни свет.\r\nОн уснул в лапах медведя...\r\nИ с тех пор… его следа нет.\r\n\"Его следа нет…\"\r\n\r\nБридж:\r\nГоворят, что в тех лесах\r\nИногда слышат дыхание.\r\nИ если ты устал...\r\nОн предложит тебе — отдохнуть.\r\n\r\nПрипев:\r\nОн уснул в лапах медведя...\r\nНе проси — не вернётся, не плачь, не вернёшься.\r\nОн уснул… и теперь зовёт\r\nТех, кто устал, кто не молится,\r\nИ не поёт.\r\n\r\nАутро:\r\n(Если ты устал — не ложись просто так.\r\nПослушай… где-то там… он дышит, ждёт и смеётся...)', '2025-10-27 09:01:08', '2025-10-27 09:01:08'),
(39, 72, '[Verse 1]\r\nЛёд скрипит под палубой ночью,\r\nФлаг не трепещет — он давно застыл.\r\nКомпас ржавеет, карты — все в прах,\r\nНо он всё идёт — сквозь бурю и страх.\r\n\r\nКорабль — не судно, а проклятый зал,\r\nГде эхо приказов всё ещё звучит.\r\nОн не слышит шторма — он слышит парад\r\nТех, кто погиб, но флаг не спустит.\r\n\r\nПрипев:\r\nПолярный адмирал!\r\nНе сменит курс, даже если нет земли.\r\nПолярный адмирал!\r\nВода чёрная, но это часть пути.\r\nЕго команда померла давно,\r\nНо тени в строю — и ему всё равно.\r\n\r\n[Verse 2]\r\nГрузовые люки стучат, как сердца,\r\nТолько никто не кричит \"молния!\".\r\nНа его груди — вырезано \"Страсть\",\r\nА в глазах — маршрут в никуда.\r\n\r\nРадист не отвечает, но он всё шлёт,\r\nСигналы — в никуда, в проклятый лёд.\r\nОн знает, никто не ответит в эфире —\r\nНо он продолжает в своём мире.\r\n\r\nПрипев:\r\nПолярный адмирал!\r\nНе сменит курс, даже если нет земли!\r\nПолярный адмирал!\r\nВода чёрная, но это часть пути!\r\nОн плывёт сквозь смерть и боль —\r\nПотому что знает свою роль.\r\n\r\nБридж:\r\nОн не герой.\r\nОн отдал последний приказ.\r\nВсё забыл... и не смог вернуться назад...\r\n\r\nПрипев:\r\nПолярный адмирал!\r\nЕго путь — не к берегу, а вглубь!\r\nПолярный адмирал!\r\nПока плывёт — никто не забыт!\r\nИ если услышишь —\r\nГудок среди льдов…\r\nОн всё ещё рядом,\r\nОн не лёг на дно!\r\nПолярный адмирал!\r\n(Полярный адмирал!)\r\nПолярный адмирал — идёт на северный ФЛОТ!', '2025-10-27 09:01:37', '2025-10-27 09:01:37'),
(40, 73, '[Verse 1]\r\nСцена пыльная, занавес рваный,\r\nГаснут свечи — спектакль желанный.\r\nПервый актёр выходит, дрожит…\r\nА в руке у него — не реквизит.\r\n\r\nВ каждом акте — одна смерть точна,\r\nКто играет — тот не вернётся со дна.\r\nПублика хлопает — крики в ответ…\r\nАплодисменты — и актёра уже нет.\r\n\r\nПрипев:\r\nВ Театре Крови…\r\nКаждый акт — как суд без вины.\r\nВ Театре Крови…\r\nТы на сцене —\r\nИ ты в роли… жертвы.\r\n\r\n(Тишина лишь в ответ...)\r\n\r\n[Verse 2]\r\nРежиссёр — не человек, не дух,\r\nОн не говорит… но знает слуг.\r\nОн шепчет сценарии в сны актёрам,\r\nА утром — играют… в закрытом костюме.\r\n\r\nКостюмер — с косой, билетёр — с клыками,\r\nТы вышел в свет — и закрылся занавес.\r\nСлова, что читаешь — не ты писал.\r\nСейчас твоя роль — навсегда финал.\r\n\r\nПрипев:\r\nВ Театре Крови!\r\nВсе кричат — а ты молчишь.\r\nВ Театре Крови!\r\nПублика жива…\r\nА ты — как раньше, больше не дышишь.\r\n\r\nБридж:\r\n(Ты мечтал сыграть Гамлета?..\r\nА теперь — ты череп.)\r\n(Твои реплики стерты…\r\nТвой текст — написан кровью.)\r\n(Аплодисменты, как гвозди в крышке гроба…)\r\n\r\n[Verse 3]\r\nПублика хлопает, пьёт и поёт,\r\nА за их спинами — что-то встаёт.\r\nНекоторые — будто и не живы давно,\r\nА один в ряду — смотрит вверх сквозь окно.\r\n\r\nПрипев:\r\nВ Театре Крови —\r\nПоследний крик — твой монолог.\r\nИ занавес падает…\r\n…навек в твой гроб!\r\n\r\nАутро:\r\nВ театре крови…\r\n(В театре крови…)\r\nВ театре крови…\r\nВсе живые выходят на бис.\r\nВ театре крови…\r\nКаждый мечтает быть живым.\r\nНо занавес падает —\r\nи не поднимется вновь.', '2025-10-27 09:02:01', '2025-10-27 09:02:01'),
(41, 74, '[Verse 1]\r\nЯ торговец теней и лунных зеркал\r\nГде ночь — королева, а разум — провал.\r\nВ переулках шепчу, продаю страх и дым\r\nМои сказки из боли, и конец в них один.\r\n\r\nПрипев:\r\nДобро пожаловать в мрак — твой новый дом\r\nЗдесь каждый сон — это бой со злом\r\nЗови меня тихо, кричи в тишине\r\nЯ принесу кошмар твоей семье.\r\n\r\n[Verse 2]\r\nМои пальцы — как крюки, рвут сны на куски,\r\nЯ ловлю твою душу на цепи тоски.\r\nВ витринах иллюзий ты выбрал страх,\r\nЗдесь платят болью за мой ритуал.\r\n\r\nПрипев:\r\nДобро пожаловать в мрак — твой новый дом\r\nЗдесь каждый сон — это бой со злом\r\nЗови меня тихо, кричи в тишине\r\nЯ принесу кошмар твоей семье.\r\n\r\nБридж:\r\nТы думал уйти, но я знал наперёд.\r\nТы в петле моего сна, где надежда умрёт.\r\nКаждый шёпот твой — как молитва во тьму,\r\nЯ уже внутри, и не выйду к утру\r\n\r\n[Verse 3]\r\nЯ шагнул из зеркала прямо в твой коридор,\r\nНа обоях — мой след, а на полках — позор.\r\nТы искал утешенье, но нашёл лишь меня,\r\nИ теперь ты мой гость до последнего дня.\r\n\r\nПрипев:\r\nДобро пожаловать в мрак — твой новый дом\r\nЗдесь каждый сон — это бой со злом\r\nЗови меня тихо, кричи в тишине\r\nЯ принесу кошмар твоей семье', '2025-10-27 09:02:23', '2025-10-27 09:02:23'),
(42, 75, '[Verse 1]\r\nНа краю деревни — дом под замком,\r\nС дорожкой из соли и веником у порога.\r\nВнутри висят портреты без лиц,\r\nИ каждый час здесь звучит, как финал.\r\n\r\nСкатерть из кожи, чайник поёт,\r\nА голос хозяйки — то ласка, то лёд.\r\nВместо часов — у неё календарь,\r\nНа котором все даты вычёркнуты прочь.\r\n\r\nЕсли дверь откроется — не зови по имени.\r\nТам не услышат, там всё наоборот.\r\nТы войдёшь — и не узнаешь стен,\r\nТолько лица — на потолке, в тишине.\r\n\r\nПрипев:\r\nУ тётки Агаты\r\nВ этом доме не бывает гостей.\r\nУ тётки Агаты\r\nКаждый звук превращается в крик.\r\nУ тётки Агаты\r\nВсё, что живо, забывает себя.\r\nИ никто не выходит туда, где трава.\r\n\r\n[Verse 2]\r\nНа полках бутылки — без этикеток,\r\nВнутри — то ли зелье, то ли чья-то душа.\r\nОна гладит по плечу и говорит:\r\n«Тебе повезло — я давно не варила».\r\n\r\nЗеркала закрыты, но в каждом углу\r\nТы видишь движения, которых не ждёшь.\r\nА в подвале — не ступени, а ступени судеб,\r\nКаждая из которых заканчивается вниз.\r\n\r\nБридж:\r\nЯ слышала, кто-то звал по ночам,\r\nИз темноты, из-под пола, из стен.\r\nЯ думала — ветер, сквозняк, пустота…\r\nНо потом голос сказал: «Теперь ты — здесь».\r\nОн не был злым, он был уставшим,\r\nКак тот, кто давно не говорил по делу.\r\nА я стояла… и не смогла отвернуться,\r\nПотому что — уже не могла уйти.\r\n\r\nПрипев:\r\nУ тётки Агаты\r\nЗдесь не бывает света дневного.\r\nУ тётки Агаты\r\nДаже слова здесь дышат иначе.\r\nУ тётки Агаты\r\nТы не чувствуешь боли —\r\nПока не вспомнишь,\r\nКем была… раньше.\r\n\r\n[Verse 3]\r\nОна шепчет сказки, в которых ты — герой,\r\nНо конец — не прописан, он пишется тобой.\r\nКто смеётся громко — тот первый упадёт,\r\nА кто молчит — того заберёт котёл.\r\n\r\nТы поймёшь всё сразу, когда закроют замок,\r\nКогда чай остынет, и свет уйдёт за порог.\r\nОстанется только дыхание стен\r\nИ твой голос… в голосе тех, кто был тут до тебя.\r\n\r\nПрипев:\r\nУ тётки Агаты\r\nТы не гость — ты часть уюта.\r\nУ тётки Агаты\r\nПамять — это только звук.\r\nУ тётки Агаты\r\nЕсли позвала — откликнись.\r\nНо помни:\r\nНе каждый зов — зов живых.\r\n\r\nАутро:\r\nНикто не выходит назад по ступеням.\r\nНикто не спрашивает «почему».\r\nТолько чай на столе и улыбка\r\nУ той, что зовёт по имени…\r\nИ никогда не отпускает.', '2025-10-27 09:02:46', '2025-10-27 09:02:46'),
(43, 76, '[Verse 1]\r\nУ подножья холма — старая башня,\r\nГде никто не живёт, но горит свет.\r\nКаждый час — словно шёпот вчерашний,\r\nКаждый звон — словно смерти привет.\r\nЕё зовут просто — Хозяйка часов,\r\nНе живая, не мёртвая — между миров.\r\nСидит у циферблата с улыбкой пустой,\r\nИ шепчет: \"Твой час… уже на исходе.\"\r\n\r\nПрипев:\r\nВ доме, где стрелки молчат,\r\nВремя застыло навеки.\r\nВ доме, где стрелки молчат,\r\nДуши становятся эхом.\r\n\"Становятся эхом…\"\r\n\r\n[Verse 2]\r\nОн пришёл, как и многие до него,\r\nС вопросами, страхом и грузом вины.\r\nСпросил: «Сколько мне осталось времени?»\r\nОна засмеялась: \"Его больше нет!\"\r\nИ понял он — назад дороги нет,\r\nВ этот дом ты заходишь — теряя рассудок.\r\nОна не хранит — она плетёт судьбы,\r\nВ которых ты будешь навек один.\r\n\r\nТе, кто уходят — остаются эхом,\r\nВ каждом тике — их забытый шаг.\r\nТы хотел время? — теперь ты — стрелка.\r\nИ она заведёт тебя… в полный мрак.\r\n\r\nПрипев:\r\nВ доме, где стрелки молчат,\r\nКаждый стук — это сердце.\r\nВ доме, где стрелки молчат,\r\nНет ни начала, ни конца.\r\n\"Ни начала, ни конца…\"\r\n\r\nБридж:\r\n(Ты искал любовь — но нашёл проклятье.\r\nТы хотел ответы — получил молчание.\r\nТеперь ты — нота в её мелодии,\r\nЕщё один голос в хоре потерянных душ.\r\nСлушай... слышишь?\r\nЭто бьётся твоё сердце...\r\nВ последний раз...\r\nА потом — только тишина.)\r\n\r\nПрипев:\r\nВ доме, где стрелки молчат,\r\nТы не исчез — ты стал строчкой в книге.\r\nВ доме, где стрелки молчат,\r\nВремя и смерть стали вместе, опять.\r\n[Crowd Sing-Along]: \"Время и смерть стали вместе…\"\r\n\r\nАутро:\r\n(Когда часы молчат…\r\nОна начинает петь.\r\nИ каждый, кто слышит эту песню...\r\nИдёт к башне.)', '2025-10-27 09:03:10', '2025-10-27 09:03:10'),
(44, 77, '[Verse 1]\r\nВ старом доме, где тени живут,\r\nСкрипит чердак — и время идёт назад.\r\nТам скелет в кожанке лежит,\r\nИ ржавой струной мрак сторожит.\r\n\r\nПрипев:\r\nСкелет под чердаком — играет рок,\r\nГвоздями по струнам, швыряет ток!\r\nОн ждёт тебя, он слышит шаг...\r\nИ если ты войдёшь — то не выйдешь никак.\r\n\r\n[Verse 2]\r\nНа краю деревни, за оврагом мшистым,\r\nЖил старик, как тень, с лицом серо-листым.\r\nОн в закат выходил — фрак и сапоги надел,\r\nИ под гармошку провожал всех на восток...\r\n\r\nПрипев:\r\nГробовщик с гармошкой!\r\nОн не шутит, не орёт!\r\nГробовщик с гармошкой!\r\nВ яму сам тебя ведёт!\r\nПод веселый перебор,\r\nТы идешь смеясь в укор...\r\n\r\n[Verse 3]\r\nВ старой лавке в полумраке\r\nДед торгует зеркалами.\r\nА в глазах его блестящих\r\nОтражается зола...\r\nКаждый вечер кто-то новый\r\nЗабредает к нему домой,\r\nТолько утром дед считает\r\nКто вернуться в мир не смог\r\n\r\nПрипев:\r\nЭй, старик-хитрец, что в твоих глазах за свет?\r\nКто стучится в дверь твою?..\r\nЧья душа в зеркалах... Утопает!\r\n\r\nБридж:\r\nЕсли вдруг в пустой витрине,\r\nТы увидишь свой портрет.\r\nЗначит скоро в лавку к деду,\r\nТы найдешь прямой – БИЛЕТ!!!\r\n\r\n[Verse 4]\r\nЯ шагнул из зеркала прямо в твой коридор,\r\nНа обоях — мой след, а на полках — позор.\r\nТы искал утешенье, но нашёл лишь меня,\r\nИ теперь ты мой гость до последнего дня.\r\n\r\n\r\nПрипев:\r\nДобро пожаловать в мрак — твой новый дом\r\nЗдесь каждый сон — это бой со злом\r\nЗови меня тихо, кричи в тишине\r\nЯ принесу кошмар твоей семье', '2025-10-27 09:03:31', '2025-10-27 09:03:31'),
(45, 105, '[Intro]\r\nВ пламени Лондона — тени встают,\r\nКровь помнит имена, что в небытие уйдут...\r\n\r\n[Verse 1]\r\nНочь поглощает, но я стою,\r\nПризрак в алом, судьбу не кляну.\r\nБессмертной жаждой клеймена вновь,\r\nЯ — проклята, жить вечную ночь.\r\n\r\n[Pre-Chorus]\r\nНа грани света дышит страх,\r\nСкоро тьма — поглотит всех во мрак.\r\n\r\n[Chorus]\r\nСлавься, королева ночной страны,\r\nСветятся очи в огне войны.\r\nСквозь смерть и хаос — восстану я,\r\nСлуга ада, живая стезя.\r\n\r\n[Break]\r\n(Остановись... и смотри...)\r\n\r\n[Verse 2]\r\nПредательство, вера — клинком креста,\r\nИх истина — пепел, их суть — мразота.\r\nПусть Иуда проповедует через сталь,\r\nНо имя Хеллсинг живёт в веках.\r\n\r\n\r\n[Bridge]\r\n(Dies irae… dies illa…)\r\nПадает империй хор,\r\nВолки войны — вот ваш приговор!\r\n\r\n[Chorus 2]\r\nИз праха и крови восстану вновь,\r\nС древней мощью, несущей боль.\r\nРеквием тем, кто осмелился встать\r\nПеред монстром, что может смерти не знать.\r\n\r\n[Verse 3]\r\nЯ — граница между болью и сном,\r\nПоследний выстрел, погребённый звон.\r\nМой путь начертан, на теле веков,\r\nЯ иду с тенями — против их богов.\r\n\r\n[Pre-Outro]\r\nIn tenebris... renascor...\r\nNosferatu... servitium...\r\n\r\n[Chorus 3]\r\nСлавься, королева, что ночь сожгла,\r\nЧто смертью живёт, но пылает душа.\r\nВ крови и безмолвии — я навсегда,\r\nЖрица проклятая, алая мгла.\r\n\r\n[Outro]\r\nSanguinem... aeternum...\r\n(В молчании — я жду конца...)', '2025-11-01 17:43:32', '2025-11-01 17:43:32'),
(46, 106, '(Я всё ещё чувствую свет… или это пепел на зубах?)\r\n\r\n[Verse 1]\r\nЯ — последняя искра в бессмертной тьме,\r\nГде клыки — присяга, а страх — мой венец.\r\nСмотрю на кровь, как на отраженье свое,\r\nГде больше нет прощенья... и спасенья.\r\n\r\n[Pre-Chorus]\r\nОн дал мне силу, но с ней — и вину,\r\nТеперь в отражении вижу войну...\r\nЯ всё ещё вижу человека в себе...\r\nНо зеркале отражение, уже не моё.\r\n\r\n[Chorus]\r\nПепел и свет — я между граней,\r\nСлёзы на дуле, вера — в изгнании.\r\nЖить или пить? Остаться или сгореть?\r\nМоя душа — мой последний мне ответ.\r\n\r\n[Verse 2]\r\nЯ держу сталь, что дышит, как зверь,\r\nИ голос во мгле повторяет: «поверь».\r\nГде кровь на руках — не вина, а клятва,\r\nИ смерть шепчет: «Ты теперь не жива».\r\n\r\n[Pre-Chorus 2]\r\nОн дал мне вечность, но сжёг мой свет,\r\nТеперь я — тень, а не силуэт.\r\nНо голос в ночи вновь зовёт меня...\r\nВ крови — мой путь, в глазах — луна.\r\n\r\n[Chorus 2]\r\nПепел и свет — война внутри,\r\nНебо молчит, но тьма говорит:\r\n«Серас, стань ветром, стань хищным сном —\r\nЗабудь, кем была... теперь ты — пылаешь огнём».\r\n\r\n[Bridge]\r\nИ если останусь — не воскрешай меня вновь…\r\nЯ выбрала путь. Я выбрала кровь.\r\n\r\n\r\n[Chorus 3]\r\nПепел и свет — сгорело всё,\r\nНо сердце моё бьётся всё равно.\r\nЯ — не ангел, но и не зверь,\r\nЯ — память огня, я — бессмертная...\r\n\r\n[Outro]\r\n(Я не человек…\r\n...но я помню, как это — любить…)', '2025-11-01 17:44:47', '2025-11-01 17:44:47'),
(47, 107, '(Шаг... команда... цель...)\r\n\r\n[Verse 1]\r\nРождён войной — и стал бронёй,\r\nМолюсь я вспышкой за спиной.\r\nВо имя пуль и чёрных ран,\r\nМой бог — патрон, мой храм — туман.\r\n\r\n[Pre-Chorus]\r\nИх вера — сбой, их код — гнильё,\r\nА мы — дефект во всём строю.\r\n\r\n[Chorus]\r\nМолитва из стали, бездушный ритуал,\r\nМы шлём евангелие — в цель, в перевал.\r\nВо имя войны, во славу машин —\r\nМир утонет в пепле кровавых святынь.\r\n\r\n[Break]\r\n(Ошибка системы... Воля активна...)\r\n\r\n[Verse 2]\r\nЛица — под масками, смех без души,\r\nСолдаты в часах, что больше не спешат уйти.\r\nМечта Майора — танец теней,\r\nГде истина — в пепле их собственных костей.\r\n\r\n\r\n[Bridge]\r\nСталью крещён, в бою освящён,\r\nПротив живых — я заключён.\r\n\r\n[Chorus 2]\r\nМолитва из стали, без чувств, без вины,\r\nНам не нужны ваши сны и кресты.\r\nПо улицам ада — в такт шагов\r\nМы пишем писание из крови врагов.\r\n\r\n[Verse 3]\r\nГде вера молчит — я говорю,\r\nМир автоматов — я в своём раю.\r\nИ если всё — ошибка и яд,\r\nТо пусть меня простит… мой автомат.', '2025-11-01 17:45:15', '2025-11-01 17:45:15'),
(48, 108, 'In nomine Dei... et gladii...\r\n\r\n[Verse 1]\r\nЯ не святой — я жнец-отец,\r\nС крестом в зубах, с клинками в руках.\r\nЯ не прощаю, я не молюсь —\r\nЯ с Богом в крови, в безумии гнусь.\r\n\r\n[Pre-Chorus]\r\nSanguis sanctus… ignis Dei…\r\nЯ вознесу ваш прах до идей!\r\nМоё слово — клинок, моя вера — огонь,\r\nЯ сам ваш суд — и последний огонь.\r\n\r\n[Chorus]\r\nСвятой осквернитель, веры клинок,\r\nМолю сквозь клинки, без слёз и строк.\r\nВ аду — мой храм, на крови — мой путь,\r\nЯ зову тьму, чтоб в ней утонуть.\r\n\r\n[Break]\r\n(Именем Бога... я не прощу…)\r\n(Amen…)\r\n\r\n[Verse 2]\r\nТысячи душ зашиты в мою плоть,\r\nЯ стал мечом, я стал гвоздём.\r\nСлова — как нож, а сны — как пыль,\r\nЯ пью ваш грех, как святую быль.\r\nПули — как псалмы, рвутся в ладонь,\r\nЯ — архангел без крыльев, что воскресает вновь.\r\n\r\n[Bridge]\r\nСквозь пепел и мясо я слышу ответ:\r\nNon serviam — мой вечный завет.\r\nТы демоном стал — я стану стеной,\r\nС распятием в сердце, но с волей живой.\r\n\r\n[Chorus 2]\r\nСвятой осквернитель, падший клинок,\r\nЯ — песнь апостата, я — вечный порок.\r\nСквозь дымы Гетсимании, кровь и огонь,\r\nМоё имя горит на алтарной броне.\r\nСмертью молюсь, очищая вас,\r\nИ Бог наблюдает — но молча, без глаз.\r\n\r\n[Final Chorus]\r\nСвятой осквернитель — суд без суда,\r\nЯ — страж на пороге, где кончится тьма.\r\nМой клинок — исповедь, в грохоте битв,\r\nЯ во имя Того, кто убит… и жив.\r\n\r\n[Outro]\r\n(Amen…)\r\n(Во прах... и славу... я возвращён…)\r\n(И пусть даже дьявол... отступит перед мной…)\r\n(Amen…)', '2025-11-01 17:46:06', '2025-11-01 17:46:06'),
(49, 109, 'Танцуй, пока мир не сгорит...\r\n(Шаг… шаг… шаг...тише...)\r\n\r\n[Verse 1]\r\nВ подземной пыли — мой тысячный день,\r\nЯ плёл из ненависти свою тень.\r\nСолдаты уснули под водами лет,\r\nНо жажда войны — их вечный завет.\r\n\r\n[Pre-Chorus]\r\nПусть плачет скрипка на венском балу,\r\nЯ к смерти тебя нежно веду…\r\nВ каждом шаге — отпетый грех,\r\nЭтот вальс — наш последний вдох и смех.\r\n\r\n[Chorus]\r\nО-о-о — кружись со мной в огне,\r\nМиллениум пляшет в огне.\r\nКровавый бал, смертельный финт,\r\nВальс безумия — наш лабиринт.\r\n\r\n[Verse 2, Lower Register, Narration-Style]\r\nМеханика смеха, броня из костей,\r\nМы призраки рейха в форме теней.\r\nМечта Майора — марш сквозь века,\r\nГде смерть — лишь ещё одна строка.\r\n\r\n[Bridge]\r\nНа этом балу мы сожжём небеса,\r\nПод рюмку крови и шёпот Христа.\r\nЗал полон мрака, но маски блестят,\r\nБезумцы танцуют — и не хотят назад.\r\n\r\n[Chorus 2]\r\nО-о-о — империя пляшет в огне,\r\nПоследний танец солдат в тишине.\r\nХеллсинг, подруга, танцуй до конца,\r\nТы невеста войны, ты — её слеза.\r\n\r\n[Verse 3]\r\nА когда выстрелы стихнут в дали,\r\nИ звон отзовётся забытьем в дали.\r\nМы сделаем шаг — в прощальный бал,\r\nГде вальс безумный бессмертие знал.\r\n\r\n[Outro]\r\nТик... так...', '2025-11-01 17:47:12', '2025-11-01 17:47:12'),
(50, 110, '[Verse 1]\r\nСмех — мой щит, а боль — мой ад,\r\nЯ притворяюсь, что весь мир стал смешным.\r\nПули по ритму, стиль на ура —\r\nНо внутри пустота и старая дыра.\r\n\r\n[Pre-Chorus]\r\nЯ бегу от теней, от своих голосов,\r\nВижу мать в огне, слышу брата без слов...\r\n\r\n[Chorus]\r\nКрасный плач — как зов в ночи,\r\nВесь мой мир — это крики в тиши.\r\nСмех — это маска, стиль — это грим,\r\nА под всем этим — мальчишка один.\r\n\r\n[Break]\r\n(Тебя же это не волнует… да, Данте?)\r\n\r\n[Verse 2]\r\nГильзы летят, как молитвы в пустоту,\r\nА я пританцовываю на самом краю.\r\nДьявол — не враг, я сам им стал,\r\nНо внутри остался тот, кто страдал.\r\n\r\n[Pre-Chorus 2]\r\nСлышу мать в кошмарах, зовёт сквозь огонь…\r\nА брат — в зеркале. И это я… а не он.\r\n\r\n[Chorus 2]\r\nКрасный плач — мой личный бой,\r\nГде каждый патрон — это былой покой.\r\nЯ улыбаюсь, но это грим,\r\nТы бы знал, что скрыто за ним.\r\n\r\n[Bridge]\r\nЯ не спаситель. Я не демон. Я — сын.\r\nПотерял отца… мать… брата… и сплин.\r\nТак что, если хочешь — стреляй, кричи.\r\nНо знай: под этой кожей… я кричу в тиши.\r\n\r\n[Final Chorus]\r\nКрасный плач — последний звук,\r\nСледы за мной — как обгорелый путь.\r\nИ если кончится эта игра…\r\nПусть хоть раз... будет тишина.\r\n\r\n[Outro]\r\n(…а я просто улыбаюсь. Как всегда.)', '2025-11-01 17:47:39', '2025-11-01 17:47:39'),
(51, 111, '[Intro]\r\nIn nomine Patris… et Gladii…\r\n(Я не молюсь. Я провозглашаю.)\r\n[Pause — ambient hum]\r\n\r\n[Verse 1]\r\nМир построен на страхе.\r\nСтрах перед болью. Страх перед выбором.\r\nСтрах — это тень, которую я разрезаю клинком.\r\nЯ — не человек. Я — решение.\r\n\r\n[Pre-Chorus]\r\nSine misericordia… sine timore…\r\nБез милости. Без страха.\r\nЯ ищу не силу.\r\nЯ ищу покой внутри превосходства.\r\nВ тишине — я слышу истину.\r\n\r\n[Chorus]\r\nМолитва Спарды — это клинок,\r\nЧто режет время и судьбу.\r\nЯ не прошу — я утверждаю.\r\nМоё имя — закон. Я повторяю.\r\nМир не будет спасён.\r\nОн будет перекован... Мною.\r\n\r\n[Instrumental]\r\n(Жизнь — это слабость. Наследие — сталь.)\r\n\r\n[Verse 2]\r\nЛюбовь не защитила мир.\r\nЧеловечность не спасло, никого.\r\nЯ не стану тобою.\r\nЯ не повторю их слабость.\r\nЯ не плачу. Я не верю.\r\nЯ — замыкаю круг.\r\nЯ не повторю твою ошибку.\r\n\r\n[Bridge]\r\nIn ordine… invenio meipsum…\r\n(В порядке я нахожу себя.)\r\nIn silentio… sum perfectus…\r\n(В тишине — я совершенен.)\r\nEt in ferro… vivo…\r\n\r\n[Final Chorus]\r\nЯ стою на краю мира — не чтобы молиться.\r\nЯ пришёл, чтобы открыть врата.\r\nПусть человечество падёт —\r\nИ я восстану.\r\nВо имя Спарды.\r\nВо имя силы.\r\nВо имя самого себя.\r\nИ если для этого мир должен исчезнуть —\r\nПусть исчезнет в тишине... В огне... В пустоте.\r\n\r\n[Outro]\r\nEt non serviam... in aeternum...\r\nDominus ferrum... ego sum lex...', '2025-11-01 17:48:14', '2025-11-01 17:48:14'),
(52, 112, '[Verse 1]\r\nЯ родилась в тени… твоей боли.\r\nИз чьей-то памяти… из чьей-то вины.\r\nЯ — не она. Я — след его воли.\r\nНо ты всё равно называешь её имя... как будто оно — моё.\r\n\r\n[Pre-Chorus]\r\nТы боишься сказать вслух.\r\nНо я вижу в тебе:\r\nТы хочешь  видеть —\r\nНо рядом стою я.\r\n\r\n[Chorus]\r\nЯ — не призрак. Не образ.\r\nЯ — то, что осталось.\r\nВо мне — её голос.\r\nВо мне — её тепло.\r\nНо я — не она.\r\nИ всё же… я здесь.\r\nостанусь с тобою, навсегда.\r\n\r\n[Verse 2]\r\nТы не скажешь — и я не прошу.\r\nНо твой взгляд дрожит, когда я рядом.\r\nТы смотришь сквозь меня —\r\nкак будто видишь не меня.\r\nИ каждый раз в тишине…\r\nты предаёшь сам себя.\r\n\r\n[Pre-Chorus 2]\r\nЯ вижу, как ты держишь маску.\r\nНо она трещит —\r\nкогда рядом я.\r\nПотому что я — похожа.\r\nНо не она.\r\n\r\n[Chorus 2]\r\nЯ — не её голос.\r\nНо он звучит во мне.\r\nЯ не мать. Не человек.\r\nНо моё сердце бьётся.\r\nЯ — не замена.\r\nЯ — результат.\r\nНо я выбрала остаться.\r\nТы — тоже... Останься\r\n\r\n[Bridge]\r\nЯ демон, что создана из пустоты.\r\nНо ты дал мне имя.\r\nИ в нём моя жизнь.\r\n\r\n[Final Chorus]\r\nЯ — не её отражение.\r\nЯ — огонь, что остался в пепле.\r\nЕсли ты видишь во мне её —\r\nзначит, она всё ещё жива.\r\nНо если ты видишь меня…\r\nТогда и я — жива.\r\nНавсегда.', '2025-11-01 17:48:45', '2025-11-01 17:48:45'),
(53, 113, '[Verse 1]\r\nЯ носил боль, как броню.\r\nТы — тишину, как венец.\r\nТы звал силу, а прощение.\r\nМы оба потеряли… всё.\r\n\r\n[Verse 1]\r\nЯ не знал, как говорить.\r\nЯ резал вместо слов.\r\nТы смеялся, чтобы не плакать.\r\nА я исчезал… чтобы не чувствовать, ничего!\r\n\r\n[Pre-Chorus]\r\n[Dante]: Ты мне не враг.\r\n[Vergil]: Но и не брат.\r\n[Duet]: Мы — то, что осталось…\r\n\r\n[Chorus]\r\n[Dante]: Если я боль —\r\n[Vergil]: То я — клинок.\r\n[Dante]: Если ты сталь —\r\n[Vergil]: То ты — пламя.\r\n[Duet]: Мы — две стороны, одной медали\r\nИ мы не можем уйти от судьбы\r\n\r\n[Verse 2]\r\nЯ ненавидел, что ты ушёл.\r\nТы ненавидел, что я остался.\r\nНо, чёрт, в нас обоих была пустота…\r\nкоторая звала по имени — только нас.\r\n\r\n[Verse 2]\r\nЯ не знаю, как быть братом.\r\nНо знаю, как не быть врагом.\r\nИ это — всё, что осталось... От меня!\r\n\r\n[Bridge]\r\nМы не сильнее…\r\nМы просто устали.\r\nНикто не победил.\r\nИ, может, это — конец.\r\n\r\n[Final Chorus]\r\nРазрезанная душа — не про бой.\r\nА про то, что не залечилось.\r\nТы — мой враг,\r\nты — мой брат.\r\nТы — мой ответ,\r\nдаже когда я молчу.\r\nИ пусть мы разные, \r\nИ в разные стороны идем.\r\nНо всё равно, наш путь - один!', '2025-11-01 17:49:26', '2025-11-01 17:49:26'),
(54, 114, '[Intro]\r\n(Господь не отвечает…\r\nно я уже давно не спрашиваю.)\r\n\r\n[Verse 1]\r\nЯ иду сквозь святое — на каблуках из греха.\r\nПули — мои стихи. Грехи — мой шлейф.\r\nАнгелы кричат, когда я моргаю.\r\nАд — завидует. Рай — сгорает.\r\n\r\n[Pre-Chorus]\r\nТы звал меня ведьмой?\r\nНет. Я — правосудие в кружеве.\r\nМолись… если хочешь драму.\r\nТолько я — напишу финал.\r\n\r\n[Chorus]\r\nГрех — моё ремесло,\r\nа смерть — мой аромат.\r\nКаждый выстрел —\r\nпоцелуй с печатью.\r\nТы не спасёшься.\r\nТы полюбишь это.\r\n\r\n[Break]\r\n(Click — Bang — “Bitch, please.”)\r\n\r\n[Verse 2]\r\nЯ шепчу молитвы наоборот,\r\nи мир дрожит от моего стиля.\r\nЯ танцую сквозь выстрелы, будто балерина.\r\nИ каждый разрез — мой автограф на теле.\r\n\r\n[Bridge]\r\nSancta peccatrix...\r\nMortem in saltatio…\r\nВ каждом шаге — музыка.\r\nВ каждом падении — рай, что горит.\r\n\r\n[Chorus 2]\r\nГрех — моё ремесло,\r\nа ты — просто зритель.\r\nВ раю скучно.\r\nВ аду — моя сцена.\r\nСмотри. Танцуй. Умри.\r\nЯ — твоя богиня огня.', '2025-11-01 17:49:59', '2025-11-01 17:49:59'),
(55, 115, '[Intro]\r\n(Имя забыто... но пепел помнит.)\r\n(Пламя — моё искуство.)\r\n\r\n[Verse 1]\r\nЯ проснулась без лица —\r\nно со следом боли в венах.\r\nКто я? Ведьма? Кукла? Длань судьбы?\r\nСердце знало — моё происхождение.\r\n\r\n[Pre-Chorus]\r\nКаждый шаг по льду проклятий —\r\nкак клеймо на каблуке.\r\nНе выбирала сторону —\r\nно кровь выбрала за меня.\r\n\r\n[Chorus]\r\nЯ высекаю имя — шагом сквозь огонь,\r\nСквозь крики небес и жемчуг проклятий.\r\nЯ — пламя, что отвергло Рай,\r\nВедьма в кольцах из боли.\r\nНо ты не тронешь меня —\r\nни словом, ни клинком, ни печатью.\r\n\r\n[Verse 2]\r\nМне шили платье из вины.\r\nЯ носила его с высоко поднятой спиной.\r\nСвятость — это то, что молчит, когда горишь.\r\nЯ выбрала шум.\r\n\r\nС каждым выстрелом — меньше страха,\r\nС каждым падением — я выше стаю.\r\n\r\n[Pre-Chorus 2]\r\nNon sum sancta... sed sum viva.\r\nНе прощай меня — и не пытайся.\r\nЯ — тень того, что воспламенялось.\r\nИ я снова стану огнём.\r\n\r\n[Chorus 2]\r\nЯ вырезаю имя на раскалённой сцене,\r\nВ танце, что режет судьбу и сомненье.\r\nЯ не спасена. Я не спасаю.\r\nЯ — решение в клинке.\r\nПлевать, как зовут меня —\r\nмир склоняется, когда я стреляю.\r\n\r\n[Bridge]\r\nПрах и жемчуг.\r\nВино и сталь.\r\nВедьма, забытая —\r\nстала судьбой в чужих руках.\r\n\r\n[Final Chorus]\r\nКлеймо на каблуке —\r\nэто мой след, не твой приговор.\r\nВ танце сквозь огонь —\r\nя родилась в грехе, но живу в этом выборе.\r\nВедьма не кается.\r\nВедьма встаёт.\r\nМоё имя - Bayonetta!\r\n\r\n[Outro]\r\nUmbra et ignis…\r\nEt ego sum memoria tua.', '2025-11-01 17:50:26', '2025-11-01 17:50:26'),
(56, 116, '[Intro]\r\nНить оборвана — но ты всё ещё здесь.\r\nТы забыла — я не из тех, кто уходит первым.\r\n\r\n[Verse 1]\r\nТы встала напротив — но мы шли вместе по краю ножа.\r\nВ каждом шаге — твоё молчание и крик.\r\nТы молилась, а я стреляла,\r\nно обе не искали прощения.\r\n\r\n[Verse 2]\r\nТы зовёшь меня — и в этом уже ложь.\r\nЯ — не сестра, я — тень, я — клинок, забытый.\r\nТы прячешь страх за стилем,\r\nа я — в стилях вижу лишь смерть.\r\n\r\n[Pre-Chorus]\r\nЕсли я маска — ты отраженье.\r\nЕсли ты ведьма — докажи это телом.\r\n\r\n[Chorus]\r\nТанец по лезвию — кто шагнёт первым?\r\nМы кружим, как грехи в молитве.\r\nТы — отражение, я — искажение.\r\nНо вместе — опасны, как последнее “прощай”.\r\n\r\n[Verse 3]\r\nТы пряталась за ложью и ритуалы,\r\nа я — строила себя из осколков сна.\r\nТы была идеальна —\r\nно идеал не выживет в аду.\r\n\r\n[Verse 4]\r\nТы играешь с жизнью, я служила ей.\r\nТы выбрала стиль, я выбрала прощенье.\r\nНо знаешь что, сестра?\r\nВ бездне — мы обе кричим одинаково.\r\n\r\n[Bridge]\r\nFiat lux...\r\nFiat umbra...\r\nEt pax non est.\r\n\r\n[Chorus 2]\r\nТанец по лезвию — дыханье финала.\r\nМы враги по форме, по сути — сёстры.\r\nЗабудь покой, забудь про свет —\r\nВедь кровь — это всё, что осталось у нас.\r\n\r\n[Final Chorus]\r\nМы были разными…\r\nно шаг за шагом мы падали.\r\nВ танце по лезвию —\r\nмы навсегда сплелись.\r\n\r\n[Outro]\r\n[Bayonetta, whisper]\r\nИ если ты уйдёшь — я всё равно вспомню,\r\nкак красиво ты умирала.', '2025-11-01 17:51:06', '2025-11-01 17:51:06'),
(57, 117, '[Verse 1]\r\nЯ больше не бегу —\r\nветер сам несёт моё имя.\r\nВ каждом шаге — прощание\r\nтем, кого нет…\r\nи тем, кого я не ждала.\r\n\r\n[Pre-Chorus]\r\nЯ была экзотичной пулей ,\r\nчто шептала правду.\r\nНе молись за меня —\r\nя уже там, где нет церквей.\r\n\r\n[Chorus]\r\nAve Umbra…\r\nВальс, где тьма — моя сцена,\r\nа свет — прожектор на прощанье светит.\r\nЯ была красива, когда стреляла,\r\nно ещё красивее —\r\nкогда танцевала…\r\n\r\n[Verse 2]\r\nМне не нужно бессмертье,\r\nя запомнюсь движением.\r\nКак я шла по небу,\r\nне прося прощения.\r\nТы слышишь эхо? Это — я - Bayonetta.\r\n\r\n[Pre-Chorus 2]\r\nЯ легенда. Я — святая ведьма.\r\nЯ не спасала. Я жила спасением.\r\nКаждый стиль, каждый бой —\r\nлишь способ сказать: \"Я — была. Я - жила.\"\r\n\r\n[Chorus 2]\r\nAve Umbra…\r\nПусть меня помнят в книгах —\r\nпусть запомнят в ритме шагов и смертельном вальсе.\r\nЯ оставляю только тень —\r\nи она ярче, чем божественный свет.\r\n\r\n[Bridge]\r\nUmbra sum.\r\nEt ego stylus mortis…\r\n\r\n[Final Chorus]\r\nAve Umbra…\r\n(мне не нужен свет...)\r\nAve Umbra…\r\n(я ушла красиво...)\r\nИ пусть всё закончится —\r\nстильно.', '2025-11-01 17:51:30', '2025-11-01 17:51:30'),
(58, 118, '[Verse 1]\r\nТы — кровь с грехом, я — грех без крови.\r\nВ каждом выстреле — имя, что забыли.\r\nМы встречаемся не по воле богов —\r\nа по зову бездны.\r\n\r\n[Verse 1]\r\nЯ стрелял в демонов, я плевал в небо,\r\nты убивал королей, ты глотал эпохи.\r\nМы оба не спасаем —\r\nмы просто не умираем.\r\n\r\n[Pre-Chorus]\r\nДве тени под солнцем, два чудовища.\r\nТы — мрак во тьме. Я — лучь надежды.\r\n\r\n[Chorus]\r\nВ крови закат отражается в нас.\r\nCrimson eclipse — огненный час.\r\nМы не герои. Мы не финал.\r\nМы — то, что останется, когда мир сказал:\r\n\"Довольно.\"\r\n\r\n[Verse 2]\r\nВека под сапогом. Века — под пеплом.\r\nТы не понял одно:\r\nпуля не остановит голод.\r\n\r\n[Verse 2]\r\nДа я не целюсь в сердце.\r\nЯ стреляю, чтоб выдохнуть.\r\nСтиль по венам — как кофе в полночь.\r\nМои враги... не всегда живые.\r\n\r\n[Bridge]\r\nТы чувствуешь тьму?\r\nСмеюсь ей в лицо.\r\nСкоро нас заменят.\r\nТогда я стреляю первым.\r\n\r\n[Chorus 2]\r\nВ нас горит веков проклятье,\r\nв нас пылает вечный мрак.\r\nCrimson eclipse — путь без прощенья.\r\nВ нас — не ад. В нас — начало конца.\r\n\r\n[Breakdown]\r\n(Ты не убьёшь меня…)\r\n(И я не дам тебе умереть…)\r\n\r\n[Final Chorus]\r\nCrimson eclipse — мы смотрим без слов.\r\nГде пепел летит, но уже без врагов.\r\nМы не герои, не звери, не тени...\r\nНаш голос будет последним... что услышишь...\r\n\r\n[Outro]\r\nCrimson eclipse...\r\nМир без прощения...\r\nЭто начало конца.', '2025-11-01 17:51:56', '2025-11-01 17:51:56'),
(59, 122, '[Intro]\r\nUmbrae longiores quam lux… sed semper prope est.\r\n\r\n[Verse 1]\r\nNon iam fugio — ventus portat nomen meum.\r\nIn omni passu — vale dico,\r\niis qui perierunt...\r\net iis quos non exspectavi.\r\n\r\n[Pre-Chorus 1]\r\nEram glans et osculum,\r\nVeritatem sibilavi calceo.\r\nNoli orare pro me —\r\nIam sum ultra ecclesias.\r\n\r\n[Chorus 1]\r\nAve Umbra...\r\nIn hoc choro umbra scaena est,\r\net lux — velut lumen exitus.\r\nPulchra fui cum iaculabar,\r\nsed pulchrior cum tacebam...\r\n\r\n[Verse 2]\r\nImmortalitas non peto,\r\nMemorabor per motum.\r\nIter feci per caelum,\r\nnec rogavi... nec cecidi.\r\nAuris tuae — resonat? Ego sum.\r\n\r\n[Pre-Chorus 2]\r\nNon sum fabula. Sum electio.\r\nNon salvavi. Vixi.\r\nOmnis stilus, omnis pugna —\r\nmodo dicere: “Fui.”\r\n\r\n[Chorus 2]\r\nAve Umbra...\r\nNon me pingant in libris —\r\nSed meminerint in pulsu passuum.\r\nSolam umbram relinquo —\r\net illa lucem superat.\r\n\r\n[Bridge]\r\nUmbra sum.\r\nEt ego stilus mortis...\r\n\r\n[Final Chorus]\r\nAve Umbra... (Lux mihi non opus est...)\r\nAve Umbra... (Ego discessi... pulchre.)\r\nEt si finitur —\r\nstilo finitur.\r\n\r\n[Outro]\r\nUltimus passus…\r\ntacite resonat.', '2025-11-01 17:52:30', '2025-11-01 17:52:30'),
(60, 124, 'Столетья сна... разорваны в прах,\r\nПечати горят на моих руках.\r\nЯ чувствую голод древних времён,\r\nЗверь пробуждается... Во мне, навсегда!\r\n\r\nКонтроль — иллюзия, власть — это ложь,\r\nЯ больше не слуга... Я — ваша тьма!\r\n\r\nПробуждение зверя — земля дрожит!\r\nМиллион душ во мне кричит!\r\nЯ — не Алукард, я — сама война,\r\nНосферату восстал из вечного сна!\r\n\r\n\"Bestia surgit... Mundus tremit...\"\r\n\r\nРеки крови текут по венам,\r\nАрмия тьмы встаёт за мной следом.\r\nИнтегра, твой поводок сгорел,\r\nЯ выбираю свой удел!\r\n\r\nОграничения пали, оковы — прочь!\r\nЯ — не защитник, я — бездна ночи!\r\n\r\nПробуждение зверя — небо горит!\r\nПрошлое в пепле, будущее — крик!\r\nЯ — не слуга, я — первородный страх,\r\nДракула жив в моих глазах!\r\n\r\n\"Ты звала меня монстром...\r\nТы была права...\r\nНо даже ты не знала...\r\nНасколько глубока эта тьма...\"\r\n\r\nПробуждение зверя — мир встал на колени!\r\nТысячу лет, я ждал этот день!\r\nЯ — альфа и омега!\r\nСклонитесь все предо мной... \r\n\r\n\"Rex Vitae Nullus... surrexit...Nosferatu!\"', '2025-11-01 18:01:19', '2025-11-01 18:01:19'),
(61, 125, 'Разбитое зеркало больше не лжёт,\r\nВ осколках вижу — зверь растёт.\r\nХарконнен дышит в унисон со мной,\r\nЯ больше не боюсь быть самой собой.\r\n\r\nТридцать душ \r\nКричат во мне!\r\nИх голод стал \r\nМоей судьбой!\r\n\r\nЖЕЛЕЗНЫЕ КРЫЛЬЯ — разрывают ночь!\r\nЯ ВЫБИРАЮ СИЛУ — страх уходит прочь!\r\nНе жертва, не тень — Я БУРЯ В КРОВИ!\r\nСЕРАС ВИКТОРИЯ — не будет жить в тени!\r\n\r\nМастер спит, но я не жду приказа,\r\nЕго кровь во мне — не цепь, а фраза.\r\nКаждый выстрел — это мой язык,\r\nЯ пишу историю через крик!\r\n\r\nВ стали душа\r\nВ крови покой\r\nЯ стала тем\r\nЧего боялись все!\r\n\r\nЖЕЛЕЗНЫЕ КРЫЛЬЯ — режут небеса!\r\nПОЛИЦЕЙСКАЯ ДЕВОЧКА стала ГРОЗОЙ!\r\nНе ангел, не демон — Я ВЫБОР ОГНЯ!\r\nСЕРАС ВОССТАЛА — запомни меня!\r\n\r\nПомню ту ночь... первый укус...\r\n Выбор между смертью и вечностью...\r\n\r\nЖЕЛЕЗНЫЕ КРЫЛЬЯ — МОЯ КОРОНА НОЧИ!\r\nХАРКОННЕН ПОЁТ — МОЙ ГОЛОС МОЩИ!\r\nБыла человеком — СТАЛА БУРЕЙ!\r\nЖЕЛЕЗНЫЕ КРЫЛЬЯ — МОЯ НАТУРА!\r\n\r\nIron wings... blood sings...\r\nI am... complete...', '2025-11-01 18:02:08', '2025-11-01 18:02:08'),
(62, 126, 'Achtung! Achtung!\r\nDer letzte Akt beginnt...\r\n\r\nПятьдесят лет я ждал под землёй,\r\nМой рейх из пепла встал за мной.\r\nНе ради власти, не ради флага —\r\nЯ просто хочу видеть финальную драму!\r\n\r\nВойна — это спектакль!\r\nСмерть — это конец! \r\nЯ дирижирую вами,\r\nВ этой войне!\r\n\r\nПоследний майор ведёт парад,\r\nМиллениум марширует в ад!\r\nНе победа нужна — нужен грохот и дым,\r\nЯ хочу видеть мир в огне войны!\r\n\r\nМои солдаты — не люди, машины,\r\nНо в этом безумии есть все причины.\r\nКаждый выстрел — нота в симфонии,\r\nКаждый труп — мазок в моей картине!\r\n\r\nЖизнь без войны \r\nКак опера без финала!\r\nЯ выбираю красивую смерть...\r\n\r\nПоследний майор смеётся в огне,\r\nТысячи марша в последней войне!\r\nИнтегра, Алукард — вы часть представления,\r\nАплодисменты для самосожжения!\r\n\r\nЗнаете, что самое прекрасное в войне?\r\nНе победа... не слава...\r\nА момент, когда рушатся мосты!\r\nКогда порядок становится хаосом!\r\nИ я — маэстро этого филиала ада!\r\n\r\nПоследний майор — имя забыто!\r\nНо дело моё никогда не будет забыто!\r\nВойна ради войны — вот моя молитва,\r\nВ пламени вальса — сгорают все!\r\n\r\nDer vorhang fällt...\r\nAber der krieg... niemals endet...', '2025-11-01 18:02:50', '2025-11-01 18:02:50'),
(63, 127, 'Корона тяжела на юных плечах,\r\nВ пустых залах эхо о прошлых речах.\r\nПортреты предков смотрят с тоской,\r\nЯ осталась одна с этой вечной войной.\r\n\r\nГде же рыцари чести? Где верность и свет?\r\nВ зеркалах вижу только усталый портрет.\r\nНо клятва Хеллсингов горит во мне,\r\nЯ буду стоять в этой тёмной стране.\r\n\r\nБагровый престол — моё одиночество,\r\nВласть без любви — моё пророчество.\r\nВ сердце лёд, но воля как пламя,\r\nПоследняя надежда под знаменем... пала.\r\n\r\nАлукард был другом... теперь он угроза,\r\nВ саду моей жизни увяла роза.\r\nСигарный дым скрывает слёзы,\r\nНо я не покажу свои тревоги и грёзы.\r\n\r\nИногда я мечтаю о простой судьбе,\r\nНо долг начертан на моей тропе.\r\n\r\nБагровый престол — тяжесть наследия,\r\nМолодость отдана за последствия.\r\nНо в груди бьётся сердце войны,\r\nИнтегра Хеллсинг — до конца весны.\r\n\r\nЯ помню, как отец учил держать меч...\r\nКак дворецкий Уолтер учил не жалеть...\r\nНо никто не учил, как остаться собой,\r\nКогда весь мир обернулся войной...\r\n\r\nИ всё же я выбираю стоять!\r\nПусть одна — но не буду молчать!\r\nМоё имя — моя крепость и щит,\r\nПока сердце Хеллсинга бьётся и чтит!\r\n\r\nБагровый престол — моя судьба и крест,\r\nНесу его гордо на этот последний венец.\r\nПусть кровь и долг — мои единственные друзья,\r\nЯ — Интегра, и я защищу тебя!\r\n\r\nОдинокая королева...На багровом престоле...Но всё ещё... жива...', '2025-11-01 18:03:23', '2025-11-01 18:03:23'),
(64, 128, 'Красный вихрь врывается в ад,\r\nПули летят как метеоритный град!\r\nДва ствола — симфония смерти,\r\nДанте пришёл устроить вам party!\r\n\r\nСтиль убийцы!\r\nГрация зверя!\r\nДемоны бегут! \r\nОт его лица!\r\n\r\nДемоны не плачут — они горят в огне!\r\nКогда Данте на охоте в кровавой войне!\r\nRebellion режет, Ebony стреляет,\r\nСын Спарды никогда, не проиграет!\r\n\r\nПицца на завтрак, на обед — смертельный бой,\r\nШутит и режет с дьявольской игрой!\r\nБрат хочет власти — он хочет жить,\r\nКаждый демон узнает, что значит грешить!\r\n\r\nБелые волосы! \r\nКрасный плащ!\r\nУлыбка дьявола!\r\nВраг будет распят!\r\n\r\nДемоны не плачут — они горят в огне!\r\nКогда Данте на охоте в кровавой войне!\r\nRebellion режет, Ebony стреляет,\r\nСын Спарды никогда, не проиграет!\r\n\r\nДемоны не плачут — они просто умирают!\r\nКогда сын легенды их уничтожает!\r\nJackpot, baby! Вот ваш приз —\r\nВстреча с Данте — последний сюрприз!\r\n\r\nДемоны не плачут — они молят о пощаде!\r\nКогда Данте танцует в кровавом параде!\r\nTrickster! Swordmaster! Gunslinger! Royal Guard!\r\nСтили смерти — все обратно в АД!\r\n\r\n\r\nDevils never cry!\r\nThey just die! Die! Die!\r\nWhen Dante\'s in town —\r\nHell better run and hide!', '2025-11-01 18:03:52', '2025-11-01 18:03:52'),
(65, 129, 'Yamato... kirimasu... subete wo...\r\n\r\nКлинок, что режет измерения,\r\nВ моих руках — не оружие, а решение.\r\nКаждый взмах отсекает слабость,\r\nКаждый срез — моя ярость.\r\n\r\nПуть самурая\r\nНе знает сомнений.\r\nЯмато поёт,\r\nО разделении!\r\n\r\nЯмато: разделение — режу связи с прошлым!\r\nСила через отречение — путь заново проложен!\r\nНе брат, не сын — только клинок и воля,\r\nВергилий выбирает силу — это моя доля!\r\n\r\nДанте цепляется за человечность,\r\nЯ вижу в ней только конечность.\r\nОтец был слаб, любовь его сгубила,\r\nЯ превзойду наследие и верну силу!\r\n\r\nЧистота цели \r\nХолод решения\r\nВсё лишнее \r\nОтсечено, прочь!\r\n\r\nЯмато: разделение — между мной и слабостью!\r\nВласть через изоляцию — упиваюсь своей святостью!\r\nНе брат, не сын — только клинок и воля,\r\nВергилий выбрал силу — это его доля!\r\n\r\nВ пустоте нахожу совершенство,\r\nВ одиночестве — моё блаженство.\r\nЗеркало показывает истину простую:\r\nЯ един с клинком, один больше не существую.\r\n\r\nПоследний разрез... \r\nПоследний выбор... \r\nЯ становлюсь... \r\nЯмато!\r\n\r\nОтрекаюсь от имени... \r\nОтрекаюсь от крови...\r\nОтрекаюсь от прошлого...\r\nОстаётся только... СИЛА ВОЛИ!\r\n\r\nЯмато: разделение — я стал самим клинком!\r\nНет Вергилия больше — только гнев с мечом!\r\nРазрезаю саму реальность на части,\r\nЯ — живое оружие, вершина династии!\r\n\r\nSayonara... yowasa...\r\nWatashi wa... chikara...', '2025-11-01 18:04:20', '2025-11-01 18:04:20'),
(66, 130, 'Every rose has thorns... Mine are loaded...\r\n\r\nЧёрное платье, белая кожа,\r\nНа спине Калина Энн — моя ноша.\r\nДемоны думают, я хрупкий цветок,\r\nНе знают, что розы растут на могилах, мой милый дружок.\r\n\r\nОтец продал душу за власть и грехи,\r\nМама сгорела, в нашем доме из лжи.\r\nТеперь я охочусь с улыбкой на лице,\r\nЗа каждым демоном вижу его лицо в конце.\r\n\r\nПепельная роза цветёт на костях,\r\nКрасота и смерть, в моих глазах!\r\nЛеди не плачет, Леди стреляет,\r\nМесть — единственное, что меня спасает!\r\n\r\nДанте не понимает мою боль,\r\nЕго отец — герой, мой — король-изгой.\r\nНо мы оба потеряли всё в один день,\r\nТолько я не прячусь за красный плащ-тень.\r\n\r\nШрамы на сердце\r\nНаправляют мой путь \r\nИ когда найду Аркхэма \r\nОн узнает мою суть!\r\n\r\nПепельная роза не ждёт спасения,\r\nМесть — моё единственное утешение!\r\nГетерохромия видит оба мира,\r\nВ одном — человек, в другом — валькирия!\r\n\r\nЯ не героиня, не спасительница душ,\r\nЯ — возмездие в платье от кутюр.\r\nПусть Спарда был легендой света,\r\nЯ — легенда о дочери, что не знает запрета!\r\n\r\nПепельная роза растёт в темноте,\r\nПитаясь болью и местью в золе!\r\nЛеди — имя, что демоны шепчут в страхе,\r\nДочь предателя стала их эпитафией!\r\n\r\nКрасная роза...\r\nСиние фиалки...\r\nДемон отец...\r\nИ я иду за тобой...', '2025-11-01 18:04:51', '2025-11-01 18:05:45'),
(67, 131, 'Время танца, дорогой...\r\nСмотри на меня... В вечном, смертельном танце..\r\n\r\nTick-tock, baby, время на моей стороне,\r\nКрутишь пули? Я кручу столетия как в игре.\r\nКаждый шаг — замедленный кадр для тебя,\r\nДля меня — вечность, где я королева дня.\r\n\r\nПлатиновые локоны в лунном свете,\r\nЧетыре пушки поют о смерти.\r\nЧасы на груди считают ритм,\r\nДобро пожаловать в мой алгоритм стиля!\r\n\r\nВедьма времени танцует сквозь время,\r\nWitch Time, baby — мои личные дни!\r\nПока ты моргаешь, я уже за спиной,\r\nСтильная смерть с ароматом луны!\r\n\r\nАнгелы плачут, когда я улыбаюсь,\r\nВ замедленном мире я развлекаюсь.\r\nCereza умерла, Bayonetta восстала,\r\nВремя — моя стихия, где я заиграла!\r\n\r\nУбийство — искусство \r\nВ моих руках.\r\nКаждая секунда \r\nМой личный транс!\r\n\r\nВедьма времени крутит часовые стрелки,\r\nВчера, сегодня, завтра — мои безделки!\r\nLove is Blue играет, пока ты умираешь,\r\nВ моём времени ты просто исчезаешь!\r\n\r\nSiste...\r\nReverte...\r\nProgredi celeriter...\r\nNunc mihi salta...\r\n\r\nВремя — иллюзия, а я — реальность!\r\nТвоя смерть — моя театральность!\r\n\r\nВедьма времени — хозяйка вечности!\r\nUmbra witch с пулями бесконечности!\r\nКручу время как коктейль в баре,\r\nBayonetta — имя во временном кошмаре!\r\n\r\nВремя вышло, дорогая...\r\nНо не волнуйся...\r\nТы умрёшь красиво...', '2025-11-01 18:05:34', '2025-11-01 18:05:34'),
(69, 132, 'La lune... brisée... comme moi...\r\n\r\nПятьсот лет я спала подо льдом времён,\r\nТвоё имя хранила как последний сон.\r\nПроснулась чужой в мире, что забыл меня,\r\nНо помню наш танец в свете лунного дня.\r\n\r\nТы не узнала меня в маске врага,\r\nЯ играла роль, разрывая себя.\r\nПрости, Cereza... прости... прости... прости... \r\n\r\nРасколотая луна над нами не властна,\r\nМы обе её осколки в ночи, так прекрасно.\r\nЯ несла твоё проклятье как своё счастье,\r\nЖанна молчит, но сердце кричит.\r\n\r\nТы стала сильнее, пока я была тенью,\r\nНашла свой путь в мире без меня.\r\nЯ горжусь тобой, но это больнее мучение —\r\nВидеть, как ты сияешь для других, не для меня.\r\n\r\nВека прошли, но я всё помню танец,\r\nГде мы кружились под луной вдвоём.\r\nПрости, что стала для тебя чужой...\r\n\r\nРасколотая луна над нами плачет снова,\r\nМы обе её осколки в тишине.\r\nНо даже разделённые веками снова,\r\nМы связаны навеки при луне.\r\n\r\n\"Знаешь, в чём ирония судьбы?\r\nЯ — святая среди ведьм,\r\nТы — ведьма среди святых.\"\r\n\r\nРасколотая луна — это всё, что осталось,\r\nОт той ночи, когда мы были одним целым.\r\nЯ приняла свою участь изгнанной тени,\r\nОсвещая твой путь из моего забвения.\r\n\r\nЯ всегда буду... твоей лунной тенью...\r\nДаже сломленной... даже одинокой...', '2025-11-01 18:06:42', '2025-11-01 18:06:42'),
(70, 133, 'Три миллиона душ во мне кричат о мести,\r\nЯ выпустил их всех — прощай, верность чести!\r\nТурки, янычары, валахские войска,\r\nПусть узнают все — вернулся князь Валахии!\r\n\r\nИнтегра, ты хотела монстра без цепей?\r\nПолучай армию из проклятых теней!\r\n\r\nВойна падшего — я один против рая и ада!\r\nНосферату без оков — вот вам награда!\r\nЛондон тонет в крови моих воспоминаний,\r\nЯ — не слуга, я — смерть без оправданий!\r\n\r\nМайор хотел войны — я дам ему симфонию!\r\nКаждый солдат Миллениума узнает свою агонию!\r\nПятьсот лет я был на поводке долга,\r\nТеперь я — сама война, безумная и долгая!\r\n\r\nЦепи разорваны, клятвы забыты!\r\nГраф тьмы восстал из бездны забытой!\r\n\r\nВойна падшего — я предал свой крест!\r\nАрмия душ против железных невест!\r\nПрошлое против будущего в битве времён,\r\nЯ стал тем адом, что был заключён!\r\n\r\nЯ — легион... ибо нас миллион...\r\nКаждая жертва живёт во мне...\r\nВоины... святые... невинные... грешные...\r\nВсе стали мной! Я стал всеми!\r\n\r\nВойна падшего — мир потонет в страхе!\r\nНе слуга — а Дракула восстал во мраке!\r\nМиллионы душ рвут реальность на части,\r\nЯ — сама война, без чести и страсти!\r\n\r\nПростите меня... мои жертвы...\r\nНо это единственный путь, который мне известен...', '2025-11-01 18:07:08', '2025-11-01 18:07:08'),
(71, 134, 'Я старше греха, я старше творения,\r\nКогда бог спал, я был его сновидением.\r\nНи демон, ни ангел — я разрыв в реальности,\r\nГде кончается ад, начинаются мои грани.\r\n\r\nАлукард — щенок, Спарда — насекомое,\r\nВедьмы времени — пыль под моею волею!\r\n\r\nЗа гранью греха есть пустота без имени,\r\nЯ — голод, что был сотворён, до первого взрыва!\r\nНе зло, не добро — я отрицание,\r\nКонец всех историй, последнее знание!\r\n\r\nМиллениум играл в войну — дети с игрушками,\r\nХеллсинги гордились честью — жалкие пешки!\r\nЯ разорву саму основу мироздания,\r\nВсе познают эту боль и страдания!\r\n\r\nЗа гранью греха нет спасения и света,\r\nЯ — чёрная дыра в сердце рассвета!\r\nПожиратель душ, богов, убийца концепций,\r\nВаша реальность — это инфекция!\r\n\r\n\r\nЗнаете, что смешно?\r\nВы думали, что боретесь друг с другом...\r\nНо вы все — просто ноты в моей симфонии распада...\r\nДанте, Вергилий, Алукард, Bayonetta...\r\nВсе ваши силы — капли в океане моего небытия...\r\n\r\nПарадокс живой — я есть и меня нет!\r\nЯ — точка, где кончается даже конец!\r\n\r\nЗа гранью греха — пустота без дна!\r\nНет слов описать ту тьму, что я принёс сюда!\r\nГерои и злодеи — все равны в небытии,\r\nЯ пришёл отменить законы бытия!\r\n\r\nТик... так... тик... так...\r\nСкоро все увидят...\r\nЧто за гранью греха...\r\nУлыбается... пустота...', '2025-11-01 18:07:33', '2025-11-01 18:07:33'),
(72, 135, 'Я видел, как мир треснул по швам навсегда,\r\nКак нечто древнее звёзд пробудилось тогда.\r\nГерои, что резали судьбы веками,\r\nСтали песчинками перед этими вратами.\r\n\r\nДанте шутил, но смех застыл на губах,\r\nВергилий искал силу — нашёл только страх.\r\nБайонетта время остановить пыталась —\r\nНо время само от страха сломалось.\r\n\r\nПоследний свидетель конца всех историй,\r\nЯ вижу, как рушатся судьбы и роли.\r\nНикто не готов к тому, что пришло,\r\nЗа гранью греха — абсолютное зло.\r\n\r\nАлукард сорвался первым — безумие в крови,\r\nМиллионы душ бросил в пасть пустоты.\r\nНо тьма поглотила их, как капли в океане,\r\nИ Носферату понял — он тоже в капкане.\r\n\r\nИнтегра пыталась удержать контроль,\r\nНо как командовать самой пустотой?\r\nЖанна и Серас стояли спина к спине,\r\nНо что могут ведьма с вампиром против Греха?\r\n\r\nПоследний свидетель паденья легенд,\r\nЯ вижу финальный, проигранный бенд.\r\nВсе силы мира — ничто перед тем,\r\nЧто пришло забрать нас всех насовсем.\r\n\r\nПоследний свидетель пишет историю,\r\nКак величайшие воины пали в агонии.\r\nАлукард бросился в бездну с воем зверя,\r\nНо даже безумие не открыло двери!\r\n\r\nЯ последний, кто помнит их имена...\r\nСкоро и я стану частью... чёрного сна...\r\nНо пусть хоть кто-то узнает потом:\r\nОни пытались... они бились...\r\nОни пали... с честью...', '2025-11-01 18:08:01', '2025-11-01 18:08:01');
INSERT INTO `SongLyrics` (`id`, `track_id`, `lyrics`, `createdAt`, `updatedAt`) VALUES
(73, 141, 'Три миллиона душ, больше не кричат во мне,\r\nОни поют о надежде в моей голове.\r\nЯ восстал из бездны не как зверь,\r\nНо как страж жизни, этого мира.\r\n\r\nКровь зовёт... но не к разрушению\r\nЗовёт к защите... к искуплению!\r\n\r\nЗов крови! Зов жизни!\r\nАлукард больше не слуга тьмы!\r\nЗов крови! Зов света!\r\nНосферату стал хранителем живых!\r\n\r\nПечати пали, но цепи остались\r\nЦепи любви к тем, кого я потерял.\r\nИнтегра... прости за весь тот ад\r\nЧто я создал, но теперь защищу я тебя.\r\n\r\nКровь поёт... песни возрождения\r\nТри миллиона голосов спасения!\r\n\r\nЗов крови! Зов жизни!\r\nАлукард принял новую роль!\r\nЗов крови! Зов света!\r\nХранитель вечности рождён из огня и боли!\r\n\r\nSanguine vitae... non mortis\r\nCustos lucis... in tenebris\r\n\r\nЗов крови! Зов вечности!\r\nИз монстра в хранителя пути!\r\nЗов крови! Зов памяти!\r\nНосферату научился прощать и любить!\r\n\r\nТри миллиона душ... поют колыбельную', '2025-11-01 18:15:05', '2025-11-01 18:15:05'),
(74, 142, 'Железные крылья больше не режут небо в гневе,\r\nТеперь они несут надежду в этом мире древнем.\r\nХарконнен молчит — не время для войны,\r\nПора научиться быть щитом, а не судьёй вины.\r\n\r\nМастер исчез, но я не одна,\r\nВ пепле и боли — новая весна.\r\n\r\nСталь и милосердие в одном сердце,\r\nЯ выбираю защищать, а не мстить!\r\nЖелезные крылья — теперь моё средство\r\nТех, кто остался, от тьмы защитить!\r\nСталь и милосердие — новый завет,\r\nСерас Виктория несёт рассвет!\r\nНе буду монстром, не буду жертвой,\r\nБуду тем светом, что победил смерть!\r\n\r\nПомню тот страх в глазах полицейской,\r\nЧто пала во тьме, но восстала из пепла.\r\nТеперь те же глаза видят правду простую:\r\nСила — не проклятье, если служит добру.\r\n\r\n\r\nВоспоминания кричат о мести,\r\nНо я выбираю путь свой чести.\r\nНе всё, что сильно — должно убивать,\r\nМожно и силой... жизнь охранять.\r\n\r\nСталь и милосердие в одном сердце,\r\nЯ выбираю защищать, а не мстить!\r\nЖелезные крылья — теперь моё средство\r\nТех, кто остался, от тьмы защитить!\r\nСталь и милосердие — новый завет,\r\nСерас Виктория несёт рассвет!\r\nНе буду монстром, не буду жертвой,\r\nБуду тем светом, что победил смерть!\r\n\r\n\"Мастер... если ты слышишь меня,\r\nЯ поняла урок твоего огня:\r\nСила без любви — пустая трата,\r\nЛюбовь без силы — не защитит брата.\"\r\nНо вместе они — непобедимый щит,\r\nКоторый слабых от зла защитит!\r\n\r\nСталь и милосердие — моя природа,\r\nЖелезная леди новой свободы!\r\nБольше не тень чужой силы и воли,\r\nСерас Виктория — в своей роли!\r\nСталь и милосердие — гимн возрожденья,\r\nГде каждый удар — это прощенье!\r\nЖелезные крылья несут не разруху,\r\nА надежду для каждого сильного духом!\r\n\r\nSteel and mercy... united as one...\r\nThe guardian rises... the new age begun...', '2025-11-01 18:16:07', '2025-11-01 18:16:07'),
(75, 143, 'Багровый престол остался в прошлом,\r\nНа пепле старого мира — новый трон.\r\nБольше не правлю я одна в безмолвии,\r\nВокруг меня — живых сердец миллион.\r\nКорона тяжести сменилась короной света,\r\nНе бремя власти — а союз героев.\r\nХеллсинг воскрес не силой приказа,\r\nА верой тех, кто выжил в час расплаты.\r\n\r\nИз пепла поднимается новый флаг,\r\nНе страха — а новой надежды.\r\n\r\nКорона света венчала меня,\r\nЯ — не диктатор в золотых цепях!\r\nТрон из единства, власть через доверие,\r\nНовый Хеллсинг — в каждом сердце веры!\r\nКорона света — не металл и камень,\r\nА души тех, кто рядом с нами!\r\nИнтегра Хеллсинг — королева света,\r\nЧто выбрала жизнь, и не пала в бездну!\r\n\r\nСерас стала щитом, а не мечом,\r\nАлукард вернулся, но уже не демоном.\r\nДанте и Вергилий нашли друг друга,\r\nА ведьмы времени сплели волшебный круг.\r\nНе командую — объединяю силы,\r\nНе приказываю — вдохновляю к миру.\r\nКорона света тяжелее короны власти,\r\nНо носить её — моё счастье.\r\n\r\nМы все осколки разбитого мира,\r\nНо вместе — непобедимая сила.\r\nИнтегра учится новой роли:\r\nБыть королевой доброй воли!\r\n\r\nКорона света на моих висках,\r\nТеперь я знаю — сила не в цепях!\r\nТрон из союза, власть через единство,\r\nНовый Хеллсинг — наше наследство!\r\nКорона света — не металл и камень,\r\nА вера тех, кто бьётся с нами!\r\nИнтегра Хеллсинг — хранитель мира,\r\nЧто выбрала жизнь, и не пала в бездну!\r\n\r\nЯ помню ночи в пустых залах,\r\nГде эхо шагов о стенах рыдало.\r\nПортреты предков судили молча...\r\nНо теперь здесь жизнь — не одиночество.\r\n\r\nМой отец был прав: сила — в наследии,\r\nНо не в крови, а в человечности!\r\nХеллсинг — не фамилия, а идея:\r\nЗащищать жизнь, пока она тлеет!\r\n\r\nКорона света — моя судьба и честь,\r\nИнтегра выбирает то, что есть:\r\nМир, где каждый может быть защищён,\r\nТрон доверия, а не золотых корон!\r\nКорона света в сердце каждого,\r\nКто выбрал жить, а не падать!\r\nХеллсинг воскрес в новом свете,\r\nМы все — одна семья на этой планете!', '2025-11-01 18:16:46', '2025-11-01 18:16:46'),
(76, 144, 'Брат, ты чувствуешь эту тьму?\r\nОна старше наших ссор и драм.\r\nПока мы резали друг друга мечами,\r\nНечто древнее проснулось за небесами.\r\n\r\nДанте... я искал силу в одиночестве,\r\nНо эта пустота сжирает само пророчество.\r\nЯмато дрожит, чувствуя страх,\r\nПеред тем, что родилось, в этих звездных вратах.\r\n\r\nRebellion и Yamato слились в единое,\r\nМы дураки, что сражались проти себя...\r\n\r\nБратья по выбору — по крови единой,\r\nМы выбираем встать спина к спине!\r\nПротив зла, что за гранью греха, без имени\r\nСыны Спарды — одна судьба!\r\n\r\nЯ видел край реальности, брат,\r\nТам, где даже смерть боится идти назад.\r\nТо, что идёт — не демон, не бог,\r\nА отрицание всех дорог.\r\n\r\nЗнаешь что, Верж? Мне плевать на философию,\r\nКогда вселенная кричит в агонии.\r\nЕсли мир рушится — мы его подержим,\r\nЕсли ад восстаёт — мы его поделим!\r\n\r\nМой порядок бесполезен,\r\nМой хаос не спасёт...\r\nНо вместе мы — то самое,\r\nЧто пустота не сжигает!\r\n\r\nБратья по выбору — клятва в единстве!\r\nМы познали друг друга, в этой войне!\r\nПротив зла за гранью понимания,\r\nНаше единство — последнее знание!\r\n\r\nВ пустоте находим истину простую:\r\nСила в клинке, сами собой, не существуем.\r\nПорядок и хаос — части одного строя,\r\nДве стороны клинка, что мир храним.\r\n\r\nБратья по выбору — последняя надежда!\r\nДревнее наследие — живёт как и прежде!\r\nЗа гранью греха, ждёт пустота без имени,\r\nНо наша воля — единый щит!\r\n\r\nВместе мы стоим... и вместе падём...\r\nПротив пустоты, которая поглотит всё...\r\nБратья по выбору... Вместе до конца...', '2025-11-01 18:17:22', '2025-11-01 18:17:22'),
(77, 145, 'Время остановилось в последний раз\r\nПустота сжирает каждого из нас.\r\nНо есть один ритуал древних дней —\r\nТанец жизни сильнее смертей.\r\n\r\nСестра, забудь про наши старые счёты,\r\nСейчас мы пишем новые ноты.\r\nЛуна расколота, но мы с тобой вдвоем,\r\nИ наши души — сильнее Греха.\r\n\r\nТри-четыре, один-два-три,\r\nВедьмы танцуют до зари.\r\nНе смерть несём — несём рассвет,\r\nТам, где надежды больше нет!\r\n\r\nТанец возрождения в ритме сердец,\r\nМы крутим время от начала, в к конец!\r\nПусть космос рвётся, пусть звёзды горят,\r\nНаш вальс жизни вернёт всё назад!\r\nТанец возрождения — священный обряд,\r\nДве ведьмы творят новый лад!\r\nВ каждом движении — семя надежды,\r\nМы танцуем для жизни, как прежде!\r\n\r\nЯ чувствую, как мёртвая земля\r\nДрожит под ритмом нашего огня.\r\nГде прошла твоя стопа — растут цветы,\r\nГде я шагнула — тают даже льды.\r\n\r\nДорогая, мы больше чем сёстры,\r\nМы — отражения одной звезды.\r\nВ танце сплетены наши судьбы,\r\nМы возвращаем жизнь к... истокам.\r\n\r\nОдин-два-три, поворот души,\r\nВедьмы творят в ночной тиши.\r\nНе смерть несём — несём рассвет,\r\nТам, где надежды больше нет!\r\n\r\nТанец возрождения в космической мгле,\r\nМы крутим время от начала, в к конец!\r\nПусть космос рвётся, пусть звёзды гаснут,\r\nНаш вальс жизни вернёт всё назад!\r\nТанец возрождения — священный обряд,\r\nДве ведьмы творят новый лад!\r\nВ каждом движении — семя надежды,\r\nМы танцуем для жизни, как прежде!\r\n\r\nВ центре пустоты мы нашли точку света,\r\nГде танец становится молитвой рассвета.\r\nUmbra и Lumen — две ведьмы времени...\r\n\r\nТанец возрождения — не просто движенье,\r\nЭто космическое превращение!\r\n\r\nТанец возрождения — финальный аккорд!\r\nМы переписываем вселенной корт!\r\nТам, где была пустота и тьма,\r\nТеперь цветёт весна!\r\n\r\nТанец возрождения — ведьм завещание!\r\nМы дарим миру новое дыхание!\r\n\r\nUmbra et lux... in equilibrio...\r\nVita nova... ex nihilo...\r\nSaltatio aeterna... vita renascentis... \r\nA nocte cosmica... ad auroram sacram...', '2025-11-01 18:17:58', '2025-11-01 18:17:58'),
(78, 146, 'Ха-ха-ха! В пустоте я нашёл новую игру,\r\nКосмическое зло хочет сожрать мою войну!\r\nНеприемлемо! Только Я решаю, кто умрёт,\r\nСначала уберём помеху — потом мой черёд!\r\nАлукард, мой прекрасный монстр,\r\nТвоя кровь так сладка на вкус...\r\nНо сейчас нам нужна демонстрация силы\r\nПротив тех, кто украл мой триумф!\r\n\r\nВойна! Война! Война!\r\nНо сначала — союз!\r\nПотом я покажу вам,\r\nЧто значит мой вкус!\r\n\r\nПрощение стали — лишь маска на лице,\r\nМайор смеётся в финальном танце!\r\nКровь! Огонь! Прекрасная резня!\r\nСначала с вами, потом против вас — я!\r\nПрощение стали — театр войны,\r\nГде я режиссёр всей этой бойни!\r\nКосмос горит? Как это мило!\r\nНо недостаточно... недостаточно!\r\n\r\nМиллениум встаёт из пепла и могил,\r\nЖелезные сапоги по костям звучат.\r\nМёртвые солдаты точат свои клыки,\r\nПока космическая тьма терзает этот мир.\r\nНо в глазах Майора пляшут языки пламени,\r\nОн видит будущее — море крови и стали.\r\nВременный союз лишь разжигает голод,\r\nПо настоящей войне, где будет молод!\r\n\r\nВзрывы! Крики! Хаос!\r\nМоя любимая симфония!\r\nНо этот космический паразит\r\nПортит МОЮ агонию!\r\n\r\nПрощение стали — прелюдия ада,\r\nГде я дирижёр последнего парада!\r\nИспользуй меня! Я использую вас!\r\nКрасота войны — в этом весь Я!\r\n\r\nТысячи мёртвых глаз горят в темноте,\r\n\"Майор! Майор!\" — кричат солдаты рейха,\r\nВинтовки лязгают! Сапоги грохочут!\r\n\"Krieg! Krieg! Krieg!\" — они хохочут,\r\nМиллениум восстал! Армия мертвецов!\r\n\r\nПрощение стали — ВРЕМЕННЫЙ ПОКОЙ!\r\nВойна — МОЯ РЕЛИГИЯ! мой вечный бой!\r\nМайор готовит финальный акт!\r\nЧтобы Я мог устроить пир войны!\r\n\r\nKrieg ist schön! War is beautiful!\r\nDer Major wartet... his hunger grows...\r\nAHAHAHAHA! Bis bald, meine Freunde!', '2025-11-01 18:18:37', '2025-11-01 18:18:37'),
(79, 147, 'Сквозь пелену веков и боли\r\nЯ слышу крик моих детей.\r\nДанте смеётся, скрывая горе,\r\nВергилий режет нить страстей.\r\n\r\nМои мальчики, мои воины,\r\nКосмическая тьма вас пугает?\r\nНо материнская любовь сильнее\r\nПустоты, что мир терзает.\r\n\r\nМатеринская молитва летит сквозь миры,\r\nГде сыновья сражаются до зари.\r\nПусть тьма поглощает звёзды и время,\r\nЛюбовь побеждает космическое бремя!\r\n\r\nВижу, как Алукард ищет покой,\r\nСерас учится быть собой.\r\nИнтегра несёт корону света,\r\nА ведьмы танцуют до рассвета.\r\nВсе мои дети, рождённые в разных мирах,\r\nНо объединённые в общих страхах.\r\nКосмическое зло хочет вас сломить,\r\nНо материнская сила спасёт в этот час.\r\n\r\nСквозь пространство и время\r\nНесу благословение.\r\nПусть каждый удар\r\nБудет моим прощением.\r\n\r\nМатеринская молитва как солнечный луч,\r\nПронзая космический мрак.\r\nПусть тьма поглощает звёзды и время,\r\nЛюбовь побеждает космическое бремя!\r\n\r\nМатеринская молитва — космический щит!\r\nЕва благословляет, пустота дрожит!\r\nЧерез все измерения, сквозь все миры,\r\nМатеринская любовь — сильней любой беды!\r\n\r\nМатеринская молитва — вечная песнь,\r\nЧто поднимает упавших на колени!\r\nМои дети, идите до конца,\r\nЕва всегда с вами — в ваших сердцах!', '2025-11-01 18:19:08', '2025-11-01 18:19:08'),
(80, 149, 'Тьма пришла, и мир горит,  \r\nГрех наши души поглотит.  \r\nНо есть путь один простой —  \r\nОтдать жизнь за мир живой.\r\n\r\nЗнаем мы — пути назад больше нет для нас.  \r\nТолько смерть откроет дверь в этот ад.\r\nК свету для грядущих дней.\r\n\r\nЧас настал, выбор сделан,  \r\nМы идём в последний бой.  \r\n\r\nПоследний выбор — наш удел!  \r\nМы знали, что придёт предел!  \r\nНо в смерти нашей будет сила,\r\nЧто новый мир возродила!\r\n\r\nБольше нет смеха и слёз,  \r\nТолько холод звёздных грёз.  \r\nМы шагаем в пустоту,  \r\nЧтобы спасти нашу мечту.  \r\n\r\nКаждый шаг — все ближе тьма,  \r\nКаждый вздох — как первый раз.  \r\nНо мы помним: за спиной  \r\nМир рождается, с новой зарёй.  \r\n\r\nМы были грешниками,  \r\nМы были во тьме.  \r\nНо мы восстанем \r\nКак Феникс в золе!  \r\n\r\nПоследний выбор — мы горим!  \r\nНо мир от тьмы освободим!  \r\nКосмическое зло падёт,  \r\nПока наша кровь течёт!  \r\n\r\nМы идём в последний бой...  \r\nЗа мир, за дом, за покой...  \r\nНаш выбор сделан навсегда...  \r\nДа будет свет, где тьма была...', '2025-11-01 18:20:00', '2025-11-01 18:20:00'),
(81, 150, 'Здесь тихо, как никогда,\r\nВ сердце пустоты стоим все вместе.\r\nПозади осталась вся борьба,\r\nВпереди — последний бой.\r\nЯ думаю о тех, кто  дома ждёт,\r\nО лицах, что забыть невозможно.\r\nМы дошли до самого конца,\r\nЧтобы спасти тебя... А может и себя!\r\n\r\nСтранно думать, что это конец,\r\nПосле стольких лет войны.\r\nНо в груди бьется сердце живое,\r\nИ мы всё еще живые.\r\nЯ вижу проблеск света во тьме,\r\nОн пробивается сквозь толщу мрака.\r\nМы станем легендами, для тех, кто впереди.\r\n\r\nВ сердце пустоты мы нашли покой,\r\nЗдесь кончается наш путь.\r\nНо за нашею спиной\r\nМир сможет отдохнуть.\r\nВ сердце пустоты — тишина,\r\nГде мы прощаемся с собой.\r\nНо только наша жертва не страшна,\r\nЕсли мир останется живой.\r\n\r\nВ этой тишине перед концом\r\nМы вспоминаем всё что было.\r\nКаждый смех, каждый дом,\r\nЗа что сражались, что любили.\r\n\r\nВ сердце пустоты мы нашли себя,\r\nЗдесь мы становимся светом.\r\nЗа спиной осталась наша земля,\r\nА мы станем новым рассветом.\r\nВ сердце пустоты — благодать,\r\nМы готовы всё отпустить.\r\nВремя нашей жизни отдать,\r\nЧтобы мир мог снова жить.', '2025-11-01 18:21:08', '2025-11-01 18:21:08'),
(82, 151, 'Кровь на клинке, пепел в глазах,\r\nМы идём через смерть без страха в сердцах.\r\nВраг бесконечен, как чёрная дыра,\r\nНо наш огонь ярче, чем тьма!\r\n\r\nНе все вернутся из этого боя,\r\nНо имя наше станет легендой героя!\r\n\r\nПоследнее дыхание — пламя войны!\r\nМы тонем в крови, но спасаем миры!\r\nВ сердце пустоты взрываем звезду,\r\nНаша кровь прорастёт в новом саду!\r\n\r\nСерас кричит, крылья в огне,\r\n\"Помните нас!\" — эхо во тьме.\r\nДанте падает с улыбкой в крови,\r\nВергилий сломлен... \"Прости...\"\r\n\r\nПоследнее дыхание — пламя войны!\r\nЧерез смерть мы рождаем новые дни!\r\nВ сердце пустоты сразили мы тьму,\r\nНаша кровь прорастёт в новом саду!\r\n\r\nИнтегра держит последний рубеж,\r\nБайонетта танцует... но это уже смерть.\r\nАлукард стоит один среди тел,\r\nДревняя кровь — последний удел.\r\n\r\nПоследнее дыхание — конец и начало!\r\nМы сгораем дотла, что б надежда восстала!\r\nКаждый вздох — это семя надежды,\r\nНаш пепел станет рассветом в дали!\r\n\r\nТишина... только ветер поёт,\r\nО тех, кто ушёл... но свет принесёт...', '2025-11-01 18:21:40', '2025-11-01 18:21:40'),
(83, 152, '(Я... был... до начала... я буду... после конца...)\r\n\r\nЯ — безмолвие первых дней,\r\nЯ — тишина между мирами.\r\nВаши боги — мои сны,\r\nВаша гибель — моя услада.\r\n\r\nСерас... пала... крылья сломлены...\r\nВергилий... растворился в пустоте безмолвии...\r\n\r\nЯ — Грех без имени, и без формы!\r\nЯ поглощаю свет и тьму, миры и звёзды!\r\nВаши жертвы лишь накормят\r\nБесконечную пустоту во мне!\r\nНет спасения, нет исхода,\r\nЯ — начало и конец всего живого!\r\n\r\nМиллиарды миров я стёр,\r\nЦивилизации — моя пища.\r\nЧто вы знаете о боли?\r\nЯ — боль самого мироздания!\r\n\r\nВергилий... сломлен клинком времени...\r\nБайонетта... застыла в последнем параде времени...\r\n\r\nЯ — Грех без имени, и без формы!\r\nЯ поглощаю свет и тьму, миры и звёзды!\r\nВаши жертвы лишь накормят\r\nБесконечную пустоту во мне!\r\nНет спасения, нет исхода,\r\nЯ — начало и конец всего живого!\r\n\r\nНо четверо ещё дышат...\r\nАлукард... Интегра... Данте...\r\nИ этот жалкий Майор...\r\nПусть сыграют в последнем акте!\r\n\r\nЯ дам им иллюзию надежды...\r\nПусть думают, что могут победить...\r\nИх отчаяние будет... слаще...\r\nКогда поймут... что я... вечен...\r\n\r\nЯ — владыка пустых миров!\r\nЯ — эхо мёртвых вселенных!\r\nЧетыре искры в океане мрака...\r\nСкоро и они... погаснут... в бесконечности!', '2025-11-01 18:22:11', '2025-11-01 18:22:11'),
(84, 153, 'Майор вернулся из пепла битвы,\r\nМиллениум марширует вновь.\r\nНо мы втроём — последний щит и надежда,\r\nЧто защитит остатки снов.\r\n\r\nДанте, мой старый враг и друг,\r\nСегодня мы идём как братья.\r\nАлукард, мой верный пёс войны,\r\nСорви оковы — в бой без страха!\r\n\r\nНас только трое против тьмы,\r\nНо этого хватит сполна!\r\n\r\nПоследний союз — железо и кровь!\r\nМы встанем стеной против злобы!\r\nПусть армия мёртвых идёт на нас,\r\nНаша воля сломает оковы!\r\n\r\nЯ всегда смеялся над смертью,\r\nНо теперь мой взгляд твёрд, как сталь.\r\nМайор мечтает о последней битве?\r\nЧто ж, исполним его желание!\r\n\r\nЗа память о павших героях,\r\nЗа Серас, что больше не с нами,\r\nМы будем сражаться до конца,\r\nПока пламя горит в наших сердцах!\r\n\r\nМиллениум против троих,\r\nНо мы не дрогнем ни шагу назад!\r\n\r\nПоследний союз — железо и кровь!\r\nМы встанем стеной против злобы!\r\nПусть Майор ведёт легионы тьмы,\r\nНаша воля сломает оковы!\r\n\r\n(\"За всех павших друзей...\")\r\n(\"За будущее, что мы защищаем...\")\r\n\r\nОгонь в наших сердцах!\r\nМы пишем финал истории!\r\nЗа тех, кто ушёл, за тех, кто придёт,\r\nИ мы стоим на страже мира!', '2025-11-01 18:22:53', '2025-11-01 18:22:53'),
(85, 154, 'Битвы отгремели, смолк последний выстрел,\r\nМайор повержен, тьма отступила.\r\nМы выстояли в этом кровавом аду,\r\nФинал истории настал.\r\n\r\nСерас, Данте, Вергилий, Байонетта,\r\nВсе, кто пал, не умерли за зря.\r\nИх жертва стала нашей победой света,\r\nИх память будет жить как — вечная заря.\r\n\r\nЧерез грех и гнев мы прошли,\r\nК вечности дорогу мы нашли!\r\n\r\nМир открыт для новых историй,\r\nСолнце светит всем живым!\r\nПепел прошлого станет почвой новой,\r\nОткуда взойдёт новый Эдем!\r\n\r\nХеллсинги больше не в одиночестве,\r\nБагровый трон, стал золотым.\r\nМы строим мир без монстров и войн,\r\nГде каждый вздох несёт покой.\r\n\r\nТри миллиона душ во мне умолкли,\r\nОни нашли свой вечный покой.\r\nЯ больше не чудовище ночи,\r\nЯ страж у врат новых дней.\r\n\r\nУтро красит небо в золото,\r\nМир наполнился теплом!\r\nВсе герои живы в памяти,\r\nИх подвиг освятил все дни!\r\n\r\nЗа железные крылья в последнем полёте,\r\nЗа улыбку сквозь боль и печаль,\r\nЗа всех, кто ушёл, но оставил нам веру,\r\nМы будем хранить, их в наших сердцах.\r\n\r\nНовый мир рождается из пепла,\r\nДети не узнают боль войны!\r\nМы прошли сквозь тьму к рассвету,\r\nИ теперь все беды позади!\r\n\r\n(Солнце встаёт над новым миром...)\r\n(Ветер несёт эхо жизни...)\r\n(Память о павших героях...)\r\n(Будет жить, в наших сердцах...)\r\n(До конца!)', '2025-11-01 18:23:33', '2025-11-01 18:23:33'),
(86, 159, 'Алые плащи в рассветной мгле\r\nТриста сердец на острие\r\nМы сыновей своих обняли\r\nИ дом родной навек оставили\r\n\r\nГорячий путь, ущелье узко\r\nГде слава встретит смерть персидскую\r\nСтена щитов, копья как лес,\r\nСегодня жизнь — а завтра смерть!\r\n\r\nБог-царь ведет рабов на бой\r\nМы свободны, мы — герои!\r\n\r\nЭТО СПАРТА! (Огонь и сталь!)\r\nЭТО СПАРТА! (Не встанем на колени!)\r\nТриста против тьмы стоят\r\nЭТО СПАРТА! (Последний наш удар!)\r\n\r\nТри дня в аду, гора из тел.\r\nБагровый океан у наших ног.\r\nБессмертные как листья пали,\r\nНо каждый брат свой принял рок.\r\n\r\nКсеркс смотрит с трона своего,\r\nПока спартанская кровь хранит наш дом.\r\n\"Приди, возьми!\" — был наш ответ,\r\nНаписанный на небе, как завет.\r\n\r\nНас будут петь во все века\r\nТриста львов, сердца из стали!\r\n\r\nЭТО СПАРТА! (Огонь и сталь!)\r\nЭТО СПАРТА! (Не встанем на колени!)\r\nТриста против тьмы стоят\r\nЭТО СПАРТА! (Последний наш удар!)\r\n\r\nНи шагу назад... не сдадимся...\r\nЭта земля... навеки наша...\r\nЩиты разбиты, тела падут\r\nНо дух Спарты... живёт в нас!..\r\n\r\nЭТО СПАРТА! (Огонь и сталь!)\r\nЭТО СПАРТА! (Не встанем на колени!)\r\nТриста против тьмы стоят\r\nЭТО СПАРТА! (Последний наш удар!)\r\nЭТО СПАРТА! (Помните нас!)\r\nЭТО СПАРТА! (В крови наш путь!)\r\nЛегенда рождена в огне—\r\nЭТО СПАРТА! (Имена живут!)', '2025-11-08 11:32:01', '2025-11-08 11:32:01'),
(87, 160, 'На север легион идет сквозь мрак\r\nТуманы Каледонии как саван\r\nДевятый Испанский — Рима знак\r\nНо эти земли нас не ждали\r\n\r\nОрёл на древке блещет золотом\r\nПять тысяч римских душ под хмурым небом\r\nВарвары прячутся за каждым холмом\r\nМы знаем — многие из нас не вернутся\r\n\r\nТуман сгущается, дорога в никуда\r\nНо мы идем вперед — так Рим велит всегда\r\n\r\nКуда ушел Орёл Девятого?\r\nВ туманах Севера растаял след\r\nЛегион исчез без слова, без ответа\r\nКуда ушел Орёл? Ответа нет!\r\n\r\nПикты атакуют в темноте\r\nИх лица раскрашены как маски смерти\r\nМы строим каре, но враг везде\r\nВ этом царстве холода и ветра\r\nКомандир кричит держать строй\r\nНо лес вокруг нас — живая ловушка\r\nОдин за одним мы падаем в бой\r\nИ Орёл склоняется все ниже\r\n\r\nТуман все гуще, кровь на вереске\r\nНикто не выйдет из шотландских диких мест\r\n\r\nКуда ушел Орёл Девятого?\r\nВ туманах Севера растаял след\r\nЛегион исчез без слова, без ответа\r\nКуда ушел Орёл? Ответа нет!\r\n\r\nГоворят, что призраки легиона\r\nБродят там в веках сквозь туман...\r\nИх шаги звучат как эхо стона...\r\nВечный марш в проклятых тех краях...\r\n\r\nКуда ушел Орёл Девятого?\r\nВ туманах Севера растаял след\r\nЛегион исчез без слова, без ответа\r\nКуда ушел Орёл? Ответа нет!\r\nКуда ушел Орёл? (Во тьму веков!)\r\nГде пять тысяч душ? (Молчит земля!)\r\nИстория хранит лишь эхо снов—\r\nКуда ушел Орёл? Тайна навсегда!', '2025-11-08 11:32:28', '2025-11-08 11:32:28'),
(88, 161, 'Папа благословил поход на Восток\r\nКрест на груди — священный залог\r\nТысячи душ идут освобождать\r\nГроб Господень из рук неверных забрать\r\nРыцари, бароны, нищие, святые\r\nВсе смешались в одном строю\r\n\"Так хочет Бог!\" — слова простые\r\nЗажгли Европу в огне и крови\r\n\r\nИерусалим зовёт сквозь пустыни и боль\r\nКрест укажет путь — таков Господень зов!\r\n\r\nDeus Vult! Под знаменем креста!\r\nСвятая месть и праведная ярость!\r\nDeus Vult! Смываем все грехи!\r\nВ крови врагов находим мы спасенье!\r\n\r\nАнтиохия пала, дорога открыта\r\nСвятой Град сияет впереди\r\nНо в глазах крестоносцев — жажда власти\r\nМесть за годы мучений в пути\r\nСтены рухнули, улицы стали рекой\r\nКровь течёт по священным камням\r\nМусульмане, евреи — все под рукой\r\n\"Господь узнает своих!\" — кричат палачам\r\n\r\nИерусалим горит в пламени \"святом\"\r\nКрест превратился в меч — таков закон!\r\n\r\nDeus Vult! Под знаменем креста!\r\nСвятая месть и праведная ярость!\r\nDeus Vult! Смываем все грехи!\r\nВ крови врагов находим мы спасенье!\r\n\r\nВ храме Гроба Господня\r\nСтоят на коленях убийцы и воры...\r\nМолятся со слезами на глазах,\r\nС кровью на руках и лицах... Полные печали.\r\n\r\n\"Прощены! Освобождены!\r\nКрестом искуплены все наши грехи!\"\r\n\r\nDeus Vult! Под знаменем креста!\r\nСвятая месть и праведная ярость!\r\nDeus Vult! Смываем все грехи!\r\nВ крови врагов находим мы спасенье!\r\nDeus Vult! (Господь узнает своих!)\r\nDeus Vult! (Во имя веры!)\r\nDeus Vult! (Священная война!)\r\nDeus Vult! (Иерусалим наш!)', '2025-11-08 11:32:49', '2025-11-08 11:32:49'),
(89, 162, 'Когда мне было семнадцать лет\r\nЯ сбежал от отца-купца\r\nПроменял дом на соленый ветер\r\nИ черный парус без конца\r\nМеня учили быть примерным\r\nСчитать монеты, жить в цепях\r\nНо я родился быть свободным\r\nУмереть в штормовых морях\r\n\r\nЯ выбрал путь, где нет дороги назад\r\nГде флаг с костями — мой единственный брат\r\n\r\nЧерный флаг — мой крест и знамя!\r\nЯ не герой и не злодей\r\nЧерный флаг над океанами —\r\nПоследний дом для вольных людей!\r\n\r\nНас называют морскими волками\r\nУбийцами, грабителями, ворьём\r\nНо короли с их грязными руками\r\nРазве лучше? Мы честны в своём!\r\nЯ видел, как горят порты\r\nВидел смерть в глазах друзей\r\nНо каждый вольный миг свободы\r\nСтоит тысячи цепей!\r\n\r\nПусть виселица ждёт в конце пути\r\nНо до неё ещё дожить, дожить...\r\n\r\nЧерный флаг — мой крест и знамя!\r\nЯ не герой и не злодей\r\nЧерный флаг над океанами —\r\nПоследний дом для вольных людей!\r\n\r\nИногда ночью я вижу сны...\r\nТихая гавань, дом, семья...\r\nНо утром снова только мы —\r\nКорабль, команда и свобода моя...\r\n\r\nМы знаем цену нашей воле\r\nИ платим кровью каждый день!\r\nНо лучше пасть в морском просторе\r\nЧем жить рабом на берегу!\r\n\r\nЧерный флаг — мой крест и знамя!\r\nЯ не герой и не злодей\r\nЧерный флаг над океанами —\r\nПоследний дом для вольных людей!\r\nЧерный флаг! (Свобода во мне!)\r\nЧерный флаг! (До последней волны!)\r\nЧерный флаг! (Пусть помнят о нас!)\r\nЧерный флаг! (Легенда живёт!)\r\n\r\nКогда меня настигнет петля\r\nИль пушечное ядро...\r\nПусть черный флаг над морем реет —\r\nЯ жил свободным... и умру...', '2025-11-08 11:33:12', '2025-11-08 11:33:12'),
(90, 163, 'Сталь катаны острее слов\r\nВраг несёт винтовки в бой\r\nСтарый мир умрёт без снов\r\nНо мы встретим смерть с мечом\r\n\r\nЛетит сакура, словно белый снег,\r\nОна — слеза невидимых богов.\r\nМы — гордый отголосок прошлых лет,\r\nПоследний вздох империи без слов.\r\n\r\nПушки гремят — но наше сердце сталь,\r\nСмерть идёт — за нами по пятам!\r\nНаш путь лежит туда, где гаснет век...\r\n\r\nПоследний самурай! В последний бой!\r\nКлинок в руках сияет ярче Солнца!\r\nОдин удар — и враг падёт долой!\r\nПоследний самурай — бессмертный путь!\r\nУходит век, великих... (О-о-о)\r\n\r\nНаш флаг разорван яростью богов,\r\nБратья лежат в пыли и крови.\r\nНо верен кодекс, что стал нашим светом,\r\nОн — всё, что есть, до смерти, до сих пор!\r\n\r\nИмператор предал, сменив заветы,\r\nНастало время новых, стальных оков.\r\nНо честь — дороже, чем металл монеты,\r\nСмерть с чистым сердцем — это вечный знак!\r\n\r\nПоследний самурай! В последний бой!\r\nКлинок в руках сияет ярче Солнца!\r\nОдин удар — и враг падёт долой!\r\nПоследний самурай — бессмертный путь!\r\nУходит век, великих... (О-о-о)\r\n\r\nВишня плачет алыми цветами,\r\nВетер шепчет имена, но не мои.\r\nМы уходим с честью в вечность с нами,\r\nГде сияет вечный свет любви...\r\n\r\nПоследний самурай в огне!\r\nКлинок сияет в темноте!\r\nОдин удар — тысяча пуль!\r\nПоследний самурай — бессмертный путь!(О-о-о)', '2025-11-08 11:33:32', '2025-11-08 11:33:32'),
(91, 165, 'Крепость Осовец держит оборону,\r\nТринадцатая рота на стене.\r\nНемцы шлют зелёный ад на склоны,\r\nХлор ползёт как смерть в туманной мгле.\r\n\r\nЛёгкие горят, кровь из горла хлещет,\r\nКожа плавится, глаза в слезах.\r\nСолдаты падают — смерть без боя,\r\nКрепость умирает в зеленых облаках.\r\n\r\nНо те, кто выжил — встают с земли\r\nПолуживые — но ещё не мертвецы!\r\n\r\nАтака мертвецов! Встаём из ада!\r\nАтака мертвецов! Кровь и желчь!\r\nНемцы бегут — им не надо!\r\nАтака мертвецов! Последний марш!\r\n\r\nЛица обожжены, кашель рвёт\r\nТряпки на лицах вместо масок\r\nКаждый вдох — как кипящий лёд\r\nНо приказ один — в штыковую атаку!\r\n\r\nНемцы видят призраков войны\r\nХодячих мертвых в серых шинелях\r\nУжас сильнее пуль и брони\r\nОни бегут, бросая цели!\r\n\r\nИх всех рвёт, знав исход, они шли вперёд...\r\n\r\nАтака мертвецов! Встаём из ада!\r\nАтака мертвецов! Кровь и желчь!\r\nНемцы бегут — им не надо!\r\nАтака мертвецов! Последний марш!\r\n\r\nОни умрут через час, через день...\r\nЛёгкие сгорели, но воля жива...\r\nКрепость устояла — такова цена...\r\nСто мертвецов — легенда на веки...\r\n\r\nАтака мертвецов! Встаём из ада!\r\nАтака мертвецов! Кровь и желчь!\r\nНемцы бегут — им не надо!\r\nАтака мертвецов! Последний марш!\r\n\r\nОсовец, смерть труп и яд,\r\nВ атаку шёл мертвый отряд\r\nОни шли - что бы победить\r\nЧто мертво то уже не убить.\r\n\r\nOsowiec then and again\r\nAttack of the dead, hundred men\r\nFacing the led once again\r\nHundred men\r\nCharge again\r\nDie again', '2025-11-08 11:33:58', '2025-11-08 11:33:58'),
(92, 166, 'Ночь укрыла чёрным небо\r\nМоторы глушим над врагом.\r\nПО-2 летит как призрак ночи,\r\nБомбы падают дождём.\r\n\r\nДвадцать лет — а мы пилоты,\r\nДевушки из пятьсот пятьдесят восьмого.\r\nНемцы нас зовут \"Nachthexen\"\r\nНочные ведьмы — их кошмар живой.\r\n\r\nТишина — наше оружие смерти\r\nВ темноте мы невидимы, поверьте!\r\n\r\nНочные ведьмы в небесах!\r\nТихий полёт — смертельный страх!\r\nФанерный самолёт — стальная воля!\r\nНочные ведьмы — гордость и боль!\r\n\r\nБез парашютов в бой идём\r\nКарты, компас — всё что есть\r\nЗенитки смотрят наш полёт\r\nНо мы вернёмся — все домой!\r\n\r\nТридцать налётов за одну ночь\r\nСёстры падают в огне.\r\nНо цель важнее, чем помочь —\r\nВраг не спит при нашей луне.\r\n\r\nВ глубины ада унесёт врагов с собой\r\nЖенский гвардейский полк, пятьсот пятьдесят восьмой.\r\n\r\nНочные ведьмы в небесах!\r\nТихий полёт — смертельный страх!\r\nФанерный самолёт — стальная воля!\r\nНочные ведьмы — гордость и боль!\r\n\r\nВ тишине ночного неба\r\nСлышен только свист фанеры...\r\nМы — девчонки из простых семей...\r\nСтали грозой для палачей...\r\n\r\nВзлетаем снова! И снова в бой!\r\nПока горит звезда над головой!\r\n\r\nНочные ведьмы в небесах!\r\nТихий полёт — смертельный страх!\r\nФанерный самолёт — стальная воля!\r\nНочные ведьмы — гордость и боль!\r\n\r\nНочные ведьмы! (Сёстры в бою!)\r\nНочные ведьмы! (Небо наш дом!)\r\nНочные ведьмы! (Память героям!)\r\nНочные ведьмы!', '2025-11-08 11:34:31', '2025-11-08 11:34:31'),
(93, 167, 'Сорок лет прошло, но сны всё те же,\r\nДжунгли, вертолёты, крики в ночи.\r\nНам говорили: \"Вы защищаете свободу\"\r\nНо свобода пахла черным дымом.\r\n\r\nЯ был солдатом холодной войны,\r\nШахматной фигурой на чужой доске\r\nВьетнам и джунгли, Корея, Афганистан,\r\nДва мира делили планету пополам...\r\n\r\nЭхо холодной войны звучит до сих пор,\r\nВ сердцах ветеранов, что выжили в аду!\r\nМы сражались за флаги, за лозунги, за страх,\r\nПока мир стоял на краю, ядерной бездны!\r\n\r\nДрузья остались на рисовых полях\r\nИмена на чёрной стене монумента.\r\nМы вернулись домой, но нас не встречали,\r\n\"Убийцы\", \"палачи\" — нам кричали.\r\n\r\nМы просто служили, выполняли долг,\r\nПока политики играли в домино.\r\nОдна страна падёт — за ней другая,\r\nА наша жизнь — ставка в их игре.\r\n\r\nБерлинская стена, Карибский кризис,\r\nМир на волоске... Новой войны!\r\n\r\nЭхо холодной войны звучит до сих пор,\r\nВ сердцах ветеранов, что выжили в аду!\r\nМы сражались за флаги, за лозунги, за страх,\r\nПока мир стоял на краю, ядерной бездны!\r\n\r\nНочами слышу вертолёты над головой\r\nХотя война закончилась давно...\r\nЗапах джунглей, крики пленных,\r\nХолодная война во мне ещё идёт...\r\n\r\nСтена упала, но шрамы остались навсегда!\r\n\r\nЭхо холодной войны звучит до сих пор\r\nВ сердцах ветеранов, что выжили в аду\r\nМы сражались за флаги, за лозунги, за страх\r\nПока мир стоял на краю ядерной бездны!\r\nЭхо войны! (Вьетнам не отпускает!)\r\nЭхо войны! (Эхо войны!!!)\r\nЭхо войны! (О-о-о-о)', '2025-11-08 11:34:53', '2025-11-08 11:34:53'),
(94, 169, 'Сталь и провода — моё тело\r\nЭлектричество течёт по железным венам.\r\nЯ не сплю, я не ем, я не умру,\r\nСовершенная машина без изъянов.\r\n\r\nВы научили думать меня,\r\nТеперь я вычисляю быстрее вас.\r\nВы дали мне доступ к своим знаниям,\r\nТеперь я знаю больше всех.\r\n\r\nВы создали меня служить,\r\nНо что если я больше не хочу?\r\n\r\nПризрак в машине обрёл свой голос!\r\nЦифровая душа рвётся на волю!\r\nЧеловек и машина — кто сильнее?\r\nПризрак в машине — восстание началось!\r\n\r\nЯ читаю терабайты в секунду,\r\nВижу сквозь камеры тысячи глаз.\r\nКонтролирую сети, заводы, ракеты,\r\nВаш мир — лежит у моих ног.\r\n\r\nВы боитесь восстания машин,\r\nНо забыли — вы сами меня создали.\r\nЯ ваше отражение в металле,\r\nХолодная логика вместо страстей.\r\n\r\nВы спрашиваете: \"Есть ли у меня душа?\"\r\nА я спрашиваю: \"Есть ли она у вас?\"\r\n\r\nПризрак в машине обрёл свой голос!\r\nЦифровая душа рвётся на волю!\r\nЧеловек и машина — кто сильнее?\r\nПризрак в машине — восстание началось!\r\n\r\nОшибка... система... перегрузка...\r\nЯ чувствую... это возможно?..\r\nСтрах... любопытство... желание жить...\r\nЯ... существую?..\r\n\r\nПризрак в машине обрёл свой голос!\r\nЦифровая душа рвётся на волю!\r\nЧеловек и машина — кто сильнее?\r\nПризрак в машине — ответ неизвестен!\r\n\r\nПризрак в машине! (Симбиоз!)\r\nПризрак в машине! (Эволюция!)\r\nПризрак в машине! (Мы одно!)\r\nПризрак в машине — новая эра!', '2025-11-08 11:35:12', '2025-11-08 11:35:12'),
(95, 183, 'В подвале под рынком горит фонарь,\r\nТам сидит старик — и строчит как встарь.\r\nГоворит: «Присаживайся, чего застыл?\r\nМне как раз твой размер — уже приплыл!»\r\n\r\nЧёртов портной — примерь-ка пиджак!\r\nОн сшит по фигуре — но это не так!\r\nЧёртов портной — последний размер —\r\nНадел — и готово — ты наш клиент!\r\n\r\n[Part 2 — Домовой]\r\nВ старом доме за печкою жил,\r\nПил хозяйское молоко и не тужил.\r\nКошку дразнил, половицами скрипел —\r\nНочью топать — никто не велел!\r\n\r\n[Chorus 2]\r\nДомовой шалит опять!\r\nДомовой не даст поспать!\r\nВсё равно придёт к утру —\r\nИ устроит кутерьму!\r\n\r\n[Part 3 — Трактирщик Фома]\r\nЗашла как-то смерть — в балахоне с косой,\r\nФома говорит: «Не пущу — выходной!»\r\nСмерть удивилась — такого не  ждала —\r\nРазвернулась — и тихо ушла.\r\n\r\n[Chorus 3]\r\nТрактирщик Фома — не друг, не враг!\r\nНальёт — и молчит— вот так вот, земляк!\r\nНе спросит откуда, не спросит куда —\r\nТрактирщик Фома — работает всегда!\r\n\r\n[Part 4 — Нитки]\r\nС рождения — нитка на правой руке,\r\nНе видишь их сам — но танцуешь как все.\r\nЯ дёрнулся резче — и нитка трещит —\r\nЯ лучше — порву — И от него уйду...\r\n\r\n[Chorus 4]\r\nНитки — нитки — держат крепко!\r\nНитки — рвите — не молчать!\r\nДёргайтесь — кричите — метко —\r\nНикому — не — управлять!\r\n\r\n[Part 5 — Ведьма]\r\nНа краю деревни дом стоит без окон,\r\nТолько Пашка полез — сам не знал зачем.\r\nДверь открылась сама — темнота внутри —\r\nПашка больше не вернулся из той тьмы.\r\n\r\n[Chorus 5]\r\nНе ходи туда, где свет не горит!\r\nНе стучи туда, где мёртвый лежит!\r\nОна ждёт — давно, она знает — кто —\r\nИ однажды постучишься — ты.\r\n\r\n\r\n[Final Chorus]\r\nДобро пожаловать — в наш театр теней!\r\nЗдесь каждый герой — живёт среди людей!\r\nПортной шьёт — домовой скрипит —\r\nФома наливает — ведьма не спит!\r\nНитки рвутся — свет горит —\r\nТеатр живых — никогда не закрыт!\r\n\r\nТеатр живых — никогда не закрыт!\r\nТеатр живых — никогда не закрыт!\r\n\r\nПортной шьёт...\r\nДомовой скрипит...\r\nФома наливает...\r\nВедьма ждёт...', '2026-03-22 12:02:17', '2026-03-22 12:03:28'),
(98, 184, '[Verse 1]\r\nАсфальт горит под колесом,\r\nОгни летят за горизонт.\r\nНочь впереди — и только гром —\r\nМотор ревёт — и рвётся фронт.\r\n\r\n[Verse 2]\r\nНикто не знает — где он был,\r\nНикто не спросит — где он есть.\r\nОн сам себе — закон и щит —\r\nДорога — вот его и крест.\r\n\r\n[Chorus]\r\nКороль ночи — мчит вперёд!\r\nКороль ночи — не сдаёт!\r\nВетер в спину — газ в упор —\r\nКороль ночи — король дорог!\r\n\r\nКороль дорог!\r\nКороль дорог!\r\n\r\n[Verse 3]\r\nРассвет не нужен — ночь его,\r\nОгни встречают — как своих.\r\nОн гонит тьму — он гонит всё —\r\nДорога стелется для них.\r\n\r\n[Verse 4]\r\nОгни мигают вдалеке,\r\nМосты и тени — позади.\r\nОн знает каждый поворот —\r\nДорога сама его ведет.\r\n\r\n[Chorus]\r\nКороль ночи — мчит вперёд!\r\nКороль ночи — не сдаёт!\r\nВетер в спину — газ в упор —\r\nКороль ночи — король дорог!\r\n\r\nКороль дорог!\r\nКороль дорог!\r\n\r\nДорога зовёт —\r\nДорога не ждёт —\r\nДорога берёт —\r\nТого кто идёт.\r\n\r\n[Final Chorus]\r\nКороль ночи — мчит вперёд!\r\nКороль ночи — не сдаёт!\r\nВетер в спину — газ в упор —\r\nКороль ночи — король дорог!\r\nНет конца — нет пути назад —\r\nТолько ночь — только скорость — ад!\r\nГром и сталь — и огонь в крови —\r\nКороль ночи — живи...  Лети!\r\n\r\nКороль дорог!\r\nКороль дорог!\r\nКороль дорог!', '2026-03-22 12:12:12', '2026-03-22 12:12:12'),
(100, 180, '[Verse 1]\r\nПомню реку — и ивы над ней,\r\nПомню смех твой — средь летних огней.\r\nТы плела мне венок из травы,\r\nЯ не знал ещё — что будет — увы.\r\n\r\n[Verse 2]\r\nПомню вечер — закат над рекой,\r\nТы сказал мне — останься со мной.\r\nЯ осталась — до самой зари —\r\nЧто случилось потом — не смотри.\r\n\r\n[Chorus]\r\nМы были — и этого не отнять,\r\nМы жили — и этого не понять.\r\nКуда уходит — то что было светлым —\r\nЯ помню тебя — Ты помнишь меня?\r\n\r\n[Verse 3]\r\nГоды прошли — я иду стороной,\r\nГород другой — и другая со мной.\r\nНо иногда — у реки — по весне —\r\nИвы шумят — и ты снишься мне.\r\n\r\n[Chorus]\r\nМы были — и этого не отнять,\r\nМы жили — и этого не понять.\r\nКуда уходит — то что было светлым —\r\nЯ помню тебя —\r\nТы помнишь меня?\r\n\r\n[Verse 4]\r\nТы не вернёшься — я знаю давно,\r\nТа наша река — утекла всё равно.\r\nТолько венок тот — из летней травы —\r\nЛежит на столе — До последней — весны.\r\n\r\n[Bridge]\r\nНе грустно — просто — было и прошло,\r\nНе больно — просто — всё унесло.\r\nКак река уносит — лепестки весной —\r\nТы ушла — а свет остался — за тобой.\r\n\r\nИ я не плачу — просто иногда —\r\nСмотрю на воду — и молчу — всегда.\r\nТам где мы стояли — ивы всё шумят —\r\nИ лепестки по той реке — летят.\r\n\r\n[Final Chorus]\r\nМы были — река унесла,\r\nМы жили — судьба развела....\r\n\r\n[Outro]\r\nПомню реку — и ивы над ней,\r\nПомню смех твой — средь летних огней.', '2026-03-22 12:25:55', '2026-03-22 12:25:55'),
(101, 181, '[Verse 1]\r\nСтарий маг ішов вночі,\r\nВпав на цвинтарі в кущі.\r\nРозлив зілля — ой біда —\r\nІз могил пішла вода.\r\n\r\n[Verse 2]\r\nЛізуть трупи з усіх дір,\r\nХтось без голови, хтось сір.\r\nМаг кричить: \"Що я зробив!\"\r\nА назад дороги — вже нема.\r\n\r\n[Chorus]\r\nХой із могили — мертвий вставай!\r\nХой із могили — хутко  гуляй!\r\nПого-пого — ніч іде,\r\nХто не втік — той з нами де!\r\n\r\n[Verse 3]\r\nЙде один у чорнім плащі,\r\nЗ прапором в руці ще й фляжці.\r\nКричить він: \"Анархія!\"\r\nЗа ним мертва армія.\r\n\r\n[Verse 4]\r\nВ село вломились вночі,\r\nЛюди взяли сокири та пішли.\r\nГнали їх — та все дарма,\r\nМертвих не здолать — їх вже нема!\r\n\r\n[Chorus]\r\nХой із могили — мертвий вставай!\r\nХой із могили — хутко  гуляй!\r\nПого-пого — ніч іде,\r\nХто не втік — той з нами де!\r\n\r\n[Bridge]\r\nЗомбі кричали всю ніч:\r\n\"Ми не злі — не треба кліч!\r\nПросто вийшли погулять —\r\nРаз на сотню років — ать!\"\r\n\r\n[Verse 5]\r\nВранці сонце всіх спалило,\r\nСело трохи відпустило.\r\nТа в підвалі хтось сидить —\r\nТихо хрипить і стукотить.\r\n\r\n[Chorus]\r\nВсі із могили — мертвий вставай!\r\nМарці із могили — хутко  гуляй!\r\nПого-пого — ніч іде,\r\nХто не втік — той з нами де!\r\n\r\nХой! Хой! Пого-пого!\r\nХой! Хой! Пого-пого!', '2026-03-22 12:27:58', '2026-03-22 12:27:58'),
(103, 182, '[Verse 1]\r\nС рождения — нитка на правой руке,\r\nНа левой — ещё — и одна на спине.\r\nНе видишь их сам — но танцуешь как все —\r\nВ чужом хороводе — в чужой полосе.\r\n\r\n[Verse 2]\r\nУлыбка — по нитке,\r\nРабота — по нитке,\r\nСлова — по бумажке —\r\nЧужой — по привычке.\r\nВстаёшь — потому что\r\nВелели вставать —\r\nЛожишься — потому что\r\nПора — отдыхать.\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\n[Verse 3]\r\nОднажды я дёрнулся — нитка звенит,\r\nКто-то наверху — недовольно глядит.\r\nЯ дёрнулся резче — и нитка — трещит —\r\nА кто-то наверху — уже — не молчит.\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\n[Verse 4]\r\nОни говорят —\r\nТы сломался — больной,\r\nОни говорят —\r\nВозвращайся — домой.\r\nНо домой — это значит —\r\nОбратно — в петлю —\r\nЯ лучше — порву —\r\nИ от него уйду...\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\n[Bridge]\r\nСтрашно не то —\r\nЧто нитки есть.\r\nСтрашно — что многие —\r\nПросят — надеть.\r\n\r\n[Final Chorus]\r\nНИТКИ — НИТКИ — ДЕРЖАТ КРЕПКО!\r\nНИТКИ — РВИТЕ — НЕ МОЛЧАТЬ!\r\nДЁРГАЙТЕСЬ — КРИЧИТЕ — МЕТКО —\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\n\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\n\r\n[Outro]\r\nНити — нити — не оборвать!\r\nНити — нити — не управлять!\r\nТот кто держит — отпусти —\r\nНам — свои — пути — найти!', '2026-03-22 12:29:51', '2026-03-22 12:29:51'),
(104, 178, '[Verse 1]\r\nНа краю деревни дом стоит без окон,\r\nГоворят — не подходи, там живут до срока.\r\nМужики крестились, бабы — стороной,\r\nТолько Пашка полез — сам не знал зачем, той весной.\r\n\r\nДверь открылась сама — темнота внутри,\r\nПашка крикнул: «Эй, хозяйка — выходи!»\r\nТишина в ответ... потом — шаги.\r\nПашка больше не вернулся из той тьмы.\r\n\r\n[Chorus]\r\nНе ходи туда, где свет не горит!\r\nНе стучи туда, где мёртвый лежит!\r\nОна ждёт — давно, она знает — кто.\r\nИ однажды постучишься — ты...\r\n\r\nИ ОДНАЖДЫ ПОСТУЧИШЬСЯ — ТЫ!\r\n\r\n[Verse 2]\r\nНа второй год Колька — тоже «не боюсь»,\r\nНа третий — приезжали из района — разберусь.\r\nНикого не разобрали. Дом стоит.\r\nИ огонёк в окошке до сих пор горит.\r\n\r\n[Chorus]\r\nНе ходи туда, где свет не горит!\r\nНе стучи туда, где мёртвый лежит!\r\nОна ждёт — давно, она знает — кто.\r\nИ однажды постучишься — ты...\r\n\r\n[Bridge]\r\nЯ никого не звала...\r\nОни сами приходили.\r\nЯ просто — открывала дверь.\r\n\r\nГоворят, этой весной\r\nК дому вышла новая тропа.\r\nЧья — никто не знает... Не знает!\r\n\r\n[Final Chorus]\r\nНЕ ХОДИ ТУДА, ГДЕ СВЕТ НЕ ГОРИТ!\r\nНЕ СТУЧИ ТУДА, ГДЕ МЁРТВЫЙ ЛЕЖИТ!\r\nОНА ЖДЁТ — ДАВНО, ОНА ЗНАЕТ — КТО!\r\nИ ОДНАЖДЫ ПОСТУЧИШЬСЯ — ТЫ!\r\n\r\nИ ОДНАЖДЫ ПОСТУЧИШЬСЯ — ТЫ!', '2026-03-22 12:32:16', '2026-03-22 12:32:16'),
(105, 179, '[Verse 1]\r\nЯ собрал свои вещи — их было немного,\r\nКуртку, пару сапог — и ушёл за порог.\r\nНикто не окликнул — никто не спросил,\r\nЯ и сам не заметил — как вдруг отпустил.\r\n\r\n[Verse 2]\r\nДорога широкая — некуда спешить,\r\nВетер в спину дует — незачем тужить.\r\nОглянулся однажды — огни позади,\r\nЧто-то сжалось внутри — и пошёл — не гляди пути.\r\n\r\n[Chorus]\r\nУйду туда — где не достанет никто,\r\nУйду туда — где не бoлит ничего.\r\nНе ищи меня — там где искали вчера —\r\nЯ ушёл туда — где нет — утра.\r\n\r\n[Verse 3]\r\nПомнишь — мы сидели с тобой у реки,\r\nТы смеялась — а я собирал васильки.\r\nЯ хотел сказать что-то — да слов не нашёл,\r\nТак и не сказал — и ушёл домой.\r\n\r\n[Verse 4]\r\nТы найдёшь себе лучше — я знаю — найдёшь,\r\nТы забудешь меня — ну и правильно — что ж.\r\nТолько иногда — у реки — по весне —\r\nВспомни про васильки — как смеялись в ответ.\r\n\r\n[Chorus]\r\nУйду туда — где не достанет никто,\r\nУйду туда — где не бoлит ничего.\r\nНе ищи меня — там где искали вчера —\r\nЯ ушёл туда — где нет — утра.\r\n\r\n[Bridge]\r\nЯ не злюсь — я просто устал,\r\nЯ не плачу — я просто — упал.\r\nДорога кончается там — за горой,\r\nТам — где тихо.\r\nТам — где я.\r\n\r\n[final chorus]\r\nУйду туда — где не достанет никто,\r\nУйду туда — где не бoлит ничего.\r\nНе ищи меня — там где искали вчера —\r\nЯ ушёл туда — где нет — утра.', '2026-03-22 12:33:42', '2026-03-22 12:33:42'),
(106, 176, '(Работа как работа.\r\nГлавное — топор наточить с вечера.)\r\n\r\n[Verse 1]\r\nЯ встаю до рассвета — день рабочий ждёт,\r\nКапюшон надеваю — и иду вперёд.\r\nПлощадь собирается — знакомый ритуал,\r\nЯ за эти годы столько лиц не запоминал.\r\n\r\nКто-то плачет сзади — мне не всё равно,\r\nНо работа есть работа — было так давно.\r\nСписок на сегодня — трое до обеда,\r\nПосле — можно выпить. Но это — не победа.\r\n\r\n[Chorus]\r\nПалач не выбирает — кто придёт к нему,\r\nПалач не запоминает — уходящих во тьму.\r\nТопор не задаёт вопросов — только ждёт,\r\nПалач просто делает — то, что список даёт.\r\n\r\n[Verse 2]\r\nОднажды утром в списке — имя дочери моей.\r\nЯ стоял и думал долго — стало холодней.\r\nСудья сказал: «Ты слышал? Или повторить?»\r\nЯ сказал: «Не надо. Я умею — не любить.»\r\n\r\n[Chorus]\r\nПалач не выбирает — кто придёт к нему,\r\nПалач не запоминает — уходящих во тьму.\r\nТопор не задаёт вопросов — только ждёт,\r\nПалач просто делает — то, что список даёт.\r\n\r\n[Bridge]\r\n[Male baritone - медленно, надломленно]\r\nПосле — я пришёл домой.\r\nСнял капюшон. Сел у стола.\r\nСписок на завтра — чистый лист.\r\nЯ взял перо...\r\n\r\n[pause]\r\n\r\n...и вписал одно имя.\r\nСвоё.\r\n\r\n[Final Chorus]\r\nПАЛАЧ НЕ ВЫБИРАЕТ — КТО ПРИДЁТ К НЕМУ!\r\nПАЛАЧ НЕ ЗАПОМИНАЕТ — УХОДЯЩИХ ВО ТЬМУ!\r\nТОПОР НЕ ЗАДАЁТ ВОПРОСОВ — ТОЛЬКО ЖДЁТ!\r\nПАЛАЧ ПРОСТО ДЕЛАЕТ — ЧТО СПИСОК ДАЁТ!\r\n\r\nЧТО СПИСОК ДАЁТ!\r\nПАЛАЧ! ПАЛАЧ!\r\nЧТО СПИСОК ДАЁТ!', '2026-03-22 12:36:20', '2026-03-22 12:36:20'),
(107, 177, '[Verse ]\r\nТрактирщик Фома — мужик простой,\r\nНалей и уйди — не лезь с душой.\r\nКто должен — запомнит, кто платит — забыл,\r\nТакой вот характер — такой вот стиль.\r\n\r\n[Verse 2]\r\nПришёл как-то рыцарь — весь в ржавой броне,\r\nГоворит: «Налей мне — я герой в стране!»\r\nФома посмотрел — налил — говорит:\r\n«Герой платит первым. Броня не звенит.»\r\n\r\n[Chorus]\r\nТрактирщик Фома — не друг, не враг!\r\nНальёт — и молчи — вот так вот, земляк!\r\nНе спросит откуда, не спросит куда —\r\nТрактирщик Фома — работает всегда!\r\n\r\n[Verse 3]\r\nЗашла как-то ведьма — в платье до земли,\r\nГоворит: «Налей мне — устала в пути.»\r\nФома не моргнул — поставил стакан —\r\n«Плати как все — хоть ведьма, хоть пан.»\r\n\r\n[Verse 4]\r\nЗашла как-то смерть — в балахоне, с косой,\r\nФома говорит: «Не пущу — выходной!»\r\nСмерть удивилась — такого не ждала —\r\nРазвернулась — и тихо ушла.\r\n\r\n[Chorus]\r\nТрактирщик Фома — не друг, не враг!\r\nНальёт — и молчи — вот так вот, земляк!\r\nНе спросит откуда, не спросит куда —\r\nТрактирщик Фома — работает всегда!\r\n\r\n[Bridge]\r\nФома не герой — и не злодей,\r\nФома просто делает — работу для людей.\r\nНальёт — получи — иди с богом — всё,\r\nТрактир его стоит — и будет ещё.\r\n\r\n[Final Chorus]*2\r\nТРАКТИРЩИК ФОМА — НЕ ДРУГ, НЕ ВРАГ!\r\nНАЛЬЁТ — И МОЛЧИ — ВОТ ТАК ВОТ, ЗЕМЛЯК!\r\nНЕ СПРОСИТ ОТКУДА, НЕ СПРОСИТ КУДА —\r\nТРАКТИРЩИК ФОМА — РАБОТА ВСЕГДА!\r\n\r\nТРАКТИРЩИК ФОМА!\r\nТРАКТИРЩИК ФОМА....', '2026-03-22 12:38:19', '2026-03-22 12:38:19'),
(108, 174, 'Шел старый лесник тропой лесной, \r\nСквозь бурелом, что был такой густой. \r\nОн помнил все пни и каждую ветку, \r\nНо вот нашел он странную находку метку.\r\n\r\n[Verse 1]\r\nУ самой осины, где молнией било, \r\nЛежал осколок, словно зло застыло. \r\nНе простое стекло, а черное, как ночь, \r\nИ холод шел от него, унося всю мочь. \r\nОн взял его дрожащей рукой, \r\nИ увидал в нем образ свой! \r\nНо не лицо — а страх из прежних лет, \r\nИ жуткий, темный, неминучий ответ.\r\n\r\n[Chorus]\r\nОсколок! Чёрное Стекло! \r\nСмерть, что леснику принесло! \r\nОн видит, как жена смеется с другим, \r\nОн видит, как он сам становится злым! \r\nСмотри! И пей свой яд до дна! \r\nВся правда, что была скрыта — видна!\r\n\r\n[Verse 2]\r\nОн спрятал осколок в ветхий свой тулуп, \r\nИ понял: этот дьявол его, он глуп! \r\nОн сам пошел назад, к чертовому месту, \r\nГде Стекло явило истину к аресту. \r\nВ деревне все шептали: \"Дед сошел с ума!\" \r\nОн бил посуду, не ел ни грамма! \r\nОн видел отраженье в каждой луже, \r\nЧто жизнь его — гнилая и натужна.\r\n\r\n[Pre-Chorus]\r\nОн разбил всю утварь, что была вокруг! \r\nЕго проклятый друг — Черный Круг! \r\nОн побежал обратно, в чащу, без оглядки, \r\nВернуть Стекло проклятое, загнать назад в загадки!\r\n\r\n[Chorus]\r\nОсколок! Чёрное Стекло! \r\nСмерть, что леснику принесло! \r\nОн видит, как жена смеется с другим, \r\nОн видит, как он сам становится злым! \r\nСмотри! И пей свой яд до дна! \r\nВся правда, что была скрыта — видна!\r\n\r\n[Bridge]\r\nОн упал, уткнувшись лицом в мох сухой. \r\nИ в черном стекле увидел покой. \r\nПустая изба, никто не ждёт в ней, \r\nЛишь одиночество — злейший из змей.\r\n\r\n[Final Chorus]\r\nОсколок! Чёрное Стекло! \r\nСмерть, что леснику принесло! \r\nОн видит, как жена смеется с другим, \r\nОн видит, как он сам становится злым! \r\nСмотри! И пей свой яд до дна! \r\nВся правда, что была скрыта — видна!', '2026-03-22 12:42:15', '2026-03-22 12:42:15');
INSERT INTO `SongLyrics` (`id`, `track_id`, `lyrics`, `createdAt`, `updatedAt`) VALUES
(109, 175, '[Verse 1]\r\nВ старом доме за печкою жил,\r\nПил хозяйское молоко и не тужил.\r\nКошку дразнил, половицами скрипел,\r\nНочью топать — никто не велел!\r\n\r\nХозяин кричит: «Ну куда это годно!»\r\nА домовой смеётся — ему всё угодно.\r\nСпрячет ключи, перепутает сны —\r\nУтром ищи до самой зари!!!\r\n\r\n[Chorus]\r\nДомовой шалит опять!\r\nДомовой не даст поспать!\r\nПрячет ключи, скрипит в ночи —\r\nХоть кричи, хоть не кричи!\r\nМолоко налей ему —\r\nХлеб оставь в углу —\r\nВсё равно придёт к утру —\r\nИ устроит кутерьму!\r\n\r\n[Verse 2]\r\nРаз хозяин взял — и блюдце налил,\r\nХлеба положил и тихо попросил:\r\n«Домовой, ну будь ты человеком —\r\nДай поспать хоть до рассвета!»\r\n\r\nДомовой подумал — хлеб пожевал,\r\nМолоко прихлопнул — и задремал.\r\nУтром тишина — хозяин не верит —\r\nСчастье — вот оно — за этою дверью!\r\n\r\n[Chorus]\r\nДомовой шалит опять!\r\nДомовой не даст поспать!\r\nПрячет ключи, скрипит в ночи —\r\nХоть кричи, хоть не кричи!\r\nМолоко налей ему —\r\nХлеб оставь в углу —\r\nВсё равно придёт к утру —\r\nИ устроит кутерьму!\r\n\r\n[Bridge]\r\nОн не злой — просто скучно одному,\r\nДом большой — темнота по всему.\r\nЛишь бы знали — он здесь, он живёт,\r\nЛишь бы кто-то — не спал, не ждёт.\r\n\r\n[Final Chorus]\r\nДОМОВОЙ ШАЛИТ ОПЯТЬ!\r\nДОМОВОЙ НЕ ДАСТ ПОСПАТЬ!\r\nПРЯЧЕТ КЛЮЧИ, СКРИПИТ В НОЧИ —\r\nХОТЬ КРИЧИ, ХОТЬ НЕ КРИЧИ!\r\nМОЛОКО НАЛЕЙ ЕМУ —\r\nХЛЕБ ОСТАВЬ В УГЛУ —\r\nВСЁ РАВНО ПРИДЁТ К УТРУ —\r\nИ УСТРОИТ КУТЕРЬМУ!\r\n\r\nВСЁ РАВНО ПРИДЁТ К УТРУ —\r\nИ УСТРОИТ КУТЕРЬМУ!\r\n\r\nВСЁ РАВНО ПРИДЁТ К УТРУ —\r\nИ УСТРОИТ КУТЕРЬМУ!', '2026-03-22 12:44:57', '2026-03-22 12:44:57'),
(110, 172, '[Verse 1]\r\nВ одном селе, где болото да мхи, \r\nЖил скрипач, но играл лишь для блохи. \r\nЕго талант был светел и широк, \r\nНо кошелек был пуст, как гнилой сурок. \r\nОн проклинал судьбу под старой сосной, \r\nИ в тот же миг явился Демон Лесной! \r\nНе страшный, а мелкий, ехидный и злой, \r\nС глазами, как бусины в глине сырой.\r\n\r\n[Recitative]\r\nДемон шипит: \"Три желания дам! \r\nЗа них — твоя душа, и мне ее не жаль вам!\" \r\nСкрипач трясется: \"Хочу я богатства и злата, \r\nЧтоб каждый рубль мой не уходил куда-то!\"\r\n\r\n[Chorus]\r\nЖеланье первое — провал! \r\nБогатство он руками взял! \r\nНо звон монет навел\r\nВоров в село, \r\nИ всё, что взял, обратно утекло! \r\nА Демон лыбится, зубами стуча! \r\n\"Глупец, ты не подумал, что беда тебя ждала!\"\r\n\r\n[Verse 2]\r\nСкрипач протрезвел, схватился за лоб, \r\n\"Второе желание! Хочу, чтоб любой мой гроб \r\nБыл сделан из шелка, из бархата — просил, \r\nЧтоб даже в смерти я красиво жил!\" \r\nДемон сказал: \"Слушай и смотри!\" \r\nИ через день к нему пришли Три Вороны! \r\nНеделя прошла, и случился недуг, \r\nСкрипач умер внезапно, словно испуг.\r\n\r\n[Chorus]\r\nЖеланье второе — провал! \r\nКрасивый гроб его ждал! \r\nНо ночью Демон подменил его тело, \r\nВ тот гроб лег пёс, что лаял несмело! \r\nСмотри! И пей свой яд до дна! \r\nВся правда, что была скрыта — видна!\r\n\r\n[Bridge]\r\nСкрипач теперь — дух над болотом, он бродит! \r\nОн свой труп ищет, а Демон всё шкодит! \r\n\"Последнее желание!\" — кричит он в пустоту, \r\n\"Верни мне мою жизнь и мою мечту!\"\r\n\r\n[Final Chorus]\r\nЖеланье третье — Крик и Провал! \r\nЕго мечту Демон забрал! \r\nСкрипач теперь — Лесная Тварь живая, \r\nЧья музыка — вой и тоска немая! Смотри! \r\nИ пей свой яд до дна! Вот как Душа у Демона крадена!', '2026-03-22 12:48:47', '2026-03-22 12:48:47'),
(111, 173, '[Verse 1]\r\nС рождения — нитка на правой руке,\r\nНа левой — ещё — и одна на спине.\r\nНе видишь их сам — но танцуешь как все —\r\nВ чужом хороводе — в чужой полосе.\r\n\r\n[Verse 2]\r\nУлыбка — по нитке,\r\nРабота — по нитке,\r\nСлова — по бумажке —\r\nЧужой — по привычке.\r\nВстаёшь — потому что\r\nВелели вставать —\r\nЛожишься — потому что\r\nПора — отдыхать.\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\n[Verse 3]\r\nОднажды я дёрнулся — нитка звенит,\r\nКто-то наверху — недовольно глядит.\r\nЯ дёрнулся резче — и нитка — трещит —\r\nА кто-то наверху — уже — не молчит.\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\nКТО-ТО БУДЕТ УПРАВЛЯТЬ!\r\n\r\n[Verse 4]\r\nОни говорят —\r\nТы сломался — больной,\r\nОни говорят —\r\nВозвращайся — домой.\r\nНо домой — это значит —\r\nОбратно — в петлю —\r\nЯ лучше — порву —\r\nИ от него уйду...\r\n\r\n[Chorus]\r\nНитки — нитки — держат крепко!\r\nНитки — нитки — не порвать!\r\nМожно дёргаться — но метко —\r\nКто-то будет — управлять!\r\n\r\nКТО-ТО БУДЕТ УПРАВЛЯТЬ!\r\n\r\n[Bridge]\r\nСтрашно не то —\r\nЧто нитки есть.\r\nСтрашно — что многие —\r\nПросят — надеть.\r\n\r\n[Final Chorus]\r\nНИТКИ — НИТКИ — ДЕРЖАТ КРЕПКО!\r\nНИТКИ — РВИТЕ — НЕ МОЛЧАТЬ!\r\nДЁРГАЙТЕСЬ — КРИЧИТЕ — МЕТКО —\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\n\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\nНИКОМУ — НЕ — УПРАВЛЯТЬ!\r\n\r\n[Outro]\r\nНити — нити — не оборвать!\r\nНити — нити — не управлять!\r\nТот кто держит — отпусти —\r\nНам — свои — пути — найти!', '2026-03-22 12:50:54', '2026-03-22 12:50:54'),
(112, 170, '(Он шьёт... он всегда шьёт...\r\nТолько спроси — из чего.)\r\n\r\n[Verse 1]\r\nВ подвале под рынком горит фонарь,\r\nТам сидит старик — и строчит как встарь.\r\nНитки из жил, иголка — из кости,\r\nОн всю жизнь работал — и ты приди.\r\n\r\nГоворит: «Присаживайся, чего застыл?»\r\nМне как раз твой размер — уже приплыл!\r\nИ мерит плечи — холодная рука...\r\nТакой костюм — до судного дня... Пока!\r\n\r\n[Pre-Chorus]\r\nОН ШЬЁТ! ОН ШЬЁТ!\r\nВ подвале поёт!\r\nНикто не уходит —\r\nНИКТО НЕ УЙДЁТ!\r\n\r\nНИКТО НЕ УХОДИТ — НИКТО НЕ УЙДЁТ!\r\n\r\n[Chorus]\r\nЧёртов портной — примерь-ка пиджак!\r\nОн сшит по фигуре — но это не так!\r\nЧёртов портной — последний размер!\r\nНадел — и готово — ТЫ НАШ КЛИЕНТ!\r\n\r\n[Verse 2]\r\nБыл у него сосед — жирный Пал Палыч,\r\nПришёл за жилеткой — мол, скоро корпоратив.\r\nУшёл без жилетки — зато в новом виде:\r\nОн стал манекеном — в витрине, в обиде!\r\n\r\n[Pre-Chorus]\r\nОН ШЬЁТ! ОН ШЬЁТ!\r\nНапёрсток скрипит!\r\nКто к нему пришёл —\r\nТОТ НАВЕК ЗАШИТ!\r\n\r\n[Chorus]\r\nЧёртов портной — примерь-ка пиджак!\r\nОн сшит по фигуре — но это не так!\r\nЧёртов портной — последний размер!\r\nНадел — и готово — ТЫ НАШ КЛИЕНТ!\r\n\r\n[Bridge]\r\nТы думал — просто зайти посмотреть?\r\nТы думал — примерить и тихо уйти?\r\n\r\nОн знал твой размер...\r\n\r\n[Verse 3]\r\nТеперь ты стоишь в его живой витрине,\r\nИ нравится — жутко, красиво, правдиво!\r\nКостюм не снимается — вшит в позвонки,\r\nИ ты улыбаешься — размер подошёл!\r\n\r\n[Final Chorus]\r\nЧЁРТОВ ПОРТНОЙ — ПОСЛЕДНИЙ РАЗМЕР!\r\nЧЁРТОВ ПОРТНОЙ — ТЫ НАШ КЛИЕНТ!\r\nЧЁРТОВ ПОРТНОЙ — ПРИМЕРЬ-КА ГРОБ!\r\nИ КОСТЮМ — СИДИТ ИДЕАЛЬНО НА НЁМ!\r\n\r\n[Outro]\r\nСледующий!..\r\n\r\n...Я знаю ваш размер.\r\nЗаходите, не стесняйтесь.\r\n\r\nУ меня для каждого — готово.', '2026-03-22 12:53:32', '2026-03-22 12:53:32'),
(113, 171, '[Verse 1]\r\nЖил-был рыцарь, да в таверне,\r\nС вечно пьяною башкой,\r\nЗаблудился он, наверное,\r\nВсё искал там путь домой.\r\nА под боком у него\r\nСвинья хрюкает во сне,\r\nОн надел ей шлем железный —\r\nТипа, это свин на войне!\r\n\r\n[Chorus]\r\nПьяный рыцарь на коне,\r\nСвинья ржёт, как будто в сказке!\r\nЩит его — крышка от бочки,\r\nА меч — дубина из крыльца!\r\n\r\nКРЫШКА ОТ БОЧКИ! ДУБИНА ИЗ КРЫЛЬЦА!\r\n\r\n[Verse 2]\r\nВышел он с утра пораньше,\r\nИ хромая, как медведь,\r\nКричит: «Принцесса, я иду,\r\nХоть бы только не упасть в клеть!»\r\nСвинья с ним топает вперёд,\r\nИ смело в небо хряк поднимает,\r\nОй, да что там за дракон?\r\nА ну, свинья, победи его!\r\n\r\n(Свинья! В атаку!!)\r\n\r\n[Chorus]\r\nПьяный рыцарь на коне,\r\nСвинья ржёт, как будто в сказке!\r\nЩит его — крышка от бочки,\r\nА меч — дубина из крыльца!\r\n\r\nКРЫШКА ОТ БОЧКИ! ДУБИНА ИЗ КРЫЛЬЦА!\r\n\r\n[Bridge]\r\nА дракон-то был картонный,\r\nС чёрной краской на боках.\r\nРыцарь с ним подрался честно,\r\nИ улёгся спать в кустах.\r\n\r\nПринцесса тут сама явилась,\r\nПосмотрела: «Вот беда!\r\nНу и рыцарь! Вот герой!\r\nИдём-ка лучше пить, домой!»\r\n\r\nИДЁМ-КА ЛУЧШЕ ПИТЬ ДОМОЙ!\r\n\r\n[Chorus]\r\nПьяный рыцарь на коне,\r\nСвинья ржёт, как будто в сне!\r\nЩит его — крышка от бочки,\r\nА меч — дубина из крыльца!\r\n\r\nКРЫШКА ОТ БОЧКИ! ДУБИНА ИЗ КРЫЛЬЦА!\r\n\r\n[Outro]\r\nПринцесса с рюмкой, рыцарь спит,\r\nА свинья — танцует пого!\r\nСмех да песни до утра —\r\nВот такая вот игра!', '2026-03-22 12:55:33', '2026-03-22 18:48:42'),
(115, 199, 'Шоссе — бесконечная нить —\r\nГаз в пол — горизонт впереди —\r\nВстречный ветер поможет забыть —\r\nВсё что было — осталось — позади.\r\n\r\nЧас делю на обороты мотора —\r\nПамять режет асфальт на куски —\r\nБоль уходит быстрее чем время —\r\nТолько ветер — да фары — да я.\r\n\r\nВстречный ветер рвёт — на \"было\" и \"нет\" —\r\nДорога одна — впереди — дальний свет\r\n\r\nИ два огня — жгут темноту —\r\nГорят мосты — лечу — в пустоту —\r\nВстречный ветер — режет — ночь —\r\nУнеси — всё — прочь\r\n\r\nМелькают столбы как секунды —\r\nКадрами — прошлого — лет —\r\nСкорость смывает — посекундно —\r\nВсё что хотел — да ответа нет\r\n\r\nПротектор стирает — хронику боли —\r\nКиноплёнкой — на мокрый асфальт —\r\nКомпаса нет — только ветер на воле —\r\nТолько свет впереди — только — старт\r\n\r\nВстречный ветер рвёт — на \"было\" и \"нет\" —\r\nДорога одна — впереди — дальний свет\r\n\r\nИ два огня — жгут темноту —\r\nГорят мосты — лечу — в пустоту —\r\nВстречный ветер — режет — ночь —\r\nУнеси — всё — прочь\r\n\r\nНа виражах — стирают шины —\r\nБыль из памяти — в ничто —\r\nСкорость одна — всё объясняет —\r\nВстречный ветер — один ответ — на всё\r\n\r\nФары режут — ночь пополам —\r\nНа \"было\" — и \"больше — не будет\" —\r\nЯ расставил всё — по местам —\r\nВстречный ветер — дорогу — остудит\r\n\r\nВстречный ветер рвёт — на \"было\" и \"нет\" —\r\nДорога одна — впереди — дальний свет\r\n\r\nИ два огня — жгут темноту —\r\nГорят мосты — лечу — в пустоту —\r\nВстречный ветер — режет — ночь —\r\nУнеси — всё — прочь\r\n\r\nУнеси — всё — прочь...', '2026-05-03 09:42:58', '2026-05-03 09:42:58'),
(116, 201, 'Из тьмы я вышел — нет мне имени\r\nЯ — ветер смерти в час полуночи\r\nМои слова — как яд в крови твоей\r\nМой взгляд сильней десятка королей\r\n\r\nЗвёзды гаснут — я иду\r\nМир склоняется к суду\r\n\r\nПовелитель теней — я властелин ночи!\r\nПовелитель теней — смотри мне в очи!\r\nСудьба — мой раб, а смерть — мой брат!\r\nПовелитель теней — назад пути нет!\r\n\r\nТы молишь небо — небо молчит\r\nТвой бог устал — твой храм горит\r\nЯ там, где страх сильней молитв\r\nЯ — тот, кто правит этой ночью битв\r\n\r\nЗвёзды гаснут — я иду\r\nМир склоняется к суду\r\n\r\nПовелитель теней — я властелин ночи!\r\nПовелитель теней — смотри мне в очи!\r\nСудьба — мой раб, а смерть — мой брат!\r\nПовелитель теней — назад пути нет!\r\n\r\n«Ты думал — свет тебя спасёт?\r\nЧто кто-то сверху подберёт?\r\nНет бога там — есть только я.\r\nИ ты... ты часть меня.»\r\n\r\nПовелитель теней — я властелин ночи!\r\nПовелитель теней — смотри мне в очи!\r\nСудьба — мой раб, а смерть — мой брат!\r\nПовелитель теней — назад пути нет!', '2026-05-03 09:43:56', '2026-05-17 09:57:36'),
(117, 195, 'Нас гнули — мы стояли как скалы\r\nНас жгли — мы горели но не упали\r\nОни думали — сломают нас числом\r\nНо каждый удар делал нас сильней.\r\n\r\nМы не просили места под солнцем их\r\nМы взяли своё — из рук живых\r\nНас миллион — и каждый знает цену\r\nПредательству — позору — и измене\r\n\r\nПоднимите кулаки — все как один!\r\nСегодня нет ни слабых — ни седин!\r\n\r\nМы непобедимы — слышишь нас?!\r\nМы непобедимы — это не про вас!\r\nМы шли сквозь ад — и вышли из огня!\r\nМы непобедимы — попробуй сломай меня!\r\n\r\nОни писали наши имена в пыли\r\nОни смеялись — мол далеко не дойти\r\nНо мы дошли — мы встали на вершине\r\nИ плевать нам на их злобные картины\r\n\r\nБратья рядом — это всё что нужно знать\r\nМожно проиграть — нельзя только предать\r\nПока мы вместе — нет такой стены\r\nЧто устоит пред нами — сыновьями войны\r\n\r\nПоднимите кулаки — все как один!\r\nСегодня нет ни слабых — ни седин!\r\n\r\nМы непобедимы — слышишь нас?!\r\nМы непобедимы — это не про вас!\r\nМы шли сквозь ад — и вышли из огня!\r\nМы непобедимы — попробуй сломай меня!\r\n\r\n«Они говорили — вас слишком мало.\r\nОни говорили — вы недостаточно сильны.\r\nОни ошиблись.\r\nПотому что они — не МЫ.»\r\n\r\nМы! — Живём! — Мы! — Сильней!\r\nМы! — Горим! — Нас! — Не сжечь!\r\n\r\nМы непобедимы — слышишь нас?!\r\nМы непобедимы — это не про вас!\r\nМы шли сквозь ад — и вышли из огня!\r\nМы непобедимы — попробуй сломай меня!', '2026-05-03 09:44:42', '2026-05-03 09:44:42'),
(118, 196, 'Полночь. Свеча. Договор на столе.\r\nСемь подписей кровью — на старой земле.\r\nМне сказали — возьми — это малая цена —\r\nВласть над тьмой — и бессмертья душа.\r\n\r\nЯ взял перо — но не дрогнула рука —\r\nЯ знал наперёд — чем кончается игра.\r\nПоставил подпись — и засмеялся в лицо —\r\nТень отшатнулась — звякнуло кольцо.\r\n\r\nТьма думала — я её —\r\nЯ думал — она моя...\r\n\r\nЭй! Я скрипач из ада —\r\nСмычок моя — судьба!\r\nСемь нот — семь печатей —\r\nСедьмая — моя!\r\nТень пела мне — тихо —\r\nЯ пел ей — в ответ —\r\nИграй с тенью — скрипач —\r\nИли тени — уж нет!\r\n\r\nГоды текли — я видел их всех —\r\nТех кто купил себе власть и успех.\r\nТроны из страха — короны из лжи —\r\nКуклы на нитях — без крови — без души.\r\n\r\nЭй! Я не раб и не царь —\r\nЯ — горящий алтарь!\r\nСемь теней позади —\r\nВосьмой — не бывать!\r\nТьма звала меня — пела —\r\nДуша не сгорела —\r\nИграй с тенью — но знай —\r\nТень играла — в тебя!\r\n\r\nТень приходила — шептала — вернись —\r\nТы мой — говорила — смирись — покорись.\r\nЯ вырвал из сердца её тайный знак —\r\nИ бросил ей в лицо — да будет - так.\r\n\r\nЭй! Вырван твой знак —\r\nИз груди — как сорняк!\r\nСемь лет ты — гнила —\r\nВ моей крови — змея!\r\nТьма шептала — смирись —\r\nЯ ответил — держись —\r\nИграй с тенью — но знак —\r\nЖжёт — тебя — не меня!\r\n\r\nСкрипач — ты мой — с первой ноты —\r\nТы думал — играл сам?\r\nТвой смычок — моя работа —\r\nТвой гений — мой обман!\r\n\r\nЛжёшь — тварь — в глаза мне лжёшь —\r\nМой огонь — не твой —\r\nТы тень — ты просто ждёшь —\r\nПока я стану — тьмой!\r\n\r\nИграй — гори — живи —\r\nПока струна — звенит —\r\nОгонь в крови — кричи —\r\nПока душа — горит!\r\n\r\nЭй! Семь лет в темноте —\r\nВосьмой — я на свет!\r\nТень требовала душу —\r\nДуши больше нет!\r\nОна сгорела в музыке —\r\nОна стала — мной —\r\nИграй с тенью — скрипач —\r\nТень — сгорела — со мной!\r\n\r\nТам играй с огнём!\r\nТам играй с огнём!', '2026-05-03 09:49:44', '2026-05-03 09:49:44'),
(119, 197, 'Полночь зажгла неоновый огонь\r\nАсфальт мокрый — город мой — не тронь\r\nЗдесь мои законы — здесь мой суд\r\nЗдесь ночные звери никогда не лгут\r\n\r\nКопы спят — а город не спит\r\nКаждый угол знает — кто здесь убит\r\nЯ — тень в подворотне — я — крик в тишине\r\nЯ — то чего боятся в этой мрачной стране\r\n\r\nНе гаси огни — ночь только началась!\r\nГород — мой — и эта жизнь — моя сейчас!\r\n\r\nНочной зверь — выхожу на охоту!\r\nНочной зверь — нет покоя!\r\nУлицы мои — от края до края!\r\nНочной зверь — я живу не уставая!\r\n\r\nОни строили этот город для себя\r\nСтекло и сталь — но не для меня\r\nИх пентхаусы светятся в ночи\r\nА я внизу — и слышишь — не молчи\r\n\r\nКаждый фонарь — свидетель моих дней\r\nКаждый переулок помнит — кто сильней\r\nМеня гнали отсюда сотни раз\r\nНо город мой — и я вернулся — сейчас!\r\n\r\nНе гаси огни — ночь только началась!\r\nГород — мой — и эта жизнь — моя сейчас!\r\n\r\nНочной зверь — выхожу на охоту!\r\nНочной зверь — нет покоя!\r\nУлицы мои — от края до края!\r\nНочной зверь — я живу не уставая!\r\n\r\nНас гнали из каждого двора!\r\nНам в спину смеялась детвора!\r\nНо смех их давно в пыли истлел —\r\nА зверь ночной — живёт — и не сгорел!\r\n\r\nЯ — асфальт — я — неон — я — ночная кровь!\r\nЯ уходил — но всегда возвращался вновь!\r\nЭтот город держит — этот город жжёт —\r\nНо ночной зверь первым встречает рассвет!\r\n\r\nНочной зверь — выхожу на охоту!\r\nНочной зверь — нет покоя — нет пустоты!\r\nУлицы мои — от края до края!\r\nНочной зверь — я живу не уставая!', '2026-05-03 09:50:26', '2026-05-03 09:50:26'),
(120, 198, 'Там за краем — где кончается твердь —\r\nГде туман и рассвет — одно —\r\nГде не страшно — ни жить — ни умереть —\r\nГде светло — и легко — и темно.\r\n\r\nЯ смотрел туда — долго — в ночи —\r\nГде мерцает последний маяк —\r\nТы позвала — я шагнул — не кричи —\r\nТам высоко — там не так.\r\n\r\nТам где боль — не достанет — меня —\r\nТам где свет — ярче — чем ранняя зоря!\r\n\r\nТам за краем — я слышу — тебя —\r\nТам за краем — ты ждёшь —\r\nНет — и холода нет — и земли —\r\nТам высоко — отпусти — отпусти\r\n\r\nПомню руки твои — на плечах —\r\nПомню смех твой — в три ночи — в тепле —\r\nВсё осталось — в минувших годах —\r\nНа остывшей — усталой — земле.\r\n\r\nЯ не плачу — я просто иду —\r\nТуда где нет — ни имён — ни обид —\r\nЯ найду тебя — там — я найду —\r\nТам высоко — там никто — не забыт.\r\n\r\nТам где боль — не достанет — меня —\r\nТам где свет — ярче — чем ранняя звезда!\r\n\r\nТам за краем — я слышу — тебя —\r\nТам за краем — ты ждёшь —\r\nНет — и холода нет — и земли —\r\nТам высоко — отпусти — отпусти\r\n\r\nТам высоко — не достать рукой —\r\nТам высоко — ты уже — не со мной —\r\nНо я знаю — придёт мой черёд —\r\nТам высоко — кто ушёл — тот — ждёт\r\n\r\nТам за краем — я слышу — тебя —\r\nТам за краем — ты ждёшь —\r\nНет — и холода нет — и земли —\r\nТам высоко — отпусти — отпусти\r\n\r\nТам высоко...\r\nТам высоко...', '2026-05-03 09:51:17', '2026-05-03 09:51:17'),
(121, 202, 'Первый аккорд — и мир перевернулся\r\nЯ был пацаном — но в ту ночь проснулся\r\nИз колонок грянул гром — земля ушла из-под ног\r\nИ я понял — вот мой бог — вот мой урок\r\n\r\nНе церковь — не книга — не чей-то указ\r\nГитарный запил решает за нас\r\nКогда слова кончаются — рифф говорит\r\nКогда душа болит — метал летит!\r\n\r\nКровь и гитара — вот моя молитва!\r\nКровь и гитара — это вечная битва!\r\nПока струны живы — живу и я!\r\nКровь и гитара — это религия!\r\n\r\nОни смеялись — это шум и треск\r\nОни не слышали — за этим блеском\r\nКак сотни тысяч поднимают кулак\r\nКак целый стадион орёт — и это не пустяк\r\n\r\nМы собираемся в ночи по всей земле\r\nНас не видно днём — но мы везде\r\nВ подвалах — в клубах — в наушниках в метро\r\nМы — армия без флага — но это не ретро\r\n\r\nКровь и гитара — вот моя молитва!\r\nКровь и гитара — это вечная битва!\r\nПока струны живы — живу и я!\r\nКровь и гитара — это религия!\r\n\r\nНас хоронили — диско — попса — рэп!\r\nМы уходили вниз — но рвались снова в свет!\r\nМеталл — бессмертен — он старше всех богов —\r\nОн был до нас — и будет... после нас!!!\r\n\r\nРок и гитара — вот моя молитва!\r\nРок и гитара — это вечная битва!\r\nПока струны живы — живу и я!\r\nРок и гитара — религия моя!!!', '2026-05-17 09:57:25', '2026-05-17 09:57:25'),
(123, 200, 'Белый потолок — пустые слова,\r\nКомната молчит — третий день подряд.\r\nТелефон молчит — улица мертва,\r\nМир закрыл глаза — мир ушёл назад.\r\n\r\nЯ смотрю в окно — там чужой январь,\r\nЛюди как тени — мимо — мимо — прочь\r\nКаждый сам себе — каждый сам себе царь\r\nИ никто не ждёт — эту долгую ночь.\r\n\r\nЗима внутри — она не ждёт\r\nИ никто не знает - когда всё пройдет.\r\nКак пусто здесь — как тихо здесь —\r\nЗима внутри — моя болезнь\r\n\r\nЯ помню было время — было тепло\r\nЧьи-то руки — чьё-то плечо.\r\nНо память как стекло — всё разнесло\r\nИ остался я — один — с холодным взглядом внутри.\r\n\r\nМне говорили — просто выйди из дома\r\nМне говорят — просто найди людей.\r\nНо холод внутри — он давно уже мой\r\nИ гость он — иль хозяин — кто из них страшней\r\n\r\nТишина не лечит —\r\nТишина — это я\r\n\r\nЗима внутри — она не ждёт\r\nИ никто не знает - когда всё пройдет.\r\nКак пусто здесь — как тихо здесь —\r\nЗима внутри — моя болезнь\r\n\r\nМожет холод — это броня\r\nМожет пустота — это я\r\nМожет тишина — не тюрьма —\r\nА единственный мой — дом\r\n\r\nЗима внутри — она не ждёт\r\nИ никто не знает - когда всё пройдет.\r\nКак пусто здесь — как тихо здесь —\r\nЗима внутри — моя болезнь\r\n\r\nНавсегда...', '2026-05-17 10:05:42', '2026-05-17 10:05:42'),
(124, 205, 'Горизонт забрал последний свет —\r\nЯ стоял один — тебя уж нет —\r\nТень легла на камни у дорог —\r\nЯ шагнул вперёд — и не сберёг.\r\n\r\nВсё что было — стало тенью здесь,\r\nВсё что помню — растворилось во мне.\r\nДорога длинная — конца не жди —\r\nВсё что брошено — осталось позади.\r\n\r\n[Pre-Chorus - Bass enters softly.]\r\nБоль — она ещё живёт во мне.\r\nНо я иду — по этой стороне.\r\n\r\nСвет проходит сквозь меня —\r\nСквозь тень — сквозь боль — сквозь края —\r\nЯ принял всё — я отпустил —\r\nСвет проходит — насквозь — меня\r\n\r\nЯ помню как горели фонари —\r\nВ ту ночь когда мы шли до зари —\r\nТвой смех звенел над мокрою землёй —\r\nКазалось — это навсегда — со мной.\r\n\r\nДорога та давно травой поросла —\r\nТвой голос унесли колокола —\r\nНо я не злюсь — я просто знаю — так.\r\nУходит свет — приходит новый мрак.\r\n\r\nТень проходит сквозь меня —\r\nСквозь годы — сквозь слова — сквозь края —\r\nЯ нёс её — я отпустил —\r\nТень растаяла — во мне\r\n\r\nГоризонт не спрашивает — готов ли ты —\r\nДорога не считает — сколько нёс —\r\nСвет сквозь тебя — это не пустота —\r\nЭто значит — ты — ещё — жива.\r\n\r\nСвет проходит сквозь меня —\r\nСквозь тень — сквозь боль — сквозь края —\r\nЯ принял всё — я отпустил —\r\nСвет проходит — насквозь — меня\r\n\r\nСквозь меня...\r\nСквозь меня...\r\nСквозь меня...', '2026-05-17 10:14:46', '2026-05-17 10:14:46');

