(104, '13. Швидше', NULL, 7, '/public/uploads/album_covers/68fbc287e8c00.png', '/public/uploads/full/68fbc339783f9.wav', '2025-10-24 21:19:37.493', '2025-10-24 21:19:37', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(105, '1. Crimson Requiem', 'Первый выстрел в огненном реквиеме Хеллсинга. Песня о бессмертии сквозь боль, вечной ночи и проклятом долге. Это голос Алукарда, восстающего против хаоса, с его алой сутаной как знаменем войны.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a486b75f.wav', '2025-11-01 17:42:00.440', '2025-11-01 17:43:32', NULL, NULL, NULL, NULL, NULL, 218, 0, 0),
(106, '2. Пепел и Свет', 'Исповедь Серас Виктории — потерянной между человеком и монстром. Её путь сквозь пепел и остатки света, где каждый выбор — между собой и тьмой, между памятью и кровью.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a4870576.wav', '2025-11-01 17:42:00.477', '2025-11-01 17:44:47', NULL, NULL, NULL, NULL, NULL, 228, 0, 0),
(107, '3. Молитва из Стали', 'Железный гимн бездушного легиона Миллениума. Это не просто война — это автоматическая литургия, где каждый солдат — снаряд, а каждый шаг — псалом смерти. Песня о бессмысленном вечном марше.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a487672b.wav', '2025-11-01 17:42:00.485', '2025-11-01 17:45:15', NULL, NULL, NULL, NULL, NULL, 227, 0, 0),
(108, '4. Святой осквернитель', 'Песня Отца Андерсона и Палача в одном лице. Без святой воды и без прощения, только клинок, вера в кровь и разрушение. Апостат, что несёт очищение сквозь разрушение.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a487a851.wav', '2025-11-01 17:42:00.502', '2025-11-01 17:46:06', NULL, NULL, NULL, NULL, NULL, 253, 0, 0),
(109, '5. Вальс Безумия', 'Финальный акт арки Хеллсинга — бал смерти и безумия. Это последний танец Миллениума, где герои и враги закручены в огненном вальсе под аккомпанемент рвущихся снарядов и безумных речей.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a487e92d.wav', '2025-11-01 17:42:00.518', '2025-11-01 17:47:12', NULL, NULL, NULL, NULL, NULL, 245, 0, 0),
(110, '6. Красный плач', 'Одиночество под маской Данте. Смех, что скрывает старые раны, стиль, что закрывает боль. Это крик сквозь огонь, потерю и внутреннюю воронку. История демона, что всё ещё хочет быть человеком.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48809e3.wav', '2025-11-01 17:42:00.527', '2025-11-01 17:47:39', NULL, NULL, NULL, NULL, NULL, 181, 0, 0),
(111, '7. Молитва Спарды', 'Внутренний монолог Вержила. Симфония порядка, самоотречения и гордости. Это не молитва — это ультиматум миру. Клинок в тишине, голос превосходства. Покой достигается — через пламя.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a488c05e.wav', '2025-11-01 17:42:00.574', '2025-11-01 17:48:14', NULL, NULL, NULL, NULL, NULL, 247, 0, 0),
(112, '8. Тень в её глазах', 'История Евы и Триш. О тени, ставшей живой. О принятии себя, даже если ты — не оригинал. Песня о близости, боли и выборе быть рядом, даже если тебя не ждут.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a489a5d1.wav', '2025-11-01 17:42:00.632', '2025-11-01 17:48:45', NULL, NULL, NULL, NULL, NULL, 288, 0, 0),
(113, '9. Разрезанная душа', 'Диалог Данте и Вержила. Они — братья, враги, отражения друг друга. Песня о непонимании, боли, принятии и том, что даже разорванные души могут говорить друг с другом — на языке битвы.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48a546d.wav', '2025-11-01 17:42:00.677', '2025-11-01 17:49:26', NULL, NULL, NULL, NULL, NULL, 224, 0, 0),
(114, '10. Грех — моё ремесло', 'Bayonetta говорит своим стилем. В этой песне грех — искусство, пули — поцелуи, а смерть — сцена. Богиня в кружевах с автоматами, которая не просит — она утверждает.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48a745b.wav', '2025-11-01 17:42:00.685', '2025-11-01 17:49:59', NULL, NULL, NULL, NULL, NULL, 188, 0, 0),
(115, '11. Клеймо греха', 'История самопознания. От куклы к ведьме, от проклятия к силе. Песня о принятии имени, о выборе быть собой — даже если твоё прошлое покрыто клеймами. Bayonetta становится символом свободы.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48b2f54.wav', '2025-11-01 17:42:00.733', '2025-11-01 17:50:26', NULL, NULL, NULL, NULL, NULL, 258, 0, 0),
(116, '12. Танец по лезвию', 'Дуэт Bayonetta и Jeanne — две ведьмы, две стороны одной медали. Их бой — это танец, это диалог, это вызов. Вражда, что пахнет сестринством. И каждое “прощай” — как финальный реверанс.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48bdb29.wav', '2025-11-01 17:42:00.777', '2025-11-01 17:51:05', NULL, NULL, NULL, NULL, NULL, 208, 0, 0),
(117, '13. Ave Umbra', 'Прощальная песнь Bayonetta. Стильная, гордая, печальная и красивая. Это не смерть — это финальный поклон. Её не спасали — она спасала стиль. Ave Umbra — гимн вечному следу.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48c1b76.wav', '2025-11-01 17:42:00.794', '2025-11-01 17:51:29', NULL, NULL, NULL, NULL, NULL, 248, 0, 0),
(118, '14. Crimson Eclipse', 'Кроссовер Хеллсинга и Данте. Дуэт двух чудовищ, двух воинов без пощады. Это песня о том, что останется, когда всё исчезнет. Не искупление, не победа — а финальный след на крови и пепле.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48c5c8c.wav', '2025-11-01 17:42:00.810', '2025-11-01 17:51:56', NULL, NULL, NULL, NULL, NULL, 228, 0, 0),
(119, '16. Святой осквернитель (бонус)', NULL, 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48c7cec.wav', '2025-11-01 17:42:00.819', '2025-11-01 17:42:00', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(120, '17. Грех — моё ремесло (бонус)', NULL, 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48c9da1.wav', '2025-11-01 17:42:00.827', '2025-11-01 17:42:00', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(121, '18. Ave Umbra (Бонус)', NULL, 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48cdeb4.wav', '2025-11-01 17:42:00.844', '2025-11-01 17:42:00', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(122, '19. Ave umbra - latin (Бонус)', 'Латинская вариация последнего прощания. Символ величия и вечности. Песня, что станет легендой в тенях.', 8, '/public/uploads/album_covers/690629c14d144.png', '/public/uploads/full/69062a48d1fa7.wav', '2025-11-01 17:42:00.860', '2025-11-01 17:52:30', NULL, NULL, NULL, NULL, NULL, 254, 0, 0),
(123, '1. Прелюдия хаоса', NULL, 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f4ffc0.wav', '2025-11-01 17:58:55.328', '2025-11-01 17:58:55', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(124, '2. Пробуждение зверя', 'Открывающий трек показывает освобождение Алукарда от всех ограничений. Он больше не слуга Хеллсинга, а пробудившийся древний хищник, готовый править ночью.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f5336d.wav', '2025-11-01 17:58:55.349', '2025-11-01 18:01:19', NULL, NULL, NULL, NULL, NULL, 299, 0, 0),
(125, '3. Железные крылья', 'Эволюция Серас из испуганной новообращённой в могущественного вампира-воина. Она принимает свою тёмную природу, но сохраняет человечность.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f57430.wav', '2025-11-01 17:58:55.357', '2025-11-01 18:02:08', NULL, NULL, NULL, NULL, NULL, 262, 0, 0),
(126, '4. Последний майор', 'Безумный финал лидера Миллениума - человека, начавшего войну ради самой войны. Театральное безумие и восторг разрушения.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f594db.wav', '2025-11-01 17:58:55.366', '2025-11-01 18:02:50', NULL, NULL, NULL, NULL, NULL, 238, 0, 0),
(127, '5. Багровый престол', 'Эмоциональная баллада о молодой женщине, несущей невероятное бремя власти и одиночества. Последняя защитница человечества на своём багровом престоле.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f5b565.wav', '2025-11-01 17:58:55.374', '2025-11-01 18:03:23', NULL, NULL, NULL, NULL, NULL, 349, 0, 0),
(128, '6 Демоны не плачут', 'Драйвовый экшн-гимн, показывающий Данте в деле - неостановимого охотника на демонов, превращающего каждую битву в стильное шоу.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f5d5f6.wav', '2025-11-01 17:58:55.382', '2025-11-01 18:03:52', NULL, NULL, NULL, NULL, NULL, 223, 0, 0),
(129, '7. Ямато - Разделение', 'Окончательное превращение Вергилия, использующего Ямато для отсечения всех человеческих связей ради абсолютной силы.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f63998.wav', '2025-11-01 17:58:55.408', '2025-11-01 18:04:20', NULL, NULL, NULL, NULL, NULL, 345, 0, 0),
(130, '8. Пепельная роза', 'История охотницы на демонов, движимой местью за мать. Элегантная и смертоносная, как роза с заряженными шипами.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f65864.wav', '2025-11-01 17:58:55.416', '2025-11-01 18:04:51', NULL, NULL, NULL, NULL, NULL, 266, 0, 0),
(131, '9. Ведьма времени', 'Стильная и опасная Bayonetta манипулирует временем, превращая битву в смертельный танец.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f678bc.wav', '2025-11-01 17:58:55.424', '2025-11-01 18:05:34', NULL, NULL, NULL, NULL, NULL, 264, 0, 0),
(132, '10. Расколотая луна', 'Трагическая баллада о Жанне, вернувшейся из Инферно. История разлуки и воссоединения двух ведьм.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f69959.wav', '2025-11-01 17:58:55.432', '2025-11-01 18:06:42', NULL, NULL, NULL, NULL, NULL, 377, 0, 0),
(133, '11. Война падшего', 'Эпическая битва освобождённого Алукарда против армии Миллениума. Князь Валахии ведёт войну без правил и ограничений.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f6b9d1.wav', '2025-11-01 17:58:55.441', '2025-11-01 18:07:08', NULL, NULL, NULL, NULL, NULL, 458, 0, 0),
(134, '12. За гранью греха', 'Появление космического зла, превосходящего всех. Существо за гранью понимания, для которого все герои - лишь пыль.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f6da5b.wav', '2025-11-01 17:58:55.449', '2025-11-01 18:07:33', NULL, NULL, NULL, NULL, NULL, 371, 0, 0),
(135, '13. Последний свидетель', 'Хроника финальной битвы глазами последнего выжившего. Все герои пали перед лицом абсолютного зла.', 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f6fafd.wav', '2025-11-01 17:58:55.457', '2025-11-01 18:08:01', NULL, NULL, NULL, NULL, NULL, 419, 0, 0),
(136, '14. Эпилог. Новый рассвет', NULL, 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f79d9f.wav', '2025-11-01 17:58:55.499', '2025-11-01 17:58:55', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(137, '15. Пепельная роза (бонус трек)', NULL, 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f7be07.wav', '2025-11-01 17:58:55.508', '2025-11-01 17:58:55', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(138, '16. Демоны не плачут (бону трек)', NULL, 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f7ded0.wav', '2025-11-01 17:58:55.516', '2025-11-01 17:58:55', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(139, '17. Война падшего (бонус трек)', NULL, 9, '/public/uploads/album_covers/69062d800f411.png', '/public/uploads/full/69062e3f7ff3a.wav', '2025-11-01 17:58:55.524', '2025-11-01 17:58:55', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(140, '1. Прелюдия вечности', 'Инструментальное вступление с редкими вокальными вставками. Мир лежит в руинах после событий \"Гримуара гнева\", но в пепле прорастают первые семена нового. Последний свидетель находит древний артефакт - источник жизни.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/690631948a4f8.wav', '2025-11-01 18:13:08.566', '2025-11-01 18:15:26', NULL, NULL, NULL, NULL, NULL, 153, 0, 0),
(141, '2. Зов крови', 'Алукард возвращается из бездны, но уже не как монстр - как хранитель жизни. Три миллиона душ в нем больше не кричат от боли, а поют о надежде. Трансформация от разрушителя к защитнику.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/690631949863b.wav', '2025-11-01 18:13:08.657', '2025-11-01 18:15:05', NULL, NULL, NULL, NULL, NULL, 278, 0, 0),
(142, '3. Сталь и милосердие', 'Серас принимает роль нового лидера. Железные крылья теперь несут не разрушение, а защиту. Она учится сочетать силу вампира с человеческим милосердием.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063194b4b34.wav', '2025-11-01 18:13:08.740', '2025-11-01 18:16:07', NULL, NULL, NULL, NULL, NULL, 303, 0, 0),
(143, '4. Корона света', 'Интегра находит силу не в одиночестве, а в единении с выжившими. Багровый престол становится троном света, объединяющим разрозненных героев против общей угрозы.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063194c82af.wav', '2025-11-01 18:13:08.821', '2025-11-01 18:16:46', NULL, NULL, NULL, NULL, NULL, 473, 0, 0),
(144, '5. Братья по выбору', 'Эпическая песня примирения. Братья наконец понимают друг друга перед лицом космического зла. Не кровь делает их братьями, а выбор стоять вместе.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063194da099.wav', '2025-11-01 18:13:08.893', '2025-11-01 18:17:22', NULL, NULL, NULL, NULL, NULL, 359, 0, 0),
(145, '6. Танец возрождения', 'Две ведьмы объединяют свою силу для ритуала против космического зла. Их танец не несет смерть, а пробуждает новую жизнь в мертвом мире.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063194edb25.wav', '2025-11-01 18:13:08.978', '2025-11-01 18:17:57', NULL, NULL, NULL, NULL, NULL, 384, 0, 0),
(146, '7. Прощение стали', 'Неожиданный поворот - Майор предлагает союз против космического зла, но планирует предательство. Война ради войны временно сменяется войной ради выживания.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/6906319529151.wav', '2025-11-01 18:13:09.173', '2025-11-01 18:18:37', NULL, NULL, NULL, NULL, NULL, 404, 0, 0),
(147, '8. Молитва', 'Дух матери Данте и Вергилия является всем героям. Её материнская любовь становится силой, способной исцелить раны реальности и благословить героев перед финальными испытаниями.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/690631956bd8d.wav', '2025-11-01 18:13:09.442', '2025-11-01 18:19:08', NULL, NULL, NULL, NULL, NULL, 428, 0, 0),
(148, '9. Реквием', 'Чисто инструментальный трек с трагически-меланхолическим настроением. Момент скорби по всем павшим, но с проблесками надежды. Подготовка к финальной жертве героев.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195823a5.wav', '2025-11-01 18:13:09.534', '2025-11-01 18:19:25', NULL, NULL, NULL, NULL, NULL, 269, 0, 0),
(149, '10. Последний выбор', 'Герои понимают, что победить космическое зло можно только величайшей жертвой. Каждый делает свой выбор - отдать жизнь ради возрождения мира.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195ab457.wav', '2025-11-01 18:13:09.702', '2025-11-01 18:20:00', NULL, NULL, NULL, NULL, NULL, 301, 0, 0),
(150, '11. Сердце пустоты', 'Герои проникают в сердце космического зла. Интимный, рефлективный момент перед финальной жертвой, где каждый осознает неизбежность предстоящего.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195b0f43.wav', '2025-11-01 18:13:09.725', '2025-11-01 18:21:08', NULL, NULL, NULL, NULL, NULL, 344, 0, 0),
(151, '12. Предел', 'Самый эмоциональный трек. Герои один за другим отдают свои жизни в финальной битве. Серас, Данте, Вергилий, Bayonetta погибают героически. Алукард и Интегра выживают.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195b2fc3.wav', '2025-11-01 18:13:09.733', '2025-11-01 18:21:40', NULL, NULL, NULL, NULL, NULL, 339, 0, 0),
(152, '13. Эхо пустоты', 'Древнее зло торжествует над павшими героями, но знает о четырех выживших - Алукарде, Интегре, Данте и Майоре. Готовится к финальной игре с оставшимися.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195b5086.wav', '2025-11-01 18:13:09.742', '2025-11-01 18:22:11', NULL, NULL, NULL, NULL, NULL, 338, 0, 0),
(153, '14. Последний союз', 'Финальная битва троих героев против предавшего их Майора и остатков Миллениума. Эпическая схватка, определяющая судьбу мира.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195b916f.wav', '2025-11-01 18:13:09.758', '2025-11-01 18:22:53', NULL, NULL, NULL, NULL, NULL, 376, 0, 0),
(154, '15. Новой надежды свет', 'Позитивная финальная песня о завершении всей трилогии. Майор побежден, мир спасен. Герои чтят память павших и строят светлое будущее.', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195bd2b2.wav', '2025-11-01 18:13:09.775', '2025-11-01 18:23:33', NULL, NULL, NULL, NULL, NULL, 328, 0, 0),
(155, '16. Эпилог. Конец', 'Грандиозный инструментальный финал с торжественным нарративом о завершении трилогии. \"Три книги судьбы написаны до конца... Герои ушли в легенды...\"', 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195c13b9.wav', '2025-11-01 18:13:09.792', '2025-11-01 18:23:57', NULL, NULL, NULL, NULL, NULL, 114, 0, 0),
(156, '17. Эпилог. Конец - инструментал', NULL, 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195c54b7.wav', '2025-11-01 18:13:09.808', '2025-11-01 18:13:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(157, '18. Последний выбор (бонус трек)', NULL, 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195c95e6.wav', '2025-11-01 18:13:09.825', '2025-11-01 18:13:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(158, '19. Эхо пустоты (бонус трек)', NULL, 10, '/public/uploads/album_covers/690630ce1802c.png', '/public/uploads/full/69063195cd719.wav', '2025-11-01 18:13:09.842', '2025-11-01 18:13:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(159, '1. 300 (Огонь и Сталь)', 'Открывающий трек альбома посвящён легендарной обороне Фермопил — битве 300 спартанцев против персидской армии. Яростный, скоростной power metal с галопирующими риффами и эпическими хорами передаёт дух абсолютной решимости воинов, знающих о своей неизбежной гибели, но не склонивших колени перед превосходящими силами врага. Двойная бочка без остановки, гитарные дуэли и стадионный припев \"Это Спарта!\" делают трек идеальным открытием альбома — мощным, героическим и бескомпромиссным.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa8226e4.wav', '2025-11-08 10:09:12.141', '2025-11-08 10:16:55', NULL, NULL, NULL, NULL, NULL, 314, 0, 0),
(160, '2. Орел Девятого Легиона', 'Загадочное исчезновение IX Испанского легиона Рима в туманах Каледонии (Шотландии) — одна из величайших исторических тайн. Трек погружает в атмосферу густого тумана, страха перед неизвестным и обречённого похода. Маршевый ритм, зловещие думовые куплеты и мощный чистый припев с вопросом \"Куда ушёл Орёл?\" создают ощущение истории-призрака. Волынки и военные барабаны добавляют кельтского колорита, превращая песню в музыкальный детектив без ответа.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa825ea8.wav', '2025-11-08 10:09:12.163', '2025-11-08 10:17:14', NULL, NULL, NULL, NULL, NULL, 367, 0, 0),
(161, '3. Под Знаменем Креста', 'Монументальный симфонический эпик о Первом Крестовом походе. Огромный оркестр, латинский хор, церковный орган и оперный вокал создают атмосферу религиозного фанатизма и величия \"священной миссии\". Трек намеренно контрастен — с одной стороны красота и пафос \"Deus Vult!\" (Так хочет Бог!), с другой — кровавая резня при штурме Иерусалима. Неоклассические гитарные соло и апокалиптические хоры делают композицию самой масштабной на альбоме. Это саундтрек к столкновению веры и жестокости.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa829fac.wav', '2025-11-08 10:09:12.172', '2025-11-08 10:17:44', NULL, NULL, NULL, NULL, NULL, 374, 0, 0),
(162, '4. Черный Флаг', 'Единственная баллада альбома — лирическое размышление о цене свободы через призму пиратской жизни. От тихого акустического вступления трек постепенно набирает мощь, рассказывая историю человека, выбравшего волю вместо оков \"приличного общества\". Это не романтизация разбоя, а честный рассказ о выборе между безопасностью и свободой, о том, что каждый миг вольной жизни стоит тысячи лет в цепях. Эмоциональные гитарные соло и мелодичный припев дают альбому необходимую передышку перед последующими тяжёлыми треками.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa82e578.wav', '2025-11-08 10:09:12.190', '2025-11-08 10:18:01', NULL, NULL, NULL, NULL, NULL, 329, 0, 0),
(163, '5. Последний Самурай', 'Скоростной технический трек о трагедии Восстания Сацума — последней битве самураев против современной армии с винтовками и пушками. Быстрые мелодичные гитарные гармонии в японских ладах, использование традиционных инструментов (сякухати, тайко) и стремительный темп передают красоту и ярость умирающей эпохи. Это песня о верности традициям, о кодексе Бусидо и о \"красивой смерти\" под цветущей сакурой. Контраст между медленным атмосферным бриджем и взрывными припевами символизирует столкновение старого мира с новым.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa832680.wav', '2025-11-08 10:09:12.206', '2025-11-08 10:18:14', NULL, NULL, NULL, NULL, NULL, 329, 0, 0),
(164, '6. Перекрёсток (instrumenta;)', 'Инструментальная композиция-мост между эпохами. Японские мотивы плавно трансформируются в европейские военные марши, символизируя переход от эры холодного оружия к индустриальной войне машин. Традиционные инструменты угасают, их заменяют снаряды и механические ритмы. Короткий, но атмосферный трек даёт слушателю \"выдохнуть\" и подготовиться к ужасам Первой мировой.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa8346fc.wav', '2025-11-08 10:09:12.215', '2025-11-08 10:18:29', NULL, NULL, NULL, NULL, NULL, 244, 0, 0),
(165, '7. Осада Осовца', 'Один из самых драматичных треков альбома, основанный на легендарной контратаке защитников крепости Осовец после немецкой газовой атаки. Резкий контраст между медленными давящими doom-куплетами (ужас хлорной атаки) и взрывными power metal припевами (героическая контратака) создаёт невероятное напряжение. Индустриальные звуки, имитирующие газовую атаку, и отчаянный вокал передают кошмар химического оружия и безумную храбрость полуживых солдат, поднявшихся в атаку и обративших врага в бегство одним своим видом.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa836777.wav', '2025-11-08 10:09:12.223', '2025-11-08 10:18:51', NULL, NULL, NULL, NULL, NULL, 394, 0, 0),
(166, '8. Ночные ведьмы', 'Классический galloping heavy metal в духе NWOBHM, посвящённый подвигу 588-го (46-го гвардейского) женского авиаполка. \"Летящий\" ритм, двойные гитарные гармонии и женский вокал создают ощущение ночного полёта на тихих бипланах По-2. Трек передаёт и страх, который лётчицы наводили на врага, выключая моторы перед бомбёжкой, и их невероятную отвагу. Это гимн женской силе и храбрости, доказавшей, что героизм не имеет пола.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa838833.wav', '2025-11-08 10:09:12.231', '2025-11-08 10:19:03', NULL, NULL, NULL, NULL, NULL, 367, 0, 0),
(167, '9. Эхо Холодной Войны', 'Мрачное размышление ветерана о бессмысленности \"шахматной игры\" сверхдержав, где солдаты были пешками. Трек охватывает период от Вьетнама до падения Берлинской стены, передавая горечь тех, кто воевал в чужих войнах за чужие идеи. Атмосферные гитары, звуки вертолётов и честный, усталый вокал создают ощущение незаживающей раны. Это не героическая песня — это рефлексия о цене политических игр, оплаченной кровью простых людей. Один из самых личных и эмоциональных треков альбома.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa83c930.wav', '2025-11-08 10:09:12.248', '2025-11-08 10:19:19', NULL, NULL, NULL, NULL, NULL, 323, 0, 0),
(168, '10. Будущее (instrumental)', 'Второй инструментал альбома служит мостом между XX и XXI веком, между аналоговой и цифровой эрой. Винтажные синтезаторы постепенно эволюционируют в современную электронику, человеческие элементы уступают место машинной точности. Нарастающий киберпанк-саундскейп готовит слушателя к финальному треку о встрече человека с искусственным интеллектом. Это звук рождения новой эры, где поле боя переместилось в виртуальное пространство.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa83e9d3.wav', '2025-11-08 10:09:12.256', '2025-11-08 10:19:31', NULL, NULL, NULL, NULL, NULL, 288, 0, 0),
(169, '11. Призрак из машины (Бонус трек)', 'Мощный индастриал-метал финал альбома обращён в будущее и поднимает вопрос о конфликте человека и искусственного интеллекта. Механические ритмы, холодные синтезаторы и контраст между роботизированным вокалом в куплетах и человеческим в припевах передают двойственность темы. Это мета-трек: AI поёт о себе, при этом сам альбом создан с помощью AI. Композиция не даёт однозначного ответа — симбиоз или война? — оставляя финал открытым. Идеальное завершение путешествия через \"перекрестки времён\", замыкающее круг от древних битв к цифровому будущему.', 11, '/public/uploads/album_covers/690ef6aee4cea.png', '/public/uploads/full/690efaa840a3f.wav', '2025-11-08 10:09:12.265', '2025-11-08 10:19:42', NULL, NULL, NULL, NULL, NULL, 344, 0, 0),
(170, '1. Чёртов портной', 'Открывает альбом жёстко и без предупреждения. История портного в подвале, который шьёт костюмы на заказ — вопрос только в том, для чего именно. Хоррор-панк с грязным дисторшном и припевом, который зал орёт с первого раза.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced2722f7.wav', '2026-03-22 11:13:22.468', '2026-03-22 12:53:32', NULL, NULL, NULL, NULL, NULL, 230, 0, 0),
(171, '2. Пьяный Рыцарь и Его Свинья', 'Единственный трек на альбоме, под который смеются. Средневековая история про горе-рыцаря и его боевую свинью в железном шлеме. Folk punk, скрипка, прыжки в зале — и припев про крышку от бочки, который не выбить из головы.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced272663.wav', '2026-03-22 11:13:22.468', '2026-03-22 12:55:33', NULL, NULL, NULL, NULL, NULL, 298, 0, 0),
(172, '3. Три Желания Скрипача', '', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced272878.wav', '2026-03-22 11:13:22.469', '2026-03-22 12:48:47', NULL, NULL, NULL, NULL, NULL, 207, 0, 0),
(173, '4. Баллада о мёртвом скрипаче', 'Первая баллада альбома. Скрипач, которому Смерть предложила выбор — и он выбрал скрипку. Тёмный кабаре, дуэт мужского и женского вокала, и финал в абсолютной тишине.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced272a62.wav', '2026-03-22 11:13:22.469', '2026-03-22 12:50:54', NULL, NULL, NULL, NULL, NULL, 264, 0, 0),
(174, '5. Осколок Черного Стеклa', '', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced272c4a.wav', '2026-03-22 11:13:22.470', '2026-03-22 12:42:15', NULL, NULL, NULL, NULL, NULL, 224, 0, 0),
(175, '6. Домовой', 'Лёгкий, прыгучий, живой. Домовой не злой — ему просто скучно одному. Folk punk на высоком темпе, чеканный припев и «топ-топ скрип-скрип» — зал подхватывает сам.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced272e1e.wav', '2026-03-22 11:13:22.470', '2026-03-22 12:44:57', NULL, NULL, NULL, NULL, NULL, 239, 0, 0),
(176, '7. Палач', 'Самый тяжёлый трек по содержанию. Человек, который всю жизнь исполнял чужие приговоры — пока не нашёл в списке собственное имя. Без морали, без вывода — только факт.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced273ad5.wav', '2026-03-22 11:13:22.474', '2026-03-22 12:36:20', NULL, NULL, NULL, NULL, NULL, 219, 0, 0),
(177, '8. Трактирщик', 'Фома - Портрет человека, которого не пронять ничем. Ни рыцарь в ржавой броне, ни ведьма в плаще, ни сама Смерть с косой — Фома просто говорит «выходной» и продолжает работать. Панк-гимн флегматизму.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced273d0e.wav', '2026-03-22 11:13:22.474', '2026-03-22 12:38:19', NULL, NULL, NULL, NULL, NULL, 234, 0, 0),
(178, '9. Ведьма', 'Короткая и холодная. Дом на краю деревни, куда заходят — но не возвращаются. Никаких объяснений. Никакого хэппи энда.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced273ef5.wav', '2026-03-22 11:13:22.475', '2026-03-22 12:32:16', NULL, NULL, NULL, NULL, NULL, 229, 0, 0),
(179, '10. Васильки', '', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced2740e0.wav', '2026-03-22 11:13:22.475', '2026-03-22 12:33:42', NULL, NULL, NULL, NULL, NULL, 312, 0, 0),
(180, '11. Воспоминание', 'Симфоническая баллада о том, что было и прошло. Дуэт. Река, ивы, венок из травы — и финал, в котором никто не виноват и оба всё равно одни. Самый светлый трек альбома — и самый горький одновременно.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced2742ac.wav', '2026-03-22 11:13:22.476', '2026-03-22 12:25:55', NULL, NULL, NULL, NULL, NULL, 296, 0, 0),
(181, '12. Хой з могили', 'Единственный украиноязычный трек. Зомби-панк, старый маг, анархист в кожаном плаще и деревня в панике. Дань уважения — тем кто понимает.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced274468.wav', '2026-03-22 11:13:22.476', '2026-03-22 12:28:06', NULL, NULL, NULL, NULL, NULL, 227, 0, 0),
(182, '13. Марионетка', 'Возврат к энергии после двух баллад — жёсткий и прямой. Про тех кто дёргает за нитки и тех кто позволяет. Финальный припев меняется — и зал это чувствует.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced27460f.wav', '2026-03-22 11:13:22.476', '2026-03-22 12:29:51', NULL, NULL, NULL, NULL, NULL, 241, 0, 0),
(183, '14. Попурри', 'Все герои альбома выходят на сцену последний раз. Портной, рыцарь, ведьма, домовой, Фома — по куплету каждому и общий финальный припев. Концертный формат в лучшем виде.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced2747dc.wav', '2026-03-22 11:13:22.477', '2026-03-22 12:10:40', NULL, NULL, NULL, NULL, NULL, 372, 0, 0),
(184, '15. Король ночи', 'На бис. Чистый тяжёлый металл — без сказок, без юмора, без компромиссов. Для тех кто остался до конца.', 12, '/public/uploads/album_covers/69bfc6c36f267.png', '/public/uploads/full/69bfced2749bf.wav', '2026-03-22 11:13:22.477', '2026-03-22 12:19:02', NULL, NULL, NULL, NULL, NULL, 363, 0, 0),
(185, '1. Шаги на воде', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc542f.wav', '2026-03-22 13:11:09.808', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(186, '2. Бал вечной тьмы.', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc57a7.wav', '2026-03-22 13:11:09.809', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(187, '3. Шёпот во тьме', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc5d1d.wav', '2026-03-22 13:11:09.810', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(188, '4. Сияние в бездне', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc5f54.wav', '2026-03-22 13:11:09.811', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(189, '5. Последний рассвет. Фауст', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc6156.wav', '2026-03-22 13:11:09.811', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(190, '6. Ворон', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc6338.wav', '2026-03-22 13:11:09.812', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(191, '7. Аннабель Ли', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc6503.wav', '2026-03-22 13:11:09.812', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(192, '8. Мой создатель. История Франкенштейна', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc66d7.wav', '2026-03-22 13:11:09.813', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(193, '9. Печать Мефистофеля. История Фауста', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc68a7.wav', '2026-03-22 13:11:09.813', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(194, '10. Маска и тень', NULL, 13, '/public/uploads/album_covers/69bfe94a89ba2.png', '/public/uploads/full/69bfea6dc6a7f.wav', '2026-03-22 13:11:09.813', '2026-03-22 13:11:09', NULL, NULL, NULL, NULL, NULL, 0, 0, 0),
(195, '1. НЕПОБЕДИМЫЕ', '', 14, '/public/uploads/album_covers/13ec95a2cb83398325f3a90a2be34d1e0d26ef6ecf29dc49d005709318842eea.png', '/public/uploads/full/69da99863eccf.wav', '2026-04-11 21:57:10.290', '2026-05-03 09:44:42', NULL, NULL, NULL, NULL, NULL, 266, 0, 0),
